async function saveDirectoryRecord(kind,table,record,toRow){
  if(!hasSupabaseClient()){
    console.warn(`Purple Gestão — Supabase indisponível, salvando ${kind} apenas no estado local.`);
    await Storage.save(State.db);
    return;
  }
  let typedSaved=false;
  try{
    const row=toRow(record);
    const {error}=await Supabase.from(table).upsert(row,{onConflict:'id'});
    if(error)throw error;
    typedSaved=true;
  }catch(error){
    if(typedTableMissing(error))console.warn(`Purple Gestão — tabela ${table} pendente, usando app_records.`,error);
    else throw new Error(`${table}: ${error.message||error}`);
  }
  try{await saveTypedAppRecord(kind,record)}
  catch(error){if(!typedSaved)throw error;console.warn(`Purple Gestão — app_records falhou após salvar ${table}.`,error)}
}
async function deleteDirectoryRecord(table,record){
  if(!hasSupabaseClient()){
    console.warn(`Purple Gestão — Supabase indisponível, removendo ${table} apenas do estado local.`);
    await Storage.save(State.db);
    return;
  }
  let typedDeleted=false;
  const typedId=isUUID(record?.supabaseId)?record.supabaseId:(isUUID(record?.id)?record.id:'');
  if(typedId){
    try{const {error}=await Supabase.from(table).delete().eq('id',typedId);if(error)throw error;typedDeleted=true}
    catch(error){if(typedTableMissing(error))console.warn(`Purple Gestão — tabela ${table} pendente na exclusão.`,error);else throw new Error(`${table}: ${error.message||error}`)}
  }
  if(record?.id){
    try{await Storage.remove(record.id)}
    catch(error){if(!typedDeleted)throw error;console.warn('Purple Gestão — app_records já não possuía o registro removido.',error)}
  }
}
