function hasGranularAccess(profile){return Object.prototype.hasOwnProperty.call(profile||{},'access_scope')&&Object.prototype.hasOwnProperty.call(profile||{},'permissions')}
function legacySafePermissions(role,sector){return defaultPermissions(role,sector)}
function canLoadInventory(profile,migrationApplied){return migrationApplied?profile?.permissions?.['inventory.view']===true:['direction','viewer'].includes(profile?.role)}
function effectiveProfilePermissions(profile,migrationApplied){if(!migrationApplied)return legacySafePermissions(profile.role,profile.sector);const stored=profile.permissions||{},defaults=defaultPermissions(profile.role,profile.sector);return Object.fromEntries(PERMISSION_KEYS.map(key=>[key,stored[key]===false?false:(stored[key]===true||defaults[key]===true)]))}
function normalizeAccessProfile(profile,migrationApplied=hasGranularAccess(profile)){const legacy=!migrationApplied;return {id:profile.id,name:profile.name,email:profile.email,role:profile.role,sector:profile.sector,accessScope:legacy?(profile.role==='direction'?'all_sectors':'own_sector'):profile.access_scope,permissions:effectiveProfilePermissions(profile,migrationApplied),active:profile.active,phone:profile.phone||'',jobTitle:profile.job_title||'',avatarUrl:profile.avatar_url||'',electronicSignature:profile.electronic_signature||'',lastLoginAt:profile.last_login_at||null,createdAt:profile.created_at||null,accessControlMode:legacy?'legacy-safe-fallback':'granular'}}
function can(permission){return State.user?.permissions?.[permission]===true}
function sectorAllowed(sector){return State.user?.accessScope==='all_sectors'||State.user?.sector===sector||sector==='all'}
function appRecordSector(sector){return ['all','retencao','pedagogico','financeiro'].includes(sector)?sector:'all'}
function availableSectors(){return State.user?.accessScope==='all_sectors'?['retencao','pedagogico','financeiro']:[State.user?.sector].filter(s=>['retencao','pedagogico','financeiro'].includes(s))}
function operationalDiaryVisibleSectors(){return State.user?.accessScope==='all_sectors'?OPERATIONAL_DIARY_SECTORS:[State.user?.sector].filter(s=>OPERATIONAL_DIARY_SECTORS.includes(s))}
function userReports(){return can('reports.view')?State.db.reports.filter(r=>sectorAllowed(r.sector)):[]}
function latestReport(sector,frequency=null){return State.db.reports.filter(r=>r.sector===sector&&(!frequency||r.frequency===frequency)).sort((a,b)=>(a.end||a.presentation).localeCompare(b.end||b.presentation)).at(-1)||null}
function reportsFor(sector,frequency='quinzenal'){return State.db.reports.filter(r=>r.sector===sector&&r.frequency===frequency).sort((a,b)=>(a.end||a.presentation).localeCompare(b.end||b.presentation))}
function operationalDiaryUnit(){return State.operationalDiaryUnit||State.db.settings.schoolName||'Purple Idiomas'}
function operationalDiarySector(){return operationalDiaryVisibleSectors().includes(State.operationalDiarySector)?State.operationalDiarySector:operationalDiaryVisibleSectors()[0]||'financeiro'}
function operationalDiaryEntries(){return (State.db.operationalDiaries||[]).filter(entry=>State.user?.accessScope==='all_sectors'||State.user?.sector===entry.sector).sort((a,b)=>`${b.entryDate||''}${b.updatedAt||''}`.localeCompare(`${a.entryDate||''}${a.updatedAt||''}`))}
function selectedOperationalDiaryEntry(){const sector=operationalDiarySector(),unit=operationalDiaryUnit(),date=State.operationalDiaryDate||todayISO();return operationalDiaryEntries().find(entry=>entry.sector===sector&&entry.unitName===unit&&entry.entryDate===date)||null}
function openOperationalDiaryPage(sector=''){if(sector&&operationalDiaryVisibleSectors().includes(sector))State.operationalDiarySector=sector;State.page='operational-diary';renderPage();setNavActive('operational-diary')}
function operationalDiarySummary(snapshotOrEntry){
  const sector=snapshotOrEntry?.sector;if(!sector||!OPERATIONAL_DIARY_SCHEMAS[sector])return '';
  const sourceMetrics=snapshotOrEntry?.metrics||{};
  return OPERATIONAL_DIARY_SCHEMAS[sector].metrics.slice(0,3).map(([key,label,type])=>`<span><b>${label}:</b> ${fmtMetric(sourceMetrics[key],type)}</span>`).join('')
}
async function logAudit(action,detail){
  if(!State.user||!hasSupabaseClient())return false;
  const event={id:uid('log'),at:new Date().toISOString(),actor:State.user.name||'Sistema',action,detail};
  try{
    const {error}=await Supabase.from('app_records').insert({id:event.id,kind:'audit',sector:appRecordSector(State.user.sector),owner_id:State.user.id,data:event});
    if(error)throw error;
    State.db.audit.unshift(event);
    return true;
  }catch(error){
    console.error('Purple Gestão — auditoria:',error);
    return false;
  }
}
async function saveAppRecord(row){
  if(!hasSupabaseClient())throw new Error('Supabase indisponível para persistência remota.');
  const existing=Storage.baseline.has(row.id);
  const result=existing
    ? await Supabase.from('app_records').update({sector:row.sector,data:row.data}).eq('id',row.id).select('id').single()
    : await Supabase.from('app_records').insert(row).select('id').single();
  if(result.error){
    console.error('Purple Gestão — erro real ao salvar app_records:',{row,error:result.error});
    throw new Error(`${row.kind}/${row.id}: ${result.error.message}`);
  }
  if(result.data?.id!==row.id)throw new Error(`${row.kind}/${row.id}: persistência não confirmada pelo banco.`);
  Storage.baseline.set(row.id,Storage.serialize(row));
  Storage.metadata.set(row.id,{sector:row.sector,owner_id:row.owner_id});
}
async function saveTypedAppRecord(kind,data,{id=data?.id,sector=State.user?.sector}={}){
  if(!id)throw new Error(`Registro ${kind} sem identificador.`);
  const previous=Storage.metadata.get(id);
  const row={id,kind,sector:appRecordSector(previous?.sector||sector),owner_id:previous?.owner_id||State.user?.id,data};
  await saveAppRecord(row);
}
