function safeErrorText(error){return error instanceof Error?`${error.name}: ${error.message}`:String(error)}
function recordBootstrapError(step,error){const message=safeErrorText(error);Bootstrap.errors.push({step,message,at:new Date().toISOString()});console.error(`Purple Gestão bootstrap [${step}]`,error);return message}
function hasSupabaseClient(){return !!((window.PurpleCore?.supabase?.isReady?.()&&window.PurpleCore?.supabase?.state?.client)||(window.PurpleAuth?.hasClient?.()&&window.PurpleAuth?.state?.client)||(Supabase&&Supabase.auth&&typeof Supabase.from==='function'))}
function saveLocalSessionCache(){try{if(State.user)localStorage.setItem(LOCAL_SESSION_KEY,JSON.stringify({user:State.user,sector:State.sector,at:new Date().toISOString()}))}catch(error){console.warn('Purple Gestão — cache local de sessão:',error)}}
function readLocalSessionCache(){try{const raw=localStorage.getItem(LOCAL_SESSION_KEY);if(!raw)return null;const cached=JSON.parse(raw);return cached?.user?.email?cached:null}catch(error){console.warn('Purple Gestão — leitura do cache local de sessão:',error);return null}}
function clearLocalSessionCache(){try{localStorage.removeItem(LOCAL_SESSION_KEY)}catch(error){console.warn('Purple Gestão — limpeza do cache local de sessão:',error)}}
function renderRecoveryNotice(){const card=$('.login-card');if(!card)return;let box=$('#recoveryModeBox');if(!Bootstrap.recovery){box?.remove();return}if(!box){box=document.createElement('div');box.id='recoveryModeBox';box.className='demo-accounts';const restricted=$('.login-restricted');(restricted?.parentNode||card).insertBefore(box,restricted||null)}const latest=Bootstrap.errors.at(-1);box.innerHTML=`<b>Recovery Mode ativo</b><p style="margin:8px 0 10px">A inicialização entrou em modo degradado. Etapa com falha: <b>${escapeHTML(Bootstrap.failedStep||'bootstrap')}</b>.</p><p style="margin:0 0 12px">${escapeHTML(latest?.message||'Sem detalhes adicionais.')}</p><div class="section-actions" style="justify-content:flex-start"><button type="button" class="btn soft small" onclick="App.showDiagnostics()">Abrir diagnóstico</button><button type="button" class="btn ghost small" onclick="App.fillLogin('direcao@purple.com')">Usar login local</button></div>`}
function enterRecoveryMode(step,error){Bootstrap.recovery=true;Bootstrap.failedStep=step;Bootstrap.loginState='recovery';recordBootstrapError(step,error);renderRecoveryNotice()}
function diagnosticsPayload(){return {appVersion:Bootstrap.appVersion,serviceWorkerVersion:Bootstrap.serviceWorkerVersion,manifestVersion:Bootstrap.manifestVersion,bootstrapErrors:[...Bootstrap.errors],loadedScripts:[...Bootstrap.loadedScripts],loadedResources:typeof performance!=='undefined'&&performance?.getEntriesByType?performance.getEntriesByType('resource').map(entry=>entry.name):[],core:window.PurpleSystemStatus?.()||null,supabase:{sdkType:typeof window.supabase,createClientType:typeof window.supabase?.createClient,url:SUPABASE_URL,keyConfigured:Boolean(SUPABASE_KEY),clientCreated:Bootstrap.supabase.clientCreated,coreReady:Boolean(window.PurpleCore?.supabase?.isReady?.())},app:{exists:typeof window.App,loginType:typeof window.App?.login,recovery:Bootstrap.recovery},loginState:{state:Bootstrap.loginState,user:State.user?{id:State.user.id,email:State.user.email,role:State.user.role}:null}}}
function showDiagnostics(){const payload=diagnosticsPayload();console.info('Purple Gestão diagnostics',payload);if($('#modalRoot'))modal(`<div class="modal-head"><div><span class="eyebrow">Diagnóstico</span><h3>Purple Gestão Recovery Mode</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><pre style="white-space:pre-wrap;max-height:60vh;overflow:auto;font-size:12px;line-height:1.5;background:#f8f5fb;border:1px solid var(--line);border-radius:16px;padding:16px">${escapeHTML(JSON.stringify(payload,null,2))}</pre><div class="section-actions"><button class="btn ghost" onclick="App.closeModal()">Fechar</button></div>`,true);return payload}
function reminderSignature(items){return items.map(item=>`${item.id}:${item.level}`).join('|')}
function pendingDataReminderItems(){const notifications=generateNotifications();return notifications.filter(item=>item.id.startsWith('diary-')||item.id.startsWith('rep-')||item.id.startsWith('act-')||item.id.startsWith('meet-')).filter(item=>['red','yellow'].includes(item.level)).sort((a,b)=>['red','yellow','blue'].indexOf(a.level)-['red','yellow','blue'].indexOf(b.level)||String(b.date||'').localeCompare(String(a.date||''))).slice(0,6)}
function pendingDataReminderSummary(items){return {pendingDiaries:items.filter(item=>item.id.startsWith('diary-missing-')).length,pendingReports:items.filter(item=>item.id.startsWith('rep-sent-')||item.id.startsWith('rep-adjust-')).length,pendingActions:items.filter(item=>item.id.startsWith('act-over-')||item.id.startsWith('act-soon-')).length,pendingMeetings:items.filter(item=>item.id.startsWith('meet-')).length}}
function openNotificationTarget(id){if(id.startsWith('diary-missing-')){const match=id.match(/^diary-missing-([a-z]+)-\d{4}-\d{2}-\d{2}$/i);const sector=match?.[1]||State.user.sector;closeModal();return openOperationalDiaryPage(sector)}if(id.startsWith('rep-')){closeModal();return go('reports')}if(id.startsWith('act-')){closeModal();return go('actions')}if(id.startsWith('meet-')){closeModal();return go('meetings')}return go('notifications')}
function openPendingDataWorkspace(){closeModal();const target=generateNotifications().find(item=>item.id.startsWith('diary-missing-'))||generateNotifications().find(item=>item.id.startsWith('rep-'))||generateNotifications().find(item=>item.id.startsWith('act-'))||generateNotifications().find(item=>item.id.startsWith('meet-'));if(target)return openNotificationTarget(target.id);go('notifications')}
function showPendingDataReminder(force=false){if(!State.user||State.page!=='home')return;const items=pendingDataReminderItems();if(!items.length)return;const signature=reminderSignature(items);const shown=Bootstrap.pendingDataReminderShownFor?.[State.user.id];if(!force&&shown===signature)return;Bootstrap.pendingDataReminderShownFor[State.user.id]=signature;const summary=pendingDataReminderSummary(items);modal(`<div class="pending-data-modal"><div class="modal-head"><div><span class="eyebrow">Lembrete operacional</span><h3>Complete os dados pendentes para gerar estatísticas melhores</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><p class="muted" style="line-height:1.65">Encontramos pendências que impactam os indicadores, o Purple IA e os alertas automáticos. Quando esses registros forem concluídos, o sistema consolida estatísticas mais completas.</p><div class="grid cols-4 reminder-stats"><div class="metric-card"><div class="label">Diários pendentes</div><div class="value">${fmtNumber(summary.pendingDiaries)}</div><div class="note">Atualiza os indicadores diários</div></div><div class="metric-card"><div class="label">Relatórios pendentes</div><div class="value">${fmtNumber(summary.pendingReports)}</div><div class="note">Alimenta dashboards e aprovações</div></div><div class="metric-card"><div class="label">Ações em aberto</div><div class="value">${fmtNumber(summary.pendingActions)}</div><div class="note">Mantém o plano de ação vivo</div></div><div class="metric-card"><div class="label">Reuniões próximas</div><div class="value">${fmtNumber(summary.pendingMeetings)}</div><div class="note">Organiza o centro operacional</div></div></div><div class="panel" style="margin-top:14px"><div class="panel-head"><div><h3>O que precisa ser preenchido agora</h3><small>Os itens abaixo estão puxando a operação para baixo</small></div></div><div class="priority-list">${items.map(item=>`<div class="priority-item"><i class="priority-dot ${item.level==='red'?'alta':item.level==='yellow'?'media':'baixa'}"></i><div><b>${escapeHTML(item.title)}</b><span>${escapeHTML(item.text)}</span></div><button class="btn ghost small" onclick="App.openNotificationTarget('${item.id}')">Abrir</button></div>`).join('')}</div></div><div class="section-actions" style="justify-content:flex-start;margin-top:14px"><button class="btn primary" onclick="App.openPendingDataWorkspace()">Abrir pendências</button><button class="btn soft" onclick="App.closeModal()">Lembrar depois</button></div></div>`,true)}
function initializeSupabaseClient(){try{Bootstrap.supabase.sdkType=typeof window.supabase;if(window.PurpleCore?.supabase?.getClient){Supabase=window.PurpleCore.supabase.getClient()}else if(window.PurpleAuth?.createClient){Supabase=window.PurpleAuth.createClient()}else{if(typeof window.supabase!=='object')throw new Error('window.supabase não está disponível.');if(typeof window.supabase.createClient!=='function')throw new Error('window.supabase.createClient não é uma função.');if(!SUPABASE_URL)throw new Error('SUPABASE_URL não configurada.');if(!SUPABASE_KEY)throw new Error('SUPABASE_KEY não configurada.');Supabase=window.supabase.createClient(SUPABASE_URL,SUPABASE_KEY,{auth:{persistSession:true,autoRefreshToken:true,detectSessionInUrl:true,storage:window.localStorage,storageKey:'purple-gestao-auth'}})}if(!Supabase||!Supabase.auth||typeof Supabase.from!=='function')throw new Error('Cliente Supabase inválido após createClient().');Bootstrap.supabase.clientCreated=true;Bootstrap.loginState='ready';console.info('Purple Gestão bootstrap [supabase] cliente inicializado.')}catch(error){Supabase=null;Bootstrap.supabase.clientCreated=false;enterRecoveryMode('inicialização do Supabase',error)}}
function friendlyError(error,context='operação'){console.error(`Purple Gestão — ${context}:`,error);return 'Não foi possível concluir a operação. Tente novamente.'}
function shouldPreserveTypedCase(el){
  if(!el||el.dataset?.preserveCase==='true'||el.closest?.('[data-preserve-case="true"]'))return true;
  const type=String(el.type||'').toLowerCase();
  return ['email','password','url','date','time','datetime-local','month','week','number','search'].includes(type)||['loginEmail','loginPassword'].includes(el.id);
}
function uppercaseTypedValue(el){
  if(shouldPreserveTypedCase(el)||typeof el.value!=='string')return;
  const upper=el.value.toLocaleUpperCase('pt-BR');
  if(el.value===upper)return;
  const start=el.selectionStart,end=el.selectionEnd;
  el.value=upper;
  try{if(start!==null&&end!==null)el.setSelectionRange(start,end)}catch{}
}
function bindUppercaseTyping(){
  if(Bootstrap.uppercaseTypingBound)return;
  Bootstrap.uppercaseTypingBound=true;
  document.addEventListener('input',event=>{
    const el=event.target;
    if(el?.matches?.('input, textarea'))uppercaseTypedValue(el);
  },true);
}
