function modal(content,small=false){if(window.PurpleCore?.ui?.modal)return window.PurpleCore.ui.modal(content,small);document.body.classList.add('modal-open');$('#modalRoot').innerHTML=`<div class="modal-backdrop" onclick="if(event.target===this)App.closeModal()"><div class="modal ${small?'small':''}">${content}</div></div>`}
