function ensureStudentCepFields(){const cityField=$('#studentCity')?.closest('.field'),addressField=$('#studentAddress')?.closest('.field');if(!cityField||!addressField||$('#studentCep'))return;const grid=cityField.parentElement,s=selectedStudent()||{};addressField.classList.add('span-2');const make=(id,label,value='',attrs='')=>{const div=document.createElement('div');div.className='field';div.innerHTML=`<label>${label}</label><input id="${id}" value="${escapeHTML(value||'')}" ${attrs}/>`;return div};const cep=document.createElement('div');cep.className='field';cep.innerHTML=`<label>CEP</label><input id="studentCep" value="${escapeHTML(formatCepBR(s.zip||s.cep||''))}" oninput="this.value=App.formatCepBR(this.value)" onblur="App.lookupStudentCep()"/><small id="studentCepStatus">Digite o CEP para preencher o endereço.</small>`;grid.insertBefore(cep,cityField);grid.insertBefore(addressField,cityField);addressField.after(make('studentAddressNumber','Número',s.number||s.addressNumber||''));$('#studentAddressNumber')?.closest('.field')?.after(make('studentComplement','Complemento',s.complement||''));$('#studentComplement')?.closest('.field')?.after(make('studentDistrict','Bairro',s.district||s.neighborhood||''));cityField.after(make('studentState','UF',s.state||s.uf||'','maxlength="2" oninput="this.value=this.value.toUpperCase().slice(0,2)"'))}
function readStudentCepPayload(){return {zip:formatCepBR($('#studentCep')?.value||''),cep:formatCepBR($('#studentCep')?.value||''),number:$('#studentAddressNumber')?.value.trim()||'',addressNumber:$('#studentAddressNumber')?.value.trim()||'',complement:$('#studentComplement')?.value.trim()||'',district:$('#studentDistrict')?.value.trim()||'',neighborhood:$('#studentDistrict')?.value.trim()||'',state:($('#studentState')?.value||'').trim().toUpperCase(),uf:($('#studentState')?.value||'').trim().toUpperCase()}}
