function metricChange(arr,key){if(arr.length<2)return 0;const prev=Number(arr.at(-2).metrics[key]||0),cur=Number(arr.at(-1).metrics[key]||0);return prev===0?0:(cur-prev)/Math.abs(prev)*100}
function metricCard(label,value,icon,trend=0,note='Comparado ao período anterior',invert=false){const good=invert?trend<0:trend>0;const cls=Math.abs(trend)<.4?'neutral':good?'good':'bad';return `<div class="metric-card"><div class="metric-top"><div class="metric-icon">${appIcon(icon)}</div><span class="trend ${cls}">${trend>0?'+':''}${trend.toFixed(1)}%</span></div><div class="label">${label}</div><div class="value">${value}</div><div class="note">${note}</div></div>`}
function goalTone(status){return status==='good'?'green':status==='warning'?'yellow':'red'}
function dashboardMetrics(sector){const arr=intelligenceSnapshotsFor(sector,'semanal'),r=arr.at(-1);if(!r)return '';
  if(sector==='retencao')return [
    metricCard('Base ativa',fmtNumber(intelligenceMetric(r,'baseAtiva')),'👥',intelligenceMetricChange(arr,'baseAtiva')),
    metricCard('Alunos em risco',fmtNumber(intelligenceMetric(r,'alunosRisco')),'⚠',intelligenceMetricChange(arr,'alunosRisco'),'Quanto menor, melhor',true),
    metricCard('Taxa de rematrícula',`${fmtNumber(intelligenceMetric(r,'rematriculacaoTaxa','derivedMetrics'),1)}%`,'↻',intelligenceMetricChange(arr,'rematriculacaoTaxa','derivedMetrics'),'Meta vinculada ao setor'),
    metricCard('Receita preservada',fmtMoney(intelligenceMetric(r,'receitaPreservada')),'R$',intelligenceMetricChange(arr,'receitaPreservada'))
  ].join('');
  if(sector==='pedagogico')return [
    metricCard('Aulas realizadas',fmtNumber(intelligenceMetric(r,'aulasRealizadas')),'▣',intelligenceMetricChange(arr,'aulasRealizadas')),
    metricCard('Turmas críticas',fmtNumber(intelligenceMetric(r,'turmasCriticas')),'⚠',intelligenceMetricChange(arr,'turmasCriticas'),'Quanto menor, melhor',true),
    metricCard('Alunos abaixo da média',fmtNumber(intelligenceMetric(r,'alunosBaixoRendimento')),'↘',intelligenceMetricChange(arr,'alunosBaixoRendimento'),'Quanto menor, melhor',true),
    metricCard('Feedbacks aplicados',fmtNumber(intelligenceMetric(r,'feedbacks')),'◌',intelligenceMetricChange(arr,'feedbacks'))
  ].join('');
  return [
    metricCard('Receita prevista',fmtMoney(intelligenceMetric(r,'receitaPrevista')),'R$',intelligenceMetricChange(arr,'receitaPrevista')),
    metricCard('Receita realizada',fmtMoney(intelligenceMetric(r,'receitaRealizada')),'↗',intelligenceMetricChange(arr,'receitaRealizada')),
    metricCard('Inadimplência',fmtMoney(intelligenceMetric(r,'inadimplencia')),'⚠',intelligenceMetricChange(arr,'inadimplencia'),'Quanto menor, melhor',true),
    metricCard('Saldo atual',fmtMoney(intelligenceMetric(r,'saldoAtual')),'▤',intelligenceMetricChange(arr,'saldoAtual'))
  ].join('')
}
function lineChartSVG(reports,series){if(!reports.length)return '<div class="empty"><p>Sem dados para o gráfico.</p></div>';const W=720,H=240,pad={l:42,r:18,t:18,b:34};const metricValue=(row,key,bucket)=>Number(bucket==='derivedMetrics'?row.derivedMetrics?.[key]:row.metrics?.[key]||0);const values=reports.flatMap(r=>series.map(s=>metricValue(r,s.key,s.bucket)));const min=Math.min(0,...values),max=Math.max(1,...values);const x=i=>pad.l+(W-pad.l-pad.r)*(reports.length===1?.5:i/(reports.length-1));const y=v=>pad.t+(H-pad.t-pad.b)*(1-(v-min)/(max-min||1));let svg=`<svg viewBox="0 0 ${W} ${H}" class="chart-svg" role="img">`;
  [0,.25,.5,.75,1].forEach(t=>{const yy=pad.t+(H-pad.t-pad.b)*t;svg+=`<line x1="${pad.l}" y1="${yy}" x2="${W-pad.r}" y2="${yy}" class="chart-grid"/>`});
  svg+=`<line x1="${pad.l}" y1="${H-pad.b}" x2="${W-pad.r}" y2="${H-pad.b}" class="chart-axis"/>`;
  series.forEach((s,si)=>{const pts=reports.map((r,i)=>`${x(i)},${y(metricValue(r,s.key,s.bucket))}`).join(' ');svg+=`<polyline points="${pts}" class="chart-line ${si?'alt':''}"/>`;reports.forEach((r,i)=>{const v=metricValue(r,s.key,s.bucket);svg+=`<circle cx="${x(i)}" cy="${y(v)}" r="4" class="chart-dot ${si?'alt':''}"><title>${s.label}: ${s.type==='money'?fmtMoney(v):fmtNumber(v)}</title></circle>`})});
  reports.forEach((r,i)=>{const labelDate=r.periodEnd||r.end||r.presentationDate||r.presentation||'';svg+=`<text x="${x(i)}" y="${H-10}" text-anchor="middle" class="chart-label">${labelDate?fmtDate(labelDate).slice(0,5):`P${i+1}`}</text>`});svg+='</svg>';
  return `<div class="chart-shell">${svg}<div class="chart-legend">${series.map((s,i)=>`<span><i class="${i?'alt':''}"></i>${s.label}</span>`).join('')}</div></div>`
}
function buildSectorAlerts(sector,snapshot){if(!snapshot)return '<div class="empty"><p>Sem indicador consolidado recente.</p></div>';
  if(sector==='retencao'){const remGoal=intelligenceGoal(snapshot,'rematriculacaoTaxa'),riskGoal=intelligenceGoal(snapshot,'alunosRisco');return `<div class="alert ${goalTone(remGoal?.status||'warning')}"><div class="alert-icon">↻</div><div><b>Taxa de rematrícula</b><span>${fmtNumber(intelligenceMetric(snapshot,'rematriculacaoTaxa','derivedMetrics'),1)}% concluídas; meta atual em ${fmtNumber(remGoal?.target||State.db.settings.rematriculationTarget,1)}%.</span></div></div><div class="alert ${goalTone(riskGoal?.status||'critical')}"><div class="alert-icon">!</div><div><b>Alunos em risco</b><span>${fmtNumber(intelligenceMetric(snapshot,'alunosRisco'))} casos ativos no fechamento.</span></div></div><div class="alert blue"><div class="alert-icon">◎</div><div><b>Casos integrados</b><span>${State.db.cases.filter(c=>c.retencao.level!=='good').length} casos com atenção em retenção.</span></div></div>`}
  if(sector==='pedagogico'){const criticalGoal=intelligenceGoal(snapshot,'turmasCriticas');return `<div class="alert ${goalTone(criticalGoal?.status||'warning')}"><div class="alert-icon">!</div><div><b>Turmas críticas</b><span>${fmtNumber(intelligenceMetric(snapshot,'turmasCriticas'))} turmas exigem intervenção.</span></div></div><div class="alert red"><div class="alert-icon">↘</div><div><b>Baixo rendimento</b><span>${fmtNumber(intelligenceMetric(snapshot,'alunosBaixoRendimento'))} alunos abaixo do esperado.</span></div></div><div class="alert green"><div class="alert-icon">✓</div><div><b>Reforços</b><span>${fmtNumber(intelligenceMetric(snapshot,'reforcos'))} intervenções realizadas.</span></div></div>`}
  const gap=Math.max(0,intelligenceMetric(snapshot,'receitaPrevista')-intelligenceMetric(snapshot,'receitaRealizada')),delinquencyGoal=intelligenceGoal(snapshot,'inadimplencia');return `<div class="alert ${gap>0?'red':'green'}"><div class="alert-icon">!</div><div><b>Diferença de receita</b><span>${fmtMoney(gap)} abaixo do previsto.</span></div></div><div class="alert ${goalTone(delinquencyGoal?.status||'warning')}"><div class="alert-icon">↗</div><div><b>Inadimplência</b><span>${fmtMoney(intelligenceMetric(snapshot,'inadimplencia'))} vencidos no fechamento.</span></div></div><div class="alert green"><div class="alert-icon">✓</div><div><b>Saldo atual</b><span>${fmtMoney(intelligenceMetric(snapshot,'saldoAtual'))} disponíveis.</span></div></div>`
}
function statusDonut(reports){const counts={approved:0,sent:0,review:0,draft:0,adjust:0,archived:0};reports.forEach(r=>counts[r.status]=(counts[r.status]||0)+1);const total=Math.max(1,reports.length);const a=counts.approved/total*100,s=(counts.sent+counts.review)/total*100,d=(counts.draft+counts.adjust+counts.archived)/total*100;return `<div class="donut-layout"><div style="position:relative;width:140px;height:140px"><div class="donut" style="background:conic-gradient(var(--p700) 0 ${a}%,var(--orange) ${a}% ${a+s}%,#d9c9e5 ${a+s}% 100%)"></div><div class="donut-center">${reports.length}</div></div><div class="legend-list"><div><span><i style="background:var(--p700)"></i>Aprovados</span><b>${counts.approved}</b></div><div><span><i style="background:var(--orange)"></i>Em análise</span><b>${counts.sent+counts.review}</b></div><div><span><i style="background:#d9c9e5"></i>Outros</span><b>${counts.draft+counts.adjust+counts.archived}</b></div></div></div>`}
const DNA_PHRASES=['Pessoas vêm antes dos processos.','Faça simples. Faça bem feito.','Evolução acontece todos os dias.','Ensinar muda vidas.','Consistência vence intensidade.','Organização é liberdade.'];
function todayISO(){const d=new Date();return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`}
function greeting(){const h=new Date().getHours(),word=h<12?'Bom dia':h<18?'Boa tarde':'Boa noite',name=(State.user.name||'Purple').split(/[ —-]/)[0];return `${word}, ${name}!`}
function currentDateLong(){return new Date().toLocaleDateString('pt-BR',{weekday:'long',day:'numeric',month:'long',year:'numeric'})}
function homePriorities(){const items=[];State.db.reports.filter(r=>sectorAllowed(r.sector)).forEach(r=>{if(r.status==='adjust')items.push({kind:'report',id:r.id,title:'Relatório devolvido para ajuste',sector:r.sector,date:r.presentation,priority:'alta',status:'Ajuste solicitado'});else if(['sent','review'].includes(r.status))items.push({kind:'report',id:r.id,title:State.user.role==='direction'?'Relatório aguardando aprovação':'Relatório aguardando análise',sector:r.sector,date:r.presentation,priority:'alta',status:STATUS_LABELS[r.status]})});State.db.actions.filter(actionVisible).forEach(a=>{const d=daysUntil(a.deadline);if(!['done','cancelled'].includes(a.status)&&d<=0)items.push({kind:'action',id:a.id,title:a.title,sector:a.sector,date:a.deadline,priority:d<0?'alta':a.priority,status:d<0?'Atrasado':'Vence hoje'})});State.db.meetings.filter(meetingVisible).filter(m=>m.status!=='done'&&m.date===todayISO()).forEach(m=>items.push({kind:'meeting',id:m.id,title:`Café com Raphael — ${m.participant}`,sector:m.sector,date:m.date,priority:'media',status:m.time}));return items.slice(0,8)}
function assistInsight(){const p=homePriorities(),adjust=p.find(x=>x.status==='Ajuste solicitado'),overdue=p.find(x=>x.status==='Atrasado'),reports=p.filter(x=>x.kind==='report');if(adjust)return {text:'Existe um relatório devolvido para ajuste.',action:'Revise a orientação e prepare o reenvio.',item:adjust};if(overdue)return {text:'Existe um plano de ação atrasado.',action:'Atualize o responsável e registre o próximo passo.',item:overdue};if(reports.length)return {text:`Você possui ${reports.length} relatório(s) aguardando análise.`,action:'Comece pelo item mais recente.',item:reports[0]};return {text:'Não há pendências críticas neste momento.',action:'Revise os próximos compromissos.',item:{kind:'meetings'}}}
