function purpleIaVisibleSectors(){return State.user?.accessScope==='all_sectors'?['retencao','pedagogico','financeiro']:[State.user?.sector].filter(Boolean)}
function purpleIaSeverityWeight(priority){return priority==='alta'?14:priority==='media'?8:4}
function purpleIaEstimatedTicket(){
  const fin=latestIntelligenceSnapshot('financeiro','semanal'),ret=latestIntelligenceSnapshot('retencao','semanal');
  const revenue=Math.max(intelligenceMetric(fin,'receitaRealizada'),intelligenceMetric(fin,'receitaRecebida'));
  const base=Math.max(1,intelligenceMetric(ret,'baseAtiva'));
  return revenue>0?Math.max(350,revenue/base):850;
}
function purpleIaRecommendationTone(priority){return priority==='alta'?'red':priority==='media'?'yellow':'green'}
function purpleIaRecommendationStatus(priority){return priority==='alta'?'Criticidade alta':priority==='media'?'Atenção importante':'Monitoramento'}
function purpleIaRecommendationObject(partial){return {id:partial.id||uid('pia'),priority:partial.priority||'media',sector:partial.sector||'integrado',title:partial.title||'Acompanhar indicador',problem:partial.problem||'',impact:partial.impact||'',why:partial.why||'',actions:partial.actions||[],page:partial.page||'dashboard',targetId:partial.targetId||'',metricLabel:partial.metricLabel||'',current:partial.current||'',target:partial.target||'',owner:partial.owner||'Gestão',dueDate:partial.dueDate||todayISO()}}
function purpleIaLearningInsights(){
  const finished=(State.db.actions||[]).filter(a=>a.status==='done'&&a.resolutionNote);
  if(!finished.length)return {summary:'Ainda não há histórico suficiente de ações concluídas para aprendizado operacional.',items:[]};
  const groups={};
  finished.forEach(a=>{
    const key=`${a.sector||'integrado'}:${(a.title||'').toLowerCase().split(/\s+/).slice(0,4).join(' ')}`;
    groups[key]=groups[key]||{sector:a.sector,count:0,totalMinutes:0,titles:new Set()};
    groups[key].count+=1;
    groups[key].titles.add(a.title);
    const created=new Date(a.createdAt||a.updatedAt||Date.now());
    const done=new Date(a.completedAt||a.updatedAt||Date.now());
    groups[key].totalMinutes+=Math.max(1,Math.round((done-created)/60000));
  });
  const top=Object.values(groups).sort((a,b)=>b.count-a.count||a.totalMinutes-b.totalMinutes).slice(0,3).map(item=>({sector:item.sector,count:item.count,avgMinutes:Math.max(1,Math.round(item.totalMinutes/Math.max(1,item.count))),title:[...item.titles][0]}));
  const avg=top.length?Math.round(top.reduce((s,x)=>s+x.avgMinutes,0)/top.length):0;
  return {summary:`O sistema já observou ${finished.length} ação(ões) concluída(s). Em média, as ações levavam ${avg} min para fechar quando eram resolvidas com disciplina.`,items:top};
}
function purpleIaSectorRecommendations(sector){
  const snapshot=latestIntelligenceSnapshot(sector,'semanal');
  if(!snapshot)return [];
  const out=[],ticket=purpleIaEstimatedTicket();
  if(sector==='retencao'){
    const remGoal=intelligenceGoal(snapshot,'rematriculacaoTaxa');
    const remRate=intelligenceMetric(snapshot,'rematriculacaoTaxa','derivedMetrics');
    const remTarget=Number(remGoal?.target||State.db.settings.rematriculationTarget||80);
    const baseAtiva=intelligenceMetric(snapshot,'baseAtiva');
    const alunosRisco=intelligenceMetric(snapshot,'alunosRisco');
    if(remRate<remTarget){
      const lostStudents=Math.max(1,Math.round((remTarget-remRate)/100*Math.max(baseAtiva,1)));
      out.push(purpleIaRecommendationObject({
        id:`ret-rem-${snapshot.sourceId||snapshot.periodEnd}`,priority:remRate<remTarget*0.8?'alta':'media',sector,title:'Rematrículas abaixo da meta',
        problem:`Meta de ${fmtNumber(remTarget,1)}% e resultado atual de ${fmtNumber(remRate,1)}%.`,
        impact:`Impacto estimado de ${fmtMoney(lostStudents*ticket)} no próximo ciclo caso o ritmo não seja recuperado.`,
        why:`A base em risco está em ${fmtNumber(alunosRisco)} aluno(s) e o fechamento mais recente ainda não converteu o volume esperado.`,
        actions:[`Agendar contato hoje com os ${fmtNumber(Math.max(3,alunosRisco))} casos mais sensíveis.`,`Priorizar famílias com decisão pendente no próximo fechamento.`,`Abrir ou atualizar um plano de ação para cada grupo com baixa conversão.`],
        page:'dashboard',targetId:snapshot.sourceId||'',metricLabel:'Taxa de rematrícula',current:`${fmtNumber(remRate,1)}%`,target:`${fmtNumber(remTarget,1)}%`,owner:'Retenção',dueDate:snapshot.presentationDate||snapshot.periodEnd||todayISO()
      }));
    }
    if(alunosRisco>=Math.max(3,Number(State.db.settings.retentionRisk||25)/4)){
      out.push(purpleIaRecommendationObject({
        id:`ret-risk-${snapshot.sourceId||snapshot.periodEnd}`,priority:alunosRisco>=Number(State.db.settings.retentionRisk||25)?'alta':'media',sector,title:'Casos de evasão exigem intervenção imediata',
        problem:`Existem ${fmtNumber(alunosRisco)} aluno(s) em risco ativo.`,
        impact:`Cada recuperação evita perda potencial de receita recorrente e reduz cancelamentos no próximo fechamento.`,
        why:'Quando esse indicador sobe, a evasão tende a aparecer nos fechamentos seguintes se a escola não reage rapidamente.',
        actions:[`Revisar agora os casos integrados de retenção com status diferente de bom.`,`Converter os alunos sem retorno em tarefas com prazo de hoje.`,`Escalar para reunião pedagógica os casos sem avanço após o primeiro contato.`],
        page:'cases',owner:'Retenção',dueDate:todayISO()
      }));
    }
  }
  if(sector==='pedagogico'){
    const critical=intelligenceMetric(snapshot,'turmasCriticas');
    const low=intelligenceMetric(snapshot,'alunosBaixoRendimento');
    const target=intelligenceGoal(snapshot,'turmasCriticas')?.target||State.db.settings.criticalGroups||5;
    if(critical>target){
      out.push(purpleIaRecommendationObject({
        id:`ped-critical-${snapshot.sourceId||snapshot.periodEnd}`,priority:critical>=target*1.4?'alta':'media',sector,title:'Turmas críticas acima do limite',
        problem:`${fmtNumber(critical)} turma(s) críticas frente ao limite de ${fmtNumber(target)}.`,
        impact:'A tendência é aumento de reclamações, queda de engajamento e pressão sobre rematrícula se o desvio continuar.',
        why:'O consolidado pedagógico mostra concentração de risco em desempenho e consistência de execução.',
        actions:[`Abrir hoje uma leitura turma a turma das ${fmtNumber(Math.min(critical,5))} mais críticas.`,`Definir intervenção pedagógica com professor responsável e prazo fechado.`,`Registrar no próximo relatório a causa principal e o resultado esperado de cada ação.`],
        page:'dashboard',metricLabel:'Turmas críticas',current:fmtNumber(critical),target:fmtNumber(target),owner:'Pedagógico',dueDate:todayISO()
      }));
    }
    if(low>0){
      out.push(purpleIaRecommendationObject({
        id:`ped-performance-${snapshot.sourceId||snapshot.periodEnd}`,priority:low>=10?'alta':'media',sector,title:'Baixo rendimento pede ação orientada',
        problem:`${fmtNumber(low)} aluno(s) abaixo do desempenho esperado.`,
        impact:'Sem intervenção rápida, esse grupo costuma gerar queda de satisfação e risco indireto de evasão.',
        why:'O dado pedagógico isolado não resolve; ele precisa virar reforço, feedback e acompanhamento.',
        actions:[`Priorizar feedback individual ou por turma para os casos com maior defasagem.`,`Programar reforço, reposição ou replanejamento para as próximas aulas.`,`Escalar para a Direção apenas os casos sem melhora após a primeira ação.`],
        page:'reports',owner:'Pedagógico',dueDate:todayISO()
      }));
    }
  }
  if(sector==='financeiro'){
    const delinquency=intelligenceMetric(snapshot,'inadimplencia');
    const delinquencyTarget=intelligenceGoal(snapshot,'inadimplencia')?.target||State.db.settings.delinquencyAlert||6000;
    const expected=intelligenceMetric(snapshot,'receitaPrevista');
    const realized=Math.max(intelligenceMetric(snapshot,'receitaRealizada'),intelligenceMetric(snapshot,'receitaRecebida'));
    if(delinquency>delinquencyTarget){
      out.push(purpleIaRecommendationObject({
        id:`fin-delinquency-${snapshot.sourceId||snapshot.periodEnd}`,priority:delinquency>=delinquencyTarget*1.2?'alta':'media',sector,title:'Inadimplência acima da meta',
        problem:`A meta está em ${fmtMoney(delinquencyTarget)} e o consolidado atual fechou em ${fmtMoney(delinquency)}.`,
        impact:`A recuperação desse valor melhora caixa e reduz risco de perda de receita já comprometida.`,
        why:'Quando a inadimplência cresce por mais de um fechamento, a capacidade de previsão e negociação cai rapidamente.',
        actions:[`Cobrar hoje os títulos mais antigos e com maior valor.`,`Separar negociação dos casos com maior probabilidade de pagamento.`,`Registrar no próximo fechamento o valor efetivamente recuperado por ação.`],
        page:'dashboard',metricLabel:'Inadimplência',current:fmtMoney(delinquency),target:fmtMoney(delinquencyTarget),owner:'Financeiro',dueDate:todayISO()
      }));
    }
    if(expected>0&&realized<expected){
      const gap=expected-realized;
      out.push(purpleIaRecommendationObject({
        id:`fin-gap-${snapshot.sourceId||snapshot.periodEnd}`,priority:gap>=expected*0.1?'alta':'media',sector,title:'Receita realizada abaixo do previsto',
        problem:`Faltam ${fmtMoney(gap)} para alcançar a previsão do período.`,
        impact:'A diferença reduz margem e pressiona o próximo fechamento se permanecer sem plano de recuperação.',
        why:'Receita abaixo do previsto combinada com inadimplência alta é um sinal de atenção operacional e comercial.',
        actions:[`Cruzar hoje o gap com recebimentos pendentes e contratos em atraso.`,`Priorizar ações de recuperação com maior valor potencial.`,`Levar o desvio para a Direção se o plano não compensar até o próximo fechamento.`],
        page:'dashboard',metricLabel:'Receita realizada',current:fmtMoney(realized),target:fmtMoney(expected),owner:'Financeiro',dueDate:todayISO()
      }));
    }
  }
  const learning=purpleIaLearningInsights();
  if(learning.items.length){
    const match=learning.items.find(item=>item.sector===sector);
    if(match)out.push(purpleIaRecommendationObject({
      id:`learn-${sector}-${match.title}`,priority:match.count>=3?'media':'baixa',sector,title:'Histórico operacional reforça esta abordagem',
      problem:`${match.count} situação(ões) semelhantes já foram concluídas com sucesso nesta área.`,
      impact:`Nas últimas ocorrências semelhantes, essa linha de ação levou cerca de ${fmtNumber(match.avgMinutes)} min para virar desfecho.`,
      why:learning.summary,
      actions:[`Reaproveitar a estratégia que funcionou em ${fmtNumber(match.count)} caso(s) semelhantes.`,`Registrar o resultado para alimentar a próxima recomendação.`,`Atualizar o plano de ação com o que foi feito de fato.`],
      page:'actions',owner:'Purple IA',dueDate:todayISO()
    }));
  }
  return out;
}
function purpleIaOperationalRecommendations(){
  const out=[];
  purpleIaVisibleSectors().forEach(sector=>{
    const diary=operationalDiaryEntries().find(entry=>entry.sector===sector&&entry.entryDate===todayISO());
    if(!diary){
      out.push(purpleIaRecommendationObject({
        id:`diary-${sector}-${todayISO()}`,priority:'media',sector,title:`Diário operacional pendente em ${SECTOR_LABELS[sector]}`,
        problem:`Ainda não existe registro diário de ${SECTOR_LABELS[sector]} para hoje.`,
        impact:'Sem esse fechamento, o dashboard perde atualização e a liderança toma decisão com dado incompleto.',
        why:'A ausência do diário bloqueia a leitura mais rápida das variações do dia.',
        actions:[`Preencher o diário operacional antes do próximo turno.`,`Registrar ao menos o contexto principal do dia.`,`Usar o fechamento para antecipar problemas antes do relatório semanal.`],
        page:'operational-diary',owner:SECTOR_LABELS[sector],dueDate:todayISO()
      }));
    }
  });
  const reportsPending=State.db.reports.filter(r=>sectorAllowed(r.sector)&&['sent','review'].includes(r.status));
  if(reportsPending.length){
    out.push(purpleIaRecommendationObject({
      id:`reports-pending-${reportsPending.length}`,priority:State.user.role==='direction'?'alta':'media',sector:'integrado',title:'Relatórios aguardando decisão',
      problem:`Existem ${fmtNumber(reportsPending.length)} relatório(s) no fluxo de análise.`,
      impact:'Enquanto o relatório não vira decisão, o dado não se transforma em ação para a equipe.',
      why:'Fechamentos parados aumentam o tempo entre problema identificado e resposta operacional.',
      actions:[`Começar pelo relatório mais recente ou mais crítico.`,`Registrar aprovação ou ajuste ainda hoje.`,`Converter cada risco relevante em plano de ação com responsável.`],
      page:'reports',owner:State.user.role==='direction'?'Direção':'Liderança',dueDate:todayISO()
    }));
  }
  return out;
}
function purpleIaRecommendations(){
  const items=[...purpleIaVisibleSectors().flatMap(purpleIaSectorRecommendations),...purpleIaOperationalRecommendations()];
  return items.sort((a,b)=>purpleIaSeverityWeight(b.priority)-purpleIaSeverityWeight(a.priority)||String(a.sector).localeCompare(String(b.sector)));
}
function purpleIaUnitScore(){
  const score=Math.max(0,100-purpleIaRecommendations().reduce((sum,item)=>sum+purpleIaSeverityWeight(item.priority),0));
  return Math.round(score);
}
function purpleIaSectorScore(sector){
  const items=purpleIaRecommendations().filter(item=>item.sector===sector);
  return Math.max(0,Math.round(100-items.reduce((sum,item)=>sum+purpleIaSeverityWeight(item.priority),0)));
}
function purpleIaExecutiveSummary(){
  const items=purpleIaRecommendations(),score=purpleIaUnitScore();
  if(!items.length)return {title:'Operação sob controle',text:'Não há situações críticas abertas no momento. O foco agora é manter o ritmo e revisar apenas os próximos compromissos.'};
  const critical=items.filter(item=>item.priority==='alta').length;
  const sectors=[...new Set(items.map(item=>SECTOR_LABELS[item.sector]||'Geral'))].slice(0,3).join(', ');
  return {title:`Hoje existem ${items.length} situação(ões) que merecem atenção`,text:`Saúde atual da unidade em ${score}/100. ${critical?`${critical} são críticas.`:'Nenhuma está em criticidade máxima.'} Áreas mais impactadas: ${sectors}.`};
}
function purpleIaDailySummary(){
  const rows=purpleIaVisibleSectors().map(sector=>{
    const diary=operationalDiaryEntries().find(entry=>entry.sector===sector&&entry.entryDate===todayISO());
    if(diary)return `${SECTOR_LABELS[sector]}: diário de hoje preenchido com ${Object.keys(diary.metrics||{}).length} indicador(es).`;
    return `${SECTOR_LABELS[sector]}: diário de hoje ainda pendente.`;
  });
  return rows.length?rows:['Sem setores visíveis no momento.'];
}
function purpleIaWeeklySummary(){
  const rows=purpleIaVisibleSectors().map(sector=>{
    const snapshot=latestIntelligenceSnapshot(sector,'semanal');
    if(!snapshot)return `${SECTOR_LABELS[sector]}: sem consolidação semanal recente.`;
    const items=purpleIaSectorRecommendations(sector);
    const critical=items.filter(item=>item.priority==='alta').length;
    const main=items[0]?.title||'Nenhuma urgência relevante';
    return `${SECTOR_LABELS[sector]}: ${critical} risco(s) crítico(s) e foco em ${main}.`;
  });
  return rows.length?rows:['Sem consolidado semanal disponível.'];
}
function purpleIaMonthlySummary(){
  const rows=purpleIaVisibleSectors().map(sector=>{
    const monthly=latestIntelligenceSnapshot(sector,'mensal')||latestIntelligenceSnapshot(sector,'quinzenal')||latestIntelligenceSnapshot(sector,'semanal');
    if(!monthly)return `${SECTOR_LABELS[sector]}: sem base mensal para leitura.`;
    const summary=monthly.context?.summary||monthly.context?.periodLabel||'Consolidação disponível';
    return `${SECTOR_LABELS[sector]}: ${summary}.`;
  });
  return rows.length?rows:['Sem consolidado mensal disponível.'];
}
function renderPurpleIaRecommendation(item,index){
  return `<article class="panel purple-ia-card ${item.priority}"><div class="purple-ia-head"><div><span class="eyebrow">Purple IA • ${SECTOR_LABELS[item.sector]||'Geral'}</span><h3>${escapeHTML(item.title)}</h3></div><span class="status ${item.priority==='alta'?'rejected':item.priority==='media'?'pending':'approved'}">${purpleIaRecommendationStatus(item.priority)}</span></div><p class="purple-ia-problem">${escapeHTML(item.problem)}</p><div class="purple-ia-meta">${item.metricLabel?`<span><b>${escapeHTML(item.metricLabel)}:</b> ${escapeHTML(item.current)}</span>`:''}${item.target?`<span><b>Meta:</b> ${escapeHTML(item.target)}</span>`:''}<span><b>Responsável:</b> ${escapeHTML(item.owner)}</span><span><b>Prazo:</b> ${fmtDate(item.dueDate)}</span></div><div class="alert ${purpleIaRecommendationTone(item.priority)}" style="margin-top:12px"><div class="alert-icon">!</div><div><b>Impacto estimado</b><span>${escapeHTML(item.impact)}</span></div></div><div class="form-card" style="margin-top:12px"><h4>Plano sugerido</h4><ol class="purple-ia-steps">${item.actions.map(step=>`<li>${escapeHTML(step)}</li>`).join('')}</ol><p class="muted" style="margin-top:10px">${escapeHTML(item.why)}</p></div><div class="section-actions"><button class="btn ghost" onclick="App.go('${item.page}')">Abrir contexto</button><button class="btn primary" onclick="App.createPurpleIaTask(${index})">Criar tarefa</button></div></article>`;
}
function renderPurpleIa(){
  const items=purpleIaRecommendations(),summary=purpleIaExecutiveSummary(),score=purpleIaUnitScore(),visibleSectors=purpleIaVisibleSectors(),learning=purpleIaLearningInsights();
  const highlights=visibleSectors.map(sector=>`<div class="metric-card"><div class="metric-top"><div class="metric-icon">${sector==='retencao'?'↻':sector==='pedagogico'?'▣':'R$'}</div><span class="trend ${purpleIaSectorScore(sector)>=85?'good':purpleIaSectorScore(sector)>=70?'neutral':'bad'}">${purpleIaSectorScore(sector)}/100</span></div><div class="label">${SECTOR_LABELS[sector]}</div><div class="value">${items.filter(item=>item.sector===sector).length}</div><div class="note">recomendação(ões) ativa(s)</div></div>`).join('');
  const top=items.slice(0,6);
  return `<div class="page purple-ia-page"><section class="hero purple-ia-hero"><div class="hero-content"><div><span class="eyebrow light">Purple IA — Consultor de Gestão</span><h2>${escapeHTML(summary.title)}</h2><p>${escapeHTML(summary.text)}</p></div><div class="hero-badge">Saúde da unidade ${score}/100</div></div></section><section class="grid cols-4">${metricCard('Saúde da unidade',`${score}/100`,'✦',0,'Quanto maior, melhor')}${metricCard('Prioridades críticas',fmtNumber(items.filter(item=>item.priority==='alta').length),'!',0,'Exigem resposta imediata')}${metricCard('Ações sugeridas',fmtNumber(items.length),'✓',0,'Geradas a partir dos dados atuais')}${metricCard('Planos em aberto',fmtNumber(State.db.actions.filter(actionVisible).filter(a=>!['done','cancelled'].includes(a.status)).length),'◷',0,'Execução em andamento')}</section><section class="grid cols-3" style="margin-top:16px">${highlights}</section><section class="grid cols-3" style="margin-top:16px">${[['Resumo diário',purpleIaDailySummary()],['Resumo semanal',purpleIaWeeklySummary()],['Resumo mensal',purpleIaMonthlySummary()]].map(([label,rows])=>`<div class="panel"><div class="panel-head"><div><h3>${label}</h3><small>Leitura automática para a liderança</small></div></div><ul class="purple-ia-summary-list">${rows.map(row=>`<li>${escapeHTML(row)}</li>`).join('')}</ul></div>`).join('')}</section><section class="grid cols-2" style="margin-top:16px"><div class="panel"><div class="panel-head"><div><h3>Prioridades do dia</h3><small>Nunca mostrar um dado sem mostrar o que fazer</small></div></div><div class="priority-list">${top.map((item,index)=>`<div class="priority-item"><i class="priority-dot ${item.priority}"></i><div><b>${escapeHTML(item.title)}</b><span>${SECTOR_LABELS[item.sector]||'Geral'} • ${escapeHTML(item.impact)}</span></div><button class="btn ghost small" onclick="App.go('purple-ia')">Ver plano</button></div>`).join('')||'<p class="muted">Sem prioridades abertas.</p>'}</div></div><div class="panel"><div class="panel-head"><div><h3>Aprendizado operacional</h3><small>O que a IA aprendeu com ações concluídas</small></div></div><p class="muted" style="line-height:1.65">${escapeHTML(learning.summary)}</p><div class="priority-list">${learning.items.map(item=>`<div class="priority-item"><i class="priority-dot baixa"></i><div><b>${escapeHTML(item.title)}</b><span>${SECTOR_LABELS[item.sector]||'Geral'} • ${fmtNumber(item.count)} caso(s) • ${fmtNumber(item.avgMinutes)} min médio</span></div></div>`).join('')||'<p class="muted">Sem histórico suficiente ainda.</p>'}</div></div></section><section class="dashboard-layout" style="margin-top:16px"><div class="panel"><div class="panel-head"><div><h3>Resumo executivo</h3><small>Leitura orientada para decisão</small></div></div><div class="human-summary"><li>${escapeHTML(summary.text)}</li>${visibleSectors.map(sector=>`<li>${SECTOR_LABELS[sector]} com score ${purpleIaSectorScore(sector)}/100 e ${items.filter(item=>item.sector===sector).length} ação(ões) sugerida(s).</li>`).join('')}</div><div class="alert blue" style="margin-top:12px"><div class="alert-icon">◎</div><div><b>Próximo passo sugerido</b><span>${escapeHTML(top[0]?.actions?.[0]||'Nenhuma ação imediata necessária.')}</span></div></div></div></section><section class="purple-ia-grid">${items.map(renderPurpleIaRecommendation).join('')||'<section class="panel"><div class="empty"><h3>Nenhuma recomendação ativa</h3><p>O copiloto não encontrou riscos relevantes com os dados atuais.</p></div></section>'}</section></div>`;
}
function quickSummary(){const out=[],sectors=availableSectors(),students=officialStudentCounts();out.push(`${fmtNumber(students.active)} alunos ativos na base oficial; ${fmtNumber(students.inProgress)} matrícula(s) em andamento.`);out.push(`${fmtNumber(students.inactive+students.locked)} aluno(s) inativo(s) ou trancado(s); ${fmtNumber(students.cancelled)} cancelado(s).`);sectors.forEach(s=>{const snapshot=latestIntelligenceSnapshot(s,'semanal');if(!snapshot)return;if(s==='financeiro')out.push(`Receita de ${fmtMoney(intelligenceMetric(snapshot,'receitaRealizada'))}; inadimplência de ${fmtMoney(intelligenceMetric(snapshot,'inadimplencia'))}.`)});out.push(`${State.db.actions.filter(actionVisible).filter(a=>!['done','cancelled'].includes(a.status)).length} planos de ação abertos.`);return out.slice(0,4)}
function homeMetrics(){const sectors=availableSectors(),cards=[],students=officialStudentCounts(),totals=businessTotals();cards.push(metricCard('Alunos ativos',fmtNumber(totals.studentsActive||students.active),'◉',0,'Base oficial de alunos'));cards.push(metricCard('Professores ativos',fmtNumber(totals.teachersActive),'♛',0,'Equipe em operação'));cards.push(metricCard('Turmas ativas',fmtNumber(totals.classesActive),'▤',0,`${fmtNumber(totals.fullClasses)} turma(s) lotada(s)`));if(sectors.includes('financeiro'))cards.push(metricCard('Inadimplência',fmtMoney(intelligenceMetric(latestIntelligenceSnapshot('financeiro'),'inadimplencia')),'R$',0,'Financeiro'));else cards.push(metricCard('Ações abertas',fmtNumber(State.db.actions.filter(actionVisible).filter(a=>!['done','cancelled'].includes(a.status)).length),'✓',0,'Planos de ação'));return cards.slice(0,4).join('')}
function taskRows(filter='active'){const today=todayISO();return (State.db.tasks||[]).filter(t=>t.user_id===State.user.id).filter(t=>{if(filter==='completed'||filter==='archived')return t.completed;if(filter==='today')return !t.completed&&t.due_date===today;if(filter==='overdue')return !t.completed&&t.due_date&&t.due_date<today;return !t.completed}).sort((a,b)=>Number(a.completed)-Number(b.completed)||(a.due_date||'9999').localeCompare(b.due_date||'9999'))}
function taskCompletionTime(task){if(!task.completed_at||!task.created_at)return '';const minutes=Math.max(1,Math.round((new Date(task.completed_at)-new Date(task.created_at))/60000));if(minutes<60)return `${minutes} min`;const hours=Math.round(minutes/60);if(hours<24)return `${hours} h`;return `${Math.round(hours/24)} dia(s)`}
function renderTasks(){const editable=State.user.role!=='viewer',counts={active:taskRows('active').length,today:taskRows('today').length,overdue:taskRows('overdue').length,completed:taskRows('completed').length,archived:taskRows('archived').length},activeRows=taskRows(State.taskFilter);return `<section id="tasksSection" class="panel home-section"><div class="home-section-head"><div><span class="eyebrow">Meu Dia</span><h3>Suas tarefas</h3></div>${editable?'<button class="btn primary small" onclick="App.editTask()">Nova tarefa</button>':''}</div><div class="task-filters">${[['active',`Pendentes ${counts.active}`],['today',`Hoje ${counts.today}`],['overdue',`Atrasadas ${counts.overdue}`],['completed',`Concluídas ${counts.completed}`],['archived',`Arquivadas ${counts.archived}`]].map(([filter,label])=>`<button class="${State.taskFilter===filter?'active':''}" onclick="App.setTaskFilter('${filter}')">${label}</button>`).join('')}</div><div class="field"><input type="search" placeholder="Pesquisar tarefas" oninput="App.filterTasks(this.value)"/></div><div class="task-list">${activeRows.map(t=>`<div class="task-item ${t.completed?'done':''}" data-task-search="${escapeHTML(`${t.title} ${t.description||''} ${t.priority}`.toLowerCase())}">${editable?`<button class="task-check" onclick="App.toggleTask('${t.id}',${!t.completed})">${t.completed?'✓':''}</button>`:`<span class="task-check">${t.completed?'✓':''}</span>`}<div><b>${escapeHTML(t.title)}</b><span>${t.due_date?fmtDate(t.due_date):'Sem prazo'} • ${t.priority}${t.completed_at?` • Arquivada ${fmtDateTime(t.completed_at)} • ${taskCompletionTime(t)}${t.completed_by?` • por ${escapeHTML(t.completed_by)}`:''}`:''}</span></div>${editable?`<div class="task-actions"><button class="btn ghost small" onclick="App.editTask('${t.id}')">Editar</button><button class="btn danger small" onclick="App.deleteTask('${t.id}')">Excluir</button></div>`:''}</div>`).join('')||'<p class="muted">Nenhuma tarefa nesta visão.</p>'}</div>${State.taskFilter==='completed'||State.taskFilter==='archived'?`<div class="archive-panel"><div class="panel-head"><div><h4>Histórico arquivado</h4><small>Tarefas concluídas permanecem apenas aqui.</small></div></div><div class="task-list">${taskRows('completed').map(t=>`<div class="task-item done" data-task-search="${escapeHTML(`${t.title} ${t.description||''} ${t.priority}`.toLowerCase())}"><span class="task-check">✓</span><div><b>${escapeHTML(t.title)}</b><span>Concluída em ${fmtDateTime(t.completed_at||t.updated_at||t.created_at)} • ${taskCompletionTime(t)}${t.completed_by?` • por ${escapeHTML(t.completed_by)}`:''}</span></div><button class="btn ghost small" onclick="App.editTask('${t.id}')">Abrir</button></div>`).join('')||'<p class="muted">Nenhuma tarefa arquivada.</p>'}</div></div>`:''}</section>`}
function setTaskFilter(filter){State.taskFilter=filter;renderPage()}
function filterTasks(value){const q=value.trim().toLowerCase();$$('[data-task-search]').forEach(item=>item.classList.toggle('hidden',!item.dataset.taskSearch.includes(q)))}
function renderPulse(){
  const mayView=can('pulse.view'),mayAnswer=can('pulse.answer'),maySeeConsolidated=can('pulse.consolidated');
  if(!mayView&&!mayAnswer&&!maySeeConsolidated)return '';
  const today=(State.db.pulse||[]).find(p=>p.user_id===State.user.id&&p.entry_date===todayISO());
  const summary=maySeeConsolidated?`<div class="pulse-summary">${['excelente','bem','normal','dificil','muito_dificil'].map(f=>`<span><b>${(State.db.pulse||[]).filter(p=>p.entry_date===todayISO()&&p.feeling===f).length}</b>${f.replace('_',' ')}</span>`).join('')}</div>`:'';
  const answer=today?'<p class="muted">Obrigado por compartilhar. Sua resposta foi registrada.</p>':mayAnswer?`<div class="pulse-options">${[['excelente','Excelente'],['bem','Bem'],['normal','Normal'],['dificil','Difícil'],['muito_dificil','Muito difícil']].map(x=>`<button onclick="App.answerPulse('${x[0]}')">${x[1]}</button>`).join('')}</div>`:'<p class="muted">Visualização do Pulse disponível em modo de consulta.</p>';
  return `<section class="panel home-section"><div class="home-section-head"><div><span class="eyebrow">Pulse</span><h3>Como você está hoje?</h3></div>${today?'<span class="status approved">Respondido</span>':''}</div>${answer}${summary}</section>`
}
function renderAchievements(){return `<section class="panel home-section"><div class="home-section-head"><div><span class="eyebrow">Conquistas</span><h3>Marcos desbloqueados</h3></div></div><div class="achievement-list">${(State.db.achievements||[]).filter(a=>a.user_id===State.user.id).map(a=>`<span>✦ ${escapeHTML(a.title)}</span>`).join('')||'<p class="muted">Suas conquistas aparecerão aqui.</p>'}</div></section>`}
function commitmentRows(){const items=[];State.db.meetings.filter(meetingVisible).forEach(m=>{const status=m.status==='done'?'done':daysUntil(m.date)<0?'overdue':daysUntil(m.date)<=7?'week':daysUntil(m.date)<=30?'month':'future';items.push({kind:'meeting',date:m.date,title:m.title||`Café com Raphael — ${m.participant}`,meta:`${m.time} • ${SECTOR_LABELS[m.sector]} • ${m.participant}`,status,priority:status==='overdue'?'alta':status==='week'?'media':'baixa',source:'Agenda'});});State.db.actions.filter(actionVisible).forEach(a=>{const status=['done','cancelled'].includes(a.status)?'done':daysUntil(a.deadline)<0?'overdue':daysUntil(a.deadline)===0?'today':daysUntil(a.deadline)<=7?'week':daysUntil(a.deadline)<=30?'month':'future';items.push({kind:'action',date:a.deadline,title:a.title,meta:`${SECTOR_LABELS[a.sector]} • ${a.owner}`,status,priority:a.priority||'media',source:'Plano de ação'});});State.db.reports.filter(r=>sectorAllowed(r.sector)&&['sent','review','adjust'].includes(r.status)).forEach(r=>items.push({kind:'report',date:r.presentation||r.end,title:`${STATUS_LABELS[r.status]}: ${r.period}`,meta:`${SECTOR_LABELS[r.sector]} • ${r.owner}`,status:'today',priority:'alta',source:'Relatório'}));return items.sort((a,b)=>String(a.date||'').localeCompare(String(b.date||'')))}
function upcomingCommitments(){return commitmentRows().filter(item=>['future','today','week'].includes(item.status)).slice(0,6)}
function renderHome(){const assist=assistInsight(),priorities=homePriorities(),commitments=upcomingCommitments(),dna=DNA_PHRASES[Math.floor(new Date().setHours(0,0,0,0)/86400000)%DNA_PHRASES.length],recentAudit=State.db.audit.slice().sort((a,b)=>String(b.at||'').localeCompare(String(a.at||''))).slice(0,7),feed=State.user.role==='direction'?`<section class="panel home-section"><div class="home-section-head"><div><span class="eyebrow">Feed da Direção</span><h3>Movimentações recentes</h3></div></div><div class="feed-list">${recentAudit.map(e=>`<div><time>${fmtDateTime(e.at)}</time><p><b>${escapeHTML(e.action)}</b><br>${escapeHTML(e.detail||'')}</p></div>`).join('')}</div></section>`:renderAchievements(),copilot=purpleIaExecutiveSummary(),copilotItems=purpleIaRecommendations().slice(0,3),quickAccess=[['Purple IA','✦',"App.go('purple-ia')"],['Financeiro','R$',"App.openNavItem('financial','','financeiro')"],['Relatórios','▦',"App.go('reports')"],['Diário Operacional','◨',"App.go('operational-diary')"],['Indicadores','◫',"App.go('dashboard')"],['Meu Dia','◷',"App.go('home');App.setTaskFilter('active')"],['Alunos','◉',"App.go('students')"],['Turmas','▤',"App.go('classes')"],['Professores','♜',"App.go('teachers')"],['Planos de ação','✓',"App.go('actions')"],['Reuniões','◷',"App.go('meetings')"],['Notificações','♢',"App.go('notifications')"],['Mural','◆',"App.go('mural')"]];return `<div class="page home-page"><div class="home-welcome"><div><span class="eyebrow">${escapeHTML(currentDateLong())}</span><h1>${escapeHTML(greeting())}</h1><p>Veja o que merece sua atenção e organize o seu dia.</p></div><div class="dna"><span>Purple DNA</span>${escapeHTML(dna)}</div></div><section class="assist-card"><div class="assist-mark">P</div><div><span>Purple Assist</span><h2>${escapeHTML(assist.text)}</h2><p>${escapeHTML(assist.action)}</p></div><button class="btn primary" onclick="App.openHomeItem('${assist.item.kind}','${assist.item.id||''}','${assist.item.sector||''}')">Abrir prioridade</button></section><section class="panel home-section"><div class="home-section-head"><div><span class="eyebrow">Atalhos do painel</span><h3>Funções mais usadas</h3></div></div><div class="grid cols-4 quick-access-grid">${quickAccess.map(([label,icon,action])=>`<button class="quick-access-card" type="button" onclick="${action}"><span>${appIcon(icon)}</span><strong>${label}</strong></button>`).join('')}</div></section><section class="panel home-section purple-ia-home"><div class="home-section-head"><div><span class="eyebrow">Purple IA</span><h3>${escapeHTML(copilot.title)}</h3></div><button class="btn primary small" onclick="App.go('purple-ia')">Abrir consultor</button></div><p class="muted" style="line-height:1.65">${escapeHTML(copilot.text)}</p><div class="priority-list">${copilotItems.map(item=>`<div class="priority-item"><i class="priority-dot ${item.priority}"></i><div><b>${escapeHTML(item.title)}</b><span>${SECTOR_LABELS[item.sector]||'Geral'} • ${escapeHTML(item.actions[0]||'Abrir contexto')}</span></div></div>`).join('')||'<p class="muted">Nenhuma recomendação ativa.</p>'}</div></section><div class="home-columns"><div><section class="panel home-section"><div class="home-section-head"><div><span class="eyebrow">Prioridades de hoje</span><h3>O que precisa de atenção</h3></div><span class="count-badge">${priorities.length}</span></div><div class="priority-list">${priorities.map(p=>`<div class="priority-item"><i class="priority-dot ${p.priority}"></i><div><b>${escapeHTML(p.title)}</b><span>${SECTOR_LABELS[p.sector]||'Geral'} • ${p.date?fmtDate(p.date):'Hoje'} • ${p.status}</span></div><button class="btn ghost small" onclick="App.openHomeItem('${p.kind}','${p.id}','${p.sector||''}')">Abrir</button></div>`).join('')||'<p class="muted">Nenhuma prioridade crítica hoje.</p>'}</div></section>${renderTasks()}</div><div>${renderPulse()}<section class="panel home-section"><div class="home-section-head"><div><span class="eyebrow">Resumo rápido</span><h3>Leitura humana da operação</h3></div></div><ul class="human-summary">${quickSummary().map(x=>`<li>${escapeHTML(x)}</li>`).join('')}</ul></section></div></div><section class="grid cols-4 home-metrics">${homeMetrics()}</section><div class="home-columns"><section class="panel home-section"><div class="home-section-head"><div><span class="eyebrow">Próximos compromissos</span><h3>Agenda e prazos</h3></div></div>${commitments.map(c=>`<div class="commitment"><time>${fmtDate(c.date)}</time><div><b>${escapeHTML(c.title)}</b><span>${escapeHTML(c.meta)}</span></div></div>`).join('')||'<p class="muted">Sem compromissos futuros.</p>'}</section>${feed}</div></div>`}

function renderOperationalDiaryPanel(sector){const snapshot=todayOperationalDiarySnapshot(sector);if(!snapshot)return `<div class="panel"><div class="panel-head"><div><h3>${SECTOR_LABELS[sector]}</h3><small>Diário operacional de hoje</small></div><button class="btn ghost small" onclick="App.openOperationalDiaryPage('${sector}')">Abrir diário</button></div><div class="empty"><p>Nenhum diário lançado para ${fmtDate(todayISO())}.</p></div></div>`;return `<div class="panel"><div class="panel-head"><div><h3>${SECTOR_LABELS[sector]}</h3><small>${snapshot.context.periodLabel||fmtDate(snapshot.periodEnd)}</small></div><button class="btn ghost small" onclick="App.openOperationalDiaryPage('${sector}')">Abrir diário</button></div><div class="kpi-strip">${operationalDiarySummary(snapshot)}</div><p class="muted" style="margin-top:10px;line-height:1.6">${escapeHTML(snapshot.context.summary||'Sem observação registrada.')}</p></div>`}
function renderIntegratedDashboard(){const ret=latestIntelligenceSnapshot('retencao','semanal'),ped=latestIntelligenceSnapshot('pedagogico','semanal'),fin=latestIntelligenceSnapshot('financeiro','semanal'),students=officialStudentCounts();const pending=State.db.reports.filter(r=>['sent','review','adjust'].includes(r.status)).length;const remRate=intelligenceMetric(ret,'rematriculacaoTaxa','derivedMetrics');const cards=[
  metricCard('Alunos ativos',fmtNumber(students.active),'👥',0,'Base oficial de alunos'),
  metricCard('Alunos em risco',fmtNumber(intelligenceMetric(ret,'alunosRisco')),'⚠',0,'Acompanhamento integrado'),
  metricCard('Receita realizada',fmtMoney(intelligenceMetric(fin,'receitaRealizada')),'R$',0,'Última quinzena consolidada'),
  metricCard('Inadimplência',fmtMoney(intelligenceMetric(fin,'inadimplencia')),'↗',0,'Último fechamento consolidado'),
  metricCard('Turmas críticas',fmtNumber(intelligenceMetric(ped,'turmasCriticas')),'▣',0,'Última quinzena consolidada'),
  metricCard('Rematrícula',`${fmtNumber(remRate,1)}%`,'↻',0,'Taxa consolidada'),
  metricCard('Relatórios pendentes',fmtNumber(pending),'◫',0,'Exigem decisão da direção'),
  metricCard('Ações abertas',fmtNumber(State.db.actions.filter(a=>!['done','cancelled'].includes(a.status)).length),'✓',0,'Planos ainda em andamento')
].join('');
  const sectorPanels=['retencao','pedagogico','financeiro'].map(s=>{const snapshot=latestIntelligenceSnapshot(s,'semanal');const schemaFrequency=snapshot?.frequency&&SCHEMAS[s]?.[snapshot.frequency]?snapshot.frequency:'quinzenal';const first=SCHEMAS[s][schemaFrequency].metrics.slice(0,3);return `<div class="panel"><div class="panel-head"><div><h3>${SECTOR_LABELS[s]}</h3><small>${snapshot?.context?.periodLabel||'Sem consolidado'}</small></div><button class="btn ghost small" onclick="App.openReport('${snapshot?.sourceId||''}')">Abrir</button></div><div class="kpi-strip">${first.map(([k,l,t])=>`<span><b>${l}:</b> ${fmtMetric(intelligenceMetric(snapshot,k),t)}</span>`).join('')}</div><div class="alerts" style="margin-top:13px">${buildSectorAlerts(s,snapshot)}</div></div>`}).join('');
  const dailyPanels=operationalDiaryVisibleSectors().map(renderOperationalDiaryPanel).join('');
  const recent=State.db.reports.filter(r=>['sent','review','adjust'].includes(r.status)).sort((a,b)=>b.createdAt.localeCompare(a.createdAt)).slice(0,5).map(r=>`<div class="timeline-item"><b>${STATUS_LABELS[r.status]} — ${SECTOR_LABELS[r.sector]}</b><p>${r.period} • ${r.owner}</p><time>${fmtDateTime(r.createdAt)}</time></div>`).join('')||'<div class="empty"><p>Nenhuma pendência.</p></div>';
  return `<div class="page"><section class="hero"><div class="hero-content"><div><span class="eyebrow light">Dashboard da direção</span><h2>A operação inteira em uma única leitura.</h2><p>Indicadores consolidados dos três departamentos, alertas, relatórios pendentes e ações que exigem decisão.</p></div><div class="hero-badge">Purple Intelligence v1</div></div></section><section class="grid cols-4">${cards}</section><section class="grid cols-3" style="margin-top:16px">${sectorPanels}</section><section class="grid cols-3" style="margin-top:16px">${dailyPanels}</section><section class="dashboard-layout equal"><div class="panel"><div class="panel-head"><div><h3>Relatórios aguardando decisão</h3><small>Fluxo mais recente</small></div></div><div class="timeline">${recent}</div></div><div class="panel"><div class="panel-head"><div><h3>Status de todos os relatórios</h3><small>Distribuição geral</small></div></div>${statusDonut(State.db.reports)}</div></section></div>`
}
function renderSectorDashboard(sector){const arr=intelligenceSnapshotsFor(sector,'semanal'),snapshot=arr.at(-1);if(!snapshot)return `<div class="page"><div class="empty"><div class="emoji">◫</div><h3>Nenhum consolidado</h3><p>Crie o primeiro relatório para iniciar o dashboard.</p></div></div>`;const series=sector==='financeiro'?[{key:'receitaPrevista',label:'Prevista',type:'money'},{key:'receitaRealizada',label:'Realizada',type:'money'}]:sector==='retencao'?[{key:'rematriculasPrevistas',label:'Previstas'},{key:'rematriculasConcluidas',label:'Concluídas'}]:[{key:'aulasRealizadas',label:'Aulas'},{key:'feedbacks',label:'Feedbacks'}],frequencyLabel=intelligenceFrequencyLabel(sector,'semanal').toLowerCase(),dailyPanel=renderOperationalDiaryPanel(sector);return `<div class="page"><section class="hero"><div class="hero-content"><div><span class="eyebrow light">Painel ${SECTOR_LABELS[sector]}</span><h2>Transforme o fechamento em plano de ação.</h2><p>Último consolidado: ${snapshot.context.periodLabel}. Status: ${STATUS_LABELS[snapshot.status]||snapshot.status}.</p></div><div class="hero-badge">${arr.length} snapshots ${frequencyLabel}</div></div></section><section class="grid cols-4">${dashboardMetrics(sector)}</section><section class="dashboard-layout"><div class="panel"><div class="panel-head"><div><h3>Evolução dos últimos fechamentos</h3><small>Indicadores principais do setor</small></div></div>${lineChartSVG(arr.slice(-6),series)}</div><div class="panel"><div class="panel-head"><div><h3>Alertas e prioridades</h3><small>Leitura do último fechamento</small></div></div><div class="alerts">${buildSectorAlerts(sector,snapshot)}</div></div></section><section class="dashboard-layout equal">${dailyPanel}<div class="panel"><div class="panel-head"><div><h3>Resumo executivo</h3><small>${snapshot.context.periodLabel}</small></div><button class="btn ghost small" onclick="App.openReport('${snapshot.sourceId}')">Abrir relatório</button></div><p class="muted" style="line-height:1.65">${escapeHTML(snapshot.context.summary||'Sem resumo informado.')}</p><div class="alert blue" style="margin-top:13px"><div class="alert-icon">◎</div><div><b>Decisão registrada</b><span>${escapeHTML(snapshot.context.decisions||'Nenhuma decisão registrada.')}</span></div></div></div><div class="panel"><div class="panel-head"><div><h3>Status do setor</h3><small>Todos os relatórios</small></div></div>${statusDonut(State.db.reports.filter(x=>x.sector===sector))}</div></section></div>`}

function twrAcademicFallback(){const db=defaultDB();return {teachers:db.teachers||[],classes:db.classes||[],students:db.students||[]}}
function twrTeachers(){const fallback=twrAcademicFallback();return (State.db.teachers||[]).length?State.db.teachers:fallback.teachers}
function twrClasses(){const fallback=twrAcademicFallback();return (State.db.classes||[]).length?State.db.classes:fallback.classes}
function twrStudents(){const fallback=twrAcademicFallback();return (State.db.students||[]).length?State.db.students:fallback.students}
function twrRoutineOptions(){return TWR_2026_ROUTINES}
function twrSelectedRoutine(){if(!State.twrTeacherId)State.twrTeacherId=State.user?.role==='leader'&&State.user.sector==='pedagogico'?'twr-victor':TWR_2026_ROUTINES[0]?.id;return TWR_2026_ROUTINES.find(r=>r.id===State.twrTeacherId)||TWR_2026_ROUTINES[0]}
function twrNormalize(value=''){return String(value).normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase()}
function twrTeacher(){const routine=twrSelectedRoutine(),teachers=twrTeachers();return teachers.find(t=>twrNormalize(t.name).includes(twrNormalize(routine.name)))||{id:routine.id,name:routine.name,score:0,workload:Object.values(routine.summary||{}).filter(Boolean).join(' • ')||'TWR 2026'}}
function twrClassStudents(classId){return twrStudents().filter(s=>s.classId===classId)}
function twrBlockKind(label=''){const text=twrNormalize(label);if(text.includes('planejamento'))return 'planning';if(text.includes('reposicao')||text.includes('reforco'))return 'reposition';if(text.includes('purple class'))return 'purple-class';if(text.includes('almoco')||text.includes('intervalo')||text.includes('saida'))return 'break';if(text.includes('reuniao')||text.includes('treinamento')||text.includes('observacao'))return 'training';return 'class'}
function twrBlockStatus(kind){return kind==='planning'?'planejamento':kind==='reposition'?'reposição':kind==='break'?'intervalo':kind==='training'?'gestão':'pronta'}
function twrLessons(){const routine=twrSelectedRoutine(),teacher=twrTeacher(),days=['Segunda','Terça','Quarta','Quinta','Sexta','Sábado'];return days.flatMap(day=>(routine.days?.[day]||[]).map(([time,label],index)=>{const kind=twrBlockKind(label);return {id:`${routine.id}-${day}-${index}`,classId:`${routine.id}-${twrNormalize(label).replace(/[^a-z0-9]+/g,'-')}`,day,time,duration:kind==='break'?40:kind==='planning'?60:70,className:label,teacher:teacher.name,room:kind==='class'?'Sala conforme grade':'—',book:kind==='class'?label:'—',students:kind==='class'?0:0,frequency:kind==='class'?88:100,repositions:kind==='reposition'?1:0,status:twrBlockStatus(kind),kind,planning:kind==='planning'?'pending':'ok',notes:'Extraído do TWR 2026 enviado pela Purple.',indicators:kind==='class'?'Preparação, chamada, parecer e fechamento pós-aula.':''}})).sort((a,b)=>days.indexOf(a.day)-days.indexOf(b.day)||a.time.localeCompare(b.time))}
function twrNextLesson(){return twrLessons()[0]||null}
function twrPendingItems(){const lessons=twrLessons(),reports=(State.db.reports||[]).filter(r=>r.sector==='pedagogico'&&['draft','adjust','sent'].includes(r.status));return [...lessons.filter(l=>l.planning==='pending').map(l=>({level:'yellow',title:`Planejar ${l.className}`,text:`Aula de ${l.day} às ${l.time} ainda precisa de planejamento.`})),...lessons.filter(l=>l.repositions>0).map(l=>({level:l.repositions>2?'red':'yellow',title:`Reposições em ${l.className}`,text:`${fmtNumber(l.repositions)} reposição(ões) exigem acompanhamento.`})),...reports.map(r=>({level:r.status==='adjust'?'red':'yellow',title:'Relatório pedagógico pendente',text:`${r.period} • ${STATUS_LABELS[r.status]||r.status}`}))].slice(0,8)}
function twrTimeline(){const lessons=twrLessons().slice(0,6);return lessons.flatMap(l=>[{at:l.time,title:l.className,detail:`Aula programada • ${l.room}`},{at:addMinutesToTime(l.time,90),title:'Registro pós-aula',detail:'Frequência, parecer e conteúdo ministrado'}]).slice(0,8)}
function addMinutesToTime(value,minutes){const [h,m]=String(value).split(':').map(Number),date=new Date();date.setHours(h||0,(m||0)+minutes,0,0);return `${String(date.getHours()).padStart(2,'0')}:${String(date.getMinutes()).padStart(2,'0')}`}
function setTwrTeacher(id){State.twrTeacherId=id;renderPage()}
function twrStudentMatches(lesson){if(lesson.kind!=='class')return [];const key=twrNormalize(lesson.className);return twrStudents().filter(student=>{const klass=twrClasses().find(c=>c.id===student.classId);return twrNormalize(klass?.name||'').includes(key)||key.includes(twrNormalize(klass?.name||''))})}
function twrSourceText(lesson){return lesson?.notes||'Dados extraídos do PDF TWR 2026 enviado pela Purple.'}
function twrInfoPopup(kind,id=''){const routine=twrSelectedRoutine(),lessons=twrLessons(),lesson=lessons.find(l=>l.id===id),summary=routine.summary||{};let title='Origem dos dados',body='';if(kind==='source')body=`<p class="muted">Esta tela usa como base o arquivo <b>TWR 2026.pdf</b>. Os blocos de horário, professores, dias e resumo de carga foram extraídos do PDF e organizados no Purple Gestão.</p><div class="kpi-strip"><span><b>Professor:</b> ${escapeHTML(routine.name)}</span><span><b>Blocos:</b> ${fmtNumber(lessons.length)}</span><span><b>Dias:</b> ${fmtNumber(Object.keys(routine.days||{}).length)}</span></div>`;else if(kind==='students'&&lesson){const students=twrStudentMatches(lesson);title=`Alunos — ${lesson.className}`;body=`<p class="muted">${students.length?'Alunos encontrados nos cadastros vinculados à turma.':'O PDF TWR informa a rotina/horário, mas não traz lista nominal de alunos. Quando os alunos estiverem vinculados à turma no cadastro, eles aparecerão aqui automaticamente.'}</p><div class="priority-list">${students.map(s=>`<div class="priority-item"><i class="priority-dot ${Number(s.frequency||0)<80?'alta':'baixa'}"></i><div><b>${escapeHTML(s.name)}</b><span>Frequência ${fmtNumber(s.frequency||0,1)}% • ${escapeHTML(s.situation||'Ativo')}</span></div></div>`).join('')||'<div class="empty"><p>Nenhum aluno nominal vinculado a este bloco.</p></div>'}</div>`}else if(kind==='summary')body=`<p class="muted">Resumo exibido no rodapé do professor no PDF.</p><div class="kpi-strip"><button class="twr-info-pill" onclick="App.twrInfoPopup('summary')"><b>Turma:</b> ${escapeHTML(summary.classes||'—')}</button><button class="twr-info-pill" onclick="App.twrInfoPopup('summary')"><b>Planejamento:</b> ${escapeHTML(summary.planning||'—')}</button><button class="twr-info-pill" onclick="App.twrInfoPopup('summary')"><b>Reposição:</b> ${escapeHTML(summary.repositions||'—')}</button><button class="twr-info-pill" onclick="App.twrInfoPopup('summary')"><b>Purple Class:</b> ${escapeHTML(summary.purpleClass||'—')}</button></div>`;else if(kind==='hours')body=`<p class="muted">As horas estimadas são calculadas pelos blocos da rotina semanal importada do PDF. Blocos de aula usam duração operacional aproximada; quando o PDF possui resumo oficial, ele é mostrado no painel de carga.</p><div class="kpi-strip"><span><b>Blocos:</b> ${fmtNumber(lessons.length)}</span><span><b>Planejamento:</b> ${fmtNumber(lessons.filter(l=>l.kind==='planning').length)}</span><span><b>Aulas:</b> ${fmtNumber(lessons.filter(l=>l.kind==='class').length)}</span><span><b>Reposições:</b> ${fmtNumber(lessons.filter(l=>l.kind==='reposition').length)}</span></div>`;else if(kind==='planning'&&lesson){title=`Planejamento — ${lesson.className}`;body=`<p class="muted">Use este bloco para preparar objetivos, warm-up, vocabulary, grammar, speaking, writing, homework e materiais.</p><div class="checklist"><label><input type="checkbox"/> Objetivos</label><label><input type="checkbox"/> Warm-up</label><label><input type="checkbox"/> Materiais</label><label><input type="checkbox"/> Homework</label></div>`}else if(kind==='action'&&lesson){title=`Ação TWR — ${lesson.className}`;body=`<p class="muted">Ação aberta para este bloco do TWR.</p><div class="kpi-strip"><span><b>Professor:</b> ${escapeHTML(lesson.teacher)}</span><span><b>Quando:</b> ${lesson.day} às ${lesson.time}</span><span><b>Tipo:</b> ${escapeHTML(lesson.status)}</span></div><p class="muted">Origem: ${escapeHTML(twrSourceText(lesson))}</p>`}else body='<p class="muted">Informação conectada ao TWR 2026 e aos cadastros acadêmicos disponíveis no sistema.</p>';modal(`<div class="modal-head"><div><span class="eyebrow">TWR • Detalhes</span><h3>${escapeHTML(title)}</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div>${body}`,true)}
function twrOpenLesson(id){const lesson=twrLessons().find(l=>l.id===id);if(!lesson)return toast('Aula não encontrada.');const students=twrStudentMatches(lesson),studentCount=students.length||lesson.students;modal(`<div class="modal-head"><div><span class="eyebrow">TWR • Bloco operacional</span><h3>${escapeHTML(lesson.className)}</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="kpi-strip"><button class="twr-info-pill" onclick="App.twrInfoPopup('source','${lesson.id}')"><b>Origem:</b> TWR 2026 PDF</button><button class="twr-info-pill" onclick="App.twrInfoPopup('action','${lesson.id}')"><b>Horário:</b> ${lesson.day} às ${lesson.time}</button><button class="twr-info-pill" onclick="App.twrInfoPopup('action','${lesson.id}')"><b>Tipo:</b> ${escapeHTML(lesson.status)}</button><button class="twr-info-pill" onclick="App.twrInfoPopup('students','${lesson.id}')"><b>Alunos:</b> ${fmtNumber(studentCount)}</button></div><section class="form-card"><h3>Preparação Inteligente da Aula</h3><p class="muted">${lesson.kind==='planning'?'Este é um bloco de planejamento. Use para preparar objetivos, etapas, materiais e homework.':lesson.kind==='reposition'?'Este bloco foi identificado como reposição/reforço no PDF. A lista nominal depende do vínculo dos alunos no cadastro.':lesson.kind==='class'?'Este bloco é uma turma/aula no TWR 2026. O PDF informa o horário e a turma; alunos aparecem quando estiverem vinculados no cadastro.':'Este bloco foi importado da rotina oficial e classificado automaticamente.'}</p><div class="checklist"><label><input type="checkbox" ${lesson.planning==='ok'?'checked':''}/> Planejar aula</label><label><input type="checkbox"/> Separar material</label><label><input type="checkbox"/> Abrir áudio/slides</label><label><input type="checkbox"/> Revisar alunos em atenção</label></div></section><section class="form-card"><h3>Ações rápidas</h3><div class="section-actions" style="justify-content:flex-start"><button class="btn primary" onclick="App.twrInfoPopup('action','${lesson.id}')">Iniciar aula</button><button class="btn soft" onclick="App.twrInfoPopup('students','${lesson.id}')">Chamar lista</button><button class="btn soft" onclick="App.twrInfoPopup('students','${lesson.id}')">Registrar frequência</button><button class="btn ghost" onclick="App.twrInfoPopup('source','${lesson.id}')">Abrir material</button><button class="btn ghost" onclick="App.twrInfoPopup('planning','${lesson.id}')">Planejamento</button></div></section><section class="form-card"><h3>Alunos e origem dos dados</h3><p class="muted">${students.length?'Lista puxada do cadastro de alunos vinculado à turma.':'O PDF TWR não contém nomes de alunos. Este bloco mostra a turma/atividade; a lista nominal aparecerá quando o cadastro acadêmico estiver vinculado.'}</p><div class="priority-list">${students.map(s=>`<div class="priority-item"><i class="priority-dot ${Number(s.frequency||0)<80?'alta':'baixa'}"></i><div><b>${escapeHTML(s.name)}</b><span>Frequência ${fmtNumber(s.frequency||0,1)}% • ${escapeHTML(s.situation||'Ativo')}</span></div></div>`).join('')||'<div class="empty"><p>Nenhum aluno nominal vinculado a este bloco.</p></div>'}</div></section><section class="form-card"><h3>Depois da aula</h3><div class="form-grid cols-2"><div class="field"><label>Conteúdo ministrado</label><input placeholder="Unidade, página e objetivo"/></div><div class="field"><label>Página final</label><input placeholder="Ex.: p. 42"/></div><div class="field"><label>Participação</label><input placeholder="Alta, média ou baixa"/></div><div class="field"><label>Homework</label><input placeholder="Tarefa para casa"/></div></div><div class="field"><label>Observações e alunos com dificuldade</label><textarea placeholder="Registre parecer rápido da aula"></textarea></div></section>`,true)}
function renderTWR(){if(!can('panel.view'))return `<div class="page"><div class="empty"><div class="emoji">🔒</div><h3>Acesso restrito</h3></div></div>`;const routine=twrSelectedRoutine(),teacher=twrTeacher(),lessons=twrLessons(),next=twrNextLesson(),pending=twrPendingItems(),timeline=twrTimeline(),hours=lessons.reduce((sum,l)=>sum+l.duration/60,0),summary=routine.summary||{},selector=`<select class="select compact" onchange="App.setTwrTeacher(this.value)">${twrRoutineOptions().map(r=>`<option value="${r.id}" ${r.id===routine.id?'selected':''}>${escapeHTML(r.name)}</option>`).join('')}</select>`;return `<div class="page twr-page"><section class="hero twr-hero"><div class="hero-content"><div><span class="eyebrow light">TWR 2026 — Centro de Operação do Professor</span><h2>O dia do professor em uma única tela.</h2><p>Rotina semanal oficial do PDF, transformada em agenda operacional com planejamento, reposição, Purple Class, IA e fechamento pós-aula.</p></div><div class="hero-badge">${escapeHTML(teacher.name)}</div></div></section><div class="section-title compact"><div><h2>Teacher's Weekly Routine</h2><p>Selecione o professor para visualizar a rotina real de 2026.</p></div><div class="section-actions"><button class="btn ghost small" onclick="App.twrInfoPopup('source')">Origem dos dados</button>${selector}</div></div><section class="twr-mobile-next panel">${next?`<span class="eyebrow">Próximo bloco</span><h3>${escapeHTML(next.className)}</h3><p>${next.day} • ${next.time} • ${escapeHTML(next.status)}</p><button class="btn primary full" onclick="App.twrOpenLesson('${next.id}')">${next.kind==='class'?'Iniciar aula':'Abrir bloco'}</button>`:'<h3>Nenhum bloco programado</h3>'}</section><section class="grid cols-4"><button class="twr-metric-action" onclick="App.twrInfoPopup('source')">${metricCard('Blocos na semana',fmtNumber(lessons.length),'◬',0,'TWR 2026')}</button><button class="twr-metric-action" onclick="App.twrInfoPopup('hours')">${metricCard('Horas estimadas',`${fmtNumber(hours,1)}h`,'◷',0,'Pela grade extraída')}</button><button class="twr-metric-action" onclick="App.twrInfoPopup('summary')">${metricCard('Reposição | Reforço',summary.repositions||fmtNumber(lessons.filter(l=>l.kind==='reposition').length),'↻',0,'Resumo oficial')}</button><button class="twr-metric-action" onclick="App.twrInfoPopup('summary')">${metricCard('Planejamento',summary.planning||fmtNumber(lessons.filter(l=>l.kind==='planning').length),'▧',0,'Resumo oficial')}</button></section><section class="dashboard-layout"><div class="panel"><div class="panel-head"><div><h3>Agenda semanal inteligente</h3><small>Baseada no arquivo TWR 2026 enviado</small></div></div><div class="twr-calendar">${['Segunda','Terça','Quarta','Quinta','Sexta','Sábado'].map(day=>`<div class="twr-day"><strong>${day}</strong>${lessons.filter(l=>l.day===day).map(l=>`<button class="twr-lesson ${l.kind}" onclick="App.twrOpenLesson('${l.id}')"><span>${l.time}</span><b>${escapeHTML(l.className)}</b><small>${escapeHTML(l.status)} • ${escapeHTML(l.book)}</small></button>`).join('')||'<p class="muted">Sem bloco no TWR.</p>'}</div>`).join('')}</div></div><div class="panel"><div class="panel-head"><div><h3>Purple IA do professor</h3><small>Preparação antes do próximo bloco</small></div></div><div class="alerts">${next?`<div class="alert ${next.kind==='reposition'?'yellow':'blue'}"><div class="alert-icon">${appIcon('✦')}</div><div><b>${escapeHTML(next.className)}</b><span>${next.kind==='planning'?'Use este bloco para preparar objetivos, warm-up, materiais e homework.':next.kind==='reposition'?'Reposição exige contexto do aluno, conteúdo original e prioridade antes da aula.':'Contexto pronto: revise objetivo, página anterior e estratégia de participação antes de entrar em sala.'}</span></div></div>`:''}${pending.slice(0,4).map(p=>`<div class="alert ${p.level==='red'?'red':'yellow'}"><div class="alert-icon">${appIcon(p.level==='red'?'!':'◷')}</div><div><b>${escapeHTML(p.title)}</b><span>${escapeHTML(p.text)}</span></div></div>`).join('')||'<div class="alert green"><div class="alert-icon">'+appIcon('✓')+'</div><div><b>Semana organizada</b><span>Nenhuma pendência crítica encontrada.</span></div></div>'}</div></div></section><section class="dashboard-layout equal"><div class="panel"><div class="panel-head"><div><h3>Resumo de carga do PDF</h3><small>Planejamento, turmas, reposições e Purple Class</small></div></div><div class="kpi-strip"><button class="twr-info-pill" onclick="App.twrInfoPopup('summary')"><b>Turma:</b> ${escapeHTML(summary.classes||'—')}</button><button class="twr-info-pill" onclick="App.twrInfoPopup('summary')"><b>Planejamento:</b> ${escapeHTML(summary.planning||'—')}</button><button class="twr-info-pill" onclick="App.twrInfoPopup('summary')"><b>Reposição:</b> ${escapeHTML(summary.repositions||'—')}</button><button class="twr-info-pill" onclick="App.twrInfoPopup('summary')"><b>Purple Class:</b> ${escapeHTML(summary.purpleClass||'—')}</button></div></div><div class="panel"><div class="panel-head"><div><h3>Timeline do dia</h3><small>Eventos e registros operacionais</small></div></div><div class="timeline">${timeline.map(t=>`<div class="timeline-item"><b>${escapeHTML(t.at)} • ${escapeHTML(t.title)}</b><p>${escapeHTML(t.detail)}</p></div>`).join('')||'<p class="muted">Sem eventos para hoje.</p>'}</div></div></section></div>`}
function renderDashboard(){return State.sector==='integrado'?renderIntegratedDashboard():renderSectorDashboard(State.sector)}
function financialSnapshot(){return latestIntelligenceSnapshot('financeiro','semanal')||latestIntelligenceSnapshot('financeiro','quinzenal')||latestIntelligenceSnapshot('financeiro','mensal')||{}}
function financialMetricValue(key,bucket='metrics'){return intelligenceMetric(financialSnapshot(),key,bucket)}
function financialCenterData(){const snap=financialSnapshot(),diary=todayOperationalDiarySnapshot('financeiro'),reports=State.db.reports.filter(r=>r.sector==='financeiro'),actions=State.db.actions.filter(a=>a.sector==='financeiro'&&!['done','cancelled'].includes(a.status)),receitaPrevista=financialMetricValue('receitaPrevista'),receitaRealizada=financialMetricValue('receitaRealizada'),inadimplencia=financialMetricValue('inadimplencia'),despesasNaoPrevistas=financialMetricValue('despesasNaoPrevistas'),saldoAtual=financialMetricValue('saldoAtual')||intelligenceMetric(diary,'saldoFinal'),receberHoje=Math.max(0,receitaPrevista-receitaRealizada)+inadimplencia,pagarHoje=despesasNaoPrevistas+financialMetricValue('necessidadeCaixa'),receitaMes=financialMetricValue('receitaRecebida')||receitaRealizada,despesasMes=financialMetricValue('despesasPagas')||financialMetricValue('totalDespesas')||despesasNaoPrevistas,lucro=financialMetricValue('resultadoLiquido')||(receitaMes-despesasMes);return {snap,diary,reports,actions,receitaPrevista,receitaRealizada,inadimplencia,despesasNaoPrevistas,saldoAtual,receberHoje,pagarHoje,receitaMes,despesasMes,lucro,bankBalance:saldoAtual?saldoAtual:0,consolidatedBalance:saldoAtual,forecast30:saldoAtual+receberHoje-pagarHoje,goal:receitaPrevista||State.db.settings?.financialGoal||0}}
function financialCard(title,text,icon,action,meta=''){return `<button class="financial-module-card" type="button" onclick="${action}"><span class="financial-module-icon">${appIcon(icon)}</span><strong>${escapeHTML(title)}</strong><small>${escapeHTML(text)}</small>${meta?`<em>${escapeHTML(meta)}</em>`:''}</button>`}
function renderFinancialHubLegacy(){if(!can('financial.receipts.view')&&!can('indicators.view'))return `<div class="page"><div class="empty"><div class="emoji">🔒</div><h3>Acesso restrito</h3></div></div>`;const d=financialCenterData(),alerts=[];if(d.inadimplencia>0)alerts.push(['red','Inadimplência ativa',`Priorize cobrança dos maiores atrasos. Valor consolidado: ${fmtMoney(d.inadimplencia)}.`]);if(d.forecast30<0)alerts.push(['red','Risco de caixa',`A projeção simples para 30 dias está negativa em ${fmtMoney(Math.abs(d.forecast30))}.`]);if(d.receitaPrevista&&d.receitaRealizada<d.receitaPrevista)alerts.push(['yellow','Receita abaixo do previsto',`Faltam ${fmtMoney(d.receitaPrevista-d.receitaRealizada)} para alcançar a previsão do fechamento.`]);if(!alerts.length)alerts.push(['green','Financeiro estável','Os dados atuais não indicam risco crítico imediato.']);const modules=[
  ['Contas a receber','Mensalidades, material, matrícula, acordos e recebimentos por responsável.','↙',"App.openNavItem('reports','','financeiro')",`${fmtMoney(d.receberHoje)} em atenção`],
  ['Contas a pagar','Aluguel, folha, fornecedores, impostos, softwares e despesas por centro de custo.','↗',"App.openNavItem('operational-diary','','financeiro')",`${fmtMoney(d.pagarHoje)} projetado`],
  ['Fluxo de caixa','Entradas, saídas, saldo inicial, saldo final e projeção dos próximos períodos.','⌁',"App.openNavItem('dashboard','','financeiro')",`30 dias: ${fmtMoney(d.forecast30)}`],
  ['Caixa diário','Abertura, recebimentos, sangrias, suprimentos, fechamento e diferença.','▣',"App.openNavItem('operational-diary','','financeiro')",d.diary?'Diário de hoje lançado':'Diário pendente'],
  ['Conciliação','Pendências, duplicidades, divergências e movimentações não conciliadas.','⇄',"App.openNavItem('reports','','financeiro')",'Usa relatórios e diário'],
  ['Cartões e taxas','Operadora, bandeira, parcelamento, taxa, líquido e previsão de recebimento.','▤',"App.openNavItem('reports','','financeiro')",'Controle por recebimento'],
  ['Contas bancárias','Caixa, bancos, saldos, transferências e histórico de movimentações.','◫',"App.openNavItem('operational-diary','','financeiro')",'Saldo consolidado'],
  ['DRE gerencial','Receitas, custos, despesas, resultado operacional e comparativos.','≡',"App.openNavItem('dashboard','','financeiro')",`${fmtMoney(d.lucro)} resultado`],
  ['Inadimplência','Dias em atraso, alunos, histórico, negociação e próxima cobrança.','!',"App.openNavItem('cases','','financeiro')",`${fmtMoney(d.inadimplencia)}`],
  ['Cobranças','WhatsApp, ligação, e-mail, promessa, nova data e responsável.','☎',"App.openNavItem('actions','','financeiro')",`${fmtNumber(d.actions.length)} ação(ões)`],
  ['Relatórios financeiros','Fluxo, receitas, despesas, lucro, mensalidades, materiais e recebimentos por período.','▦',"App.openNavItem('reports','','financeiro')",`${fmtNumber(d.reports.length)} relatórios`],
  ['IA financeira','Diagnóstico, impacto, previsão de caixa e recomendações práticas.','✦',"App.openNavItem('purple-ia','','financeiro')",'Purple IA']
];const recent=d.reports.slice().sort((a,b)=>String(b.createdAt||'').localeCompare(String(a.createdAt||''))).slice(0,5);return `<div class="page financial-page"><section class="hero financial-hero"><div class="hero-content"><div><span class="eyebrow light">ERP Financeiro Purple</span><h2>Controle financeiro completo, simples e orientado por ação.</h2><p>Recebíveis, pagamentos, caixa, fluxo, inadimplência, DRE e IA financeira conectados ao restante da operação.</p></div><div class="hero-badge">Centro financeiro</div></div></section><section class="grid cols-4">${metricCard('Saldo atual em caixa',fmtMoney(d.saldoAtual),'R$',0,'Último saldo informado')}${metricCard('Saldo bancário',fmtMoney(d.bankBalance),'◫',0,'Base consolidada disponível')}${metricCard('Contas a receber',fmtMoney(d.receberHoje),'↙',0,'Previsto + inadimplência')}${metricCard('Contas a pagar',fmtMoney(d.pagarHoje),'↗',0,'Compromissos projetados')}${metricCard('Receita do mês',fmtMoney(d.receitaMes),'▣',0,'Receita consolidada')}${metricCard('Despesas do mês',fmtMoney(d.despesasMes),'▤',0,'Despesas consolidadas',true)}${metricCard('Lucro operacional',fmtMoney(d.lucro),'✓',0,'Receita menos despesas')}${metricCard('Meta financeira',fmtMoney(d.goal),'◎',0,'Referência do fechamento')}</section><section id="receivablesPanel" class="dashboard-layout"><div id="payablesPanel" class="panel"><div class="panel-head"><div><h3>Mapa financeiro da Purple</h3><small>Menus similares integrados em uma única central</small></div></div><div class="financial-module-grid">${modules.map(m=>financialCard(...m)).join('')}</div></div><div class="panel"><div class="panel-head"><div><h3>IA financeira</h3><small>Nunca apenas número: sempre decisão</small></div><button class="btn primary small" onclick="App.openNavItem('purple-ia','','financeiro')">Abrir IA</button></div><div class="alerts">${alerts.map(([tone,title,text])=>`<div class="alert ${tone}"><div class="alert-icon">${tone==='red'?'!':tone==='yellow'?'◷':'✓'}</div><div><b>${escapeHTML(title)}</b><span>${escapeHTML(text)}</span></div></div>`).join('')}</div></div></section><section class="dashboard-layout equal"><div id="cashFlowPanel" class="panel"><div class="panel-head"><div><h3>Fluxo de Caixa projetado</h3><small>Leitura simples usando recebíveis e pagamentos já consolidados</small></div></div><div class="kpi-strip"><span><b>Saldo inicial:</b> ${fmtMoney(d.saldoAtual)}</span><span><b>Entradas previstas:</b> ${fmtMoney(d.receberHoje)}</span><span><b>Saídas previstas:</b> ${fmtMoney(d.pagarHoje)}</span><span><b>Saldo projetado:</b> ${fmtMoney(d.forecast30)}</span></div><div class="alert blue" style="margin-top:13px"><div class="alert-icon">◎</div><div><b>Ação recomendada</b><span>${d.inadimplencia>0?'Criar uma ação de cobrança para os maiores atrasos e revisar acordos ativos.':'Manter rotina de fechamento diário e acompanhar variações de despesa.'}</span></div></div></div><div class="panel"><div class="panel-head"><div><h3>Últimos fechamentos financeiros</h3><small>Histórico usado pelo dashboard e pela IA</small></div><button class="btn ghost small" onclick="App.openNavItem('reports','','financeiro')">Ver todos</button></div><div class="timeline">${recent.map(r=>`<div class="timeline-item"><b>${escapeHTML(r.period)}</b><p>${STATUS_LABELS[r.status]||r.status} • ${escapeHTML(r.owner||'')}</p><time>${fmtDateTime(r.createdAt||r.presentation)}</time></div>`).join('')||'<div class="empty"><p>Nenhum fechamento financeiro encontrado.</p></div>'}</div></div></section></div>`}

function reportFilterOptions(){const sectors=availableSectors(),selected=State.sector!=='integrado'&&sectors.includes(State.sector)?State.sector:'all';return `<select id="reportSectorFilter" class="select" onchange="App.applyReportFilters()">${sectors.length>1?`<option value="all" ${selected==='all'?'selected':''}>Todos os setores</option>`:''}${sectors.map(s=>`<option value="${s}" ${selected===s?'selected':''}>${SECTOR_LABELS[s]}</option>`).join('')}</select><select id="reportFrequencyFilter" class="select" onchange="App.applyReportFilters()"><option value="all">Todas as frequências</option><option value="semanal">Semanal</option><option value="quinzenal">Quinzenal</option><option value="mensal">Mensal</option></select><select id="reportStatusFilter" class="select" onchange="App.applyReportFilters()"><option value="all">Todos os status</option>${Object.entries(STATUS_LABELS).map(([k,v])=>`<option value="${k}">${v}</option>`).join('')}</select><input id="reportSearch" class="search" placeholder="Buscar período ou responsável" oninput="App.applyReportFilters()"/>`}
function renderReports(){return `<div class="page"><div class="section-title"><div><h2>Relatórios</h2><p>Consulte, filtre, aprove, solicite ajustes e exporte o histórico.</p></div><div class="section-actions">${can('reports.export')?'<button class="btn ghost" onclick="App.exportReportsCSV()">Exportar CSV</button>':''}${can('reports.create')?`<button class="btn primary" onclick="App.go('new-report')">Novo relatório</button>`:''}</div></div><div class="filters">${reportFilterOptions()}</div><div id="reportsTable"></div></div>`}
function renderOperationalDiary(){const sectors=operationalDiaryVisibleSectors(),sector=operationalDiarySector(),entry=selectedOperationalDiaryEntry(),schema=OPERATIONAL_DIARY_SCHEMAS[sector],unit=operationalDiaryUnit(),date=State.operationalDiaryDate||todayISO(),editable=State.user.role!=='viewer'&&((entry&&can('reports.edit'))||(!entry&&can('reports.create')));return `<div class="page"><div class="section-title"><div><h2>Diário Operacional</h2><p>Uma entrada por setor, unidade e data, com atualização automática dos indicadores diários.</p></div><div class="section-actions">${entry?`<span class="status approved">Entrada localizada</span>`:`<span class="status draft">Nova entrada</span>`}</div></div><section class="form-card"><h3>Configuração do diário</h3><div class="form-grid cols-4"><div class="field"><label>Setor</label><select id="operationalDiarySector" onchange="App.setOperationalDiaryContext('sector',this.value)" ${State.user.accessScope!=='all_sectors'?'disabled':''}>${sectors.map(s=>`<option value="${s}" ${s===sector?'selected':''}>${SECTOR_LABELS[s]}</option>`).join('')}</select></div><div class="field"><label>Data</label><input id="operationalDiaryDate" type="date" value="${date}" onchange="App.setOperationalDiaryContext('date',this.value)"/></div><div class="field"><label>Unidade</label><input id="operationalDiaryUnit" value="${escapeHTML(unit)}" onchange="App.setOperationalDiaryContext('unit',this.value.trim())" ${State.user.accessScope!=='all_sectors'?'readonly':''}/></div><div class="field"><label>Responsável</label><input value="${escapeHTML(State.user.name)}" disabled/></div></div></section><form id="operationalDiaryForm" onsubmit="event.preventDefault()"><section class="form-card"><h3>Fechamento diário — ${SECTOR_LABELS[sector]}</h3><p class="helper">Os campos abaixo seguem o padrão do setor e alimentam automaticamente o Dashboard e os indicadores diários.</p><div class="form-grid cols-3">${schema.metrics.map(([key,label,type,help])=>`<div class="field"><label>${label}</label><input data-diary-metric="${key}" type="number" ${type==='money'?'step="0.01"':'step="1" min="0"'} value="${entry?.metrics?.[key]??''}" required/><small>${help}</small></div>`).join('')}</div><div class="field" style="margin-top:10px"><label>Observação</label><textarea id="operationalDiaryObservation" class="large" placeholder="Registre o principal contexto do dia.">${escapeHTML(entry?.observation||'')}</textarea></div></section>${entry?`<section class="form-card"><h3>Resumo do registro atual</h3><div class="kpi-strip">${operationalDiarySummary(entry)}</div><p class="muted" style="margin-top:10px">Última atualização: ${fmtDateTime(entry.updatedAt||entry.createdAt)}</p></section>`:''}<div class="sticky-actions no-print"><button type="button" class="btn ghost" onclick="App.go('dashboard')">Voltar</button>${editable?`<button type="button" class="btn primary" onclick="App.saveOperationalDiary()">${entry?'Salvar atualização':'Salvar diário'}</button>`:`<button type="button" class="btn soft" disabled>Somente leitura</button>`}</div></form><section class="form-card"><div class="panel-head"><div><h3>Histórico recente</h3><small>Entradas disponíveis para os setores visíveis</small></div></div><div class="table-wrap"><table><thead><tr><th>Data</th><th>Setor</th><th>Unidade</th><th>Responsável</th><th>Resumo</th><th>Ação</th></tr></thead><tbody>${operationalDiaryEntries().slice(0,10).map(item=>`<tr><td>${fmtDate(item.entryDate)}</td><td>${SECTOR_LABELS[item.sector]}</td><td>${escapeHTML(item.unitName)}</td><td>${escapeHTML(item.responsibleName)}</td><td>${operationalDiarySummary(item)||'—'}</td><td><button class="btn ghost small" onclick="App.openOperationalDiaryEntry('${item.id}')">Abrir</button></td></tr>`).join('')||`<tr><td colspan="6"><div class="empty"><p>Nenhum diário operacional encontrado.</p></div></td></tr>`}</tbody></table></div></section></div>`}
function applyReportFilters(){const target=$('#reportsTable');if(!target)return;let arr=userReports().slice().sort((a,b)=>(b.presentation||b.end).localeCompare(a.presentation||a.end));const sec=$('#reportSectorFilter')?.value||'all',freq=$('#reportFrequencyFilter')?.value||'all',status=$('#reportStatusFilter')?.value||'all',search=($('#reportSearch')?.value||'').toLowerCase();arr=arr.filter(r=>(sec==='all'||r.sector===sec)&&(freq==='all'||r.frequency===freq)&&(status==='all'||r.status===status)&&(!search||`${r.period} ${r.owner} ${SECTOR_LABELS[r.sector]}`.toLowerCase().includes(search)));const pageSize=10,totalPages=Math.max(1,Math.ceil(arr.length/pageSize));State.reportPage=Math.min(State.reportPage,totalPages);const pageArr=arr.slice((State.reportPage-1)*pageSize,State.reportPage*pageSize);const rows=pageArr.map(r=>`<tr><td>${escapeHTML(r.period)}</td><td>${SECTOR_LABELS[r.sector]}</td><td>${FREQUENCY_LABELS[r.frequency]}</td><td>${escapeHTML(r.owner)}</td><td>${statusHTML(r.status)}</td><td>${fmtDate(r.presentation)}</td><td><div class="table-actions"><button class="btn ghost small" onclick="App.openReport('${r.id}')">Abrir</button>${canEditReport(r)?`<button class="btn soft small" onclick="App.editReport('${r.id}')">Editar</button>`:''}${State.user.role==='direction'&&['sent','review'].includes(r.status)?`<button class="btn success small" onclick="App.approveReport('${r.id}')">Aprovar</button>`:''}</div></td></tr>`).join('');target.innerHTML=`<div class="table-wrap"><table><thead><tr><th>Período</th><th>Setor</th><th>Frequência</th><th>Responsável</th><th>Status</th><th>Apresentação</th><th>Ações</th></tr></thead><tbody>${rows||`<tr><td colspan="7"><div class="empty"><p>Nenhum relatório encontrado.</p></div></td></tr>`}</tbody></table></div><div class="pagination"><button class="btn ghost small" ${State.reportPage<=1?'disabled':''} onclick="App.changeReportPage(-1)">Anterior</button><span class="badge">${State.reportPage} de ${totalPages}</span><button class="btn ghost small" ${State.reportPage>=totalPages?'disabled':''} onclick="App.changeReportPage(1)">Próxima</button></div>`}
function changeReportPage(delta){State.reportPage=Math.max(1,State.reportPage+delta);applyReportFilters()}
function canEditReport(r){return can('reports.edit')&&sectorAllowed(r.sector)&&((State.user.role==='direction'&&!['approved','archived'].includes(r.status))||(r.ownerId===State.user.id&&['draft','adjust'].includes(r.status)))}
function exportReportsCSV(){if(!can('reports.export'))return toast('Exportação não autorizada.');const arr=userReports();const rows=[['ID','Setor','Frequência','Período','Responsável','Status','Apresentação','Resumo'],...arr.map(r=>[r.id,SECTOR_LABELS[r.sector],FREQUENCY_LABELS[r.frequency],r.period,r.owner,STATUS_LABELS[r.status],r.presentation,r.summary||''])];const csv=rows.map(row=>row.map(csvCell).join(';')).join('\n');download(`purple-relatorios-${new Date().toISOString().slice(0,10)}.csv`, '\ufeff'+csv,'text/csv;charset=utf-8');toast('Exportação CSV preparada.')}

function reportSectorForForm(){return State.user.role==='leader'?State.user.sector:(State.sector==='integrado'?'retencao':State.sector)}
function renderNewReport(){if(State.user.role==='viewer')return `<div class="page"><div class="empty"><div class="emoji">🔒</div><h3>Acesso somente para consulta</h3><p>Este perfil não pode criar ou alterar relatórios.</p></div></div>`;const editing=State.editingReportId?State.db.reports.find(r=>r.id===State.editingReportId):null;if(editing){State.newFrequency=editing.frequency;State.sector=editing.sector}const sector=editing?.sector||reportSectorForForm();return `<div class="page"><div class="section-title"><div><h2>${editing?'Editar':'Novo'} relatório</h2><p>Formulário adaptado automaticamente ao setor e à periodicidade.</p></div>${editing?statusHTML(editing.status):'<span class="status draft">Novo</span>'}</div><section class="form-card"><h3>Configuração do relatório</h3><p class="helper">Selecione o setor e a periodicidade. Os indicadores e explicações mudam automaticamente.</p><div class="form-grid cols-3"><div class="field"><label>Setor</label><select id="formSector" onchange="App.changeReportForm()" ${State.user.role==='leader'?'disabled':''}>${['retencao','pedagogico','financeiro'].filter(sectorAllowed).map(s=>`<option value="${s}" ${s===sector?'selected':''}>${SECTOR_LABELS[s]}</option>`).join('')}</select></div><div class="field"><label>Periodicidade</label><select id="formFrequency" onchange="App.changeReportForm()"><option value="semanal" ${State.newFrequency==='semanal'?'selected':''}>Semanal</option><option value="quinzenal" ${State.newFrequency==='quinzenal'?'selected':''}>Quinzenal</option><option value="mensal" ${State.newFrequency==='mensal'?'selected':''}>Mensal</option></select></div><div class="field"><label>Status atual</label><input value="${editing?STATUS_LABELS[editing.status]:'Novo relatório'}" disabled/></div></div></section><div id="dynamicReportForm">${renderDynamicReportForm(sector,State.newFrequency,editing)}</div></div>`}
function changeReportForm(){const sector=$('#formSector')?.value||reportSectorForForm(),frequency=$('#formFrequency')?.value||'quinzenal',editing=State.editingReportId?State.db.reports.find(report=>report.id===State.editingReportId):null;State.sector=sector;State.newFrequency=frequency;$('#sectorSwitcher').value=sector;$('#dynamicReportForm').innerHTML=renderDynamicReportForm(sector,frequency,editing);bindReportCalculations()}
function metricField([key,label,type,help],value=''){const inputType=type==='money'||type==='decimal'||type==='percent'?'number':'number';const step=type==='money'||type==='decimal'||type==='percent'?'0.01':'1';const inner=`<input data-metric="${key}" id="metric-${key}" type="${inputType}" step="${step}" min="0" value="${value??''}" placeholder="${type==='money'?'0,00':'0'}"/>`;return `<div class="field"><label>${label}</label>${type==='money'?`<div class="money"><span>R$</span>${inner}</div>`:inner}<small>${help}</small></div>`}
function renderDynamicReportForm(sector,frequency,report){const schema=SCHEMAS[sector][frequency],metrics=schema.metrics.map(m=>metricField(m,report?.metrics?.[m[0]]??'')).join(''),reasons=SCHEMAS[sector].reasons.map(reason=>`<label class="check-chip"><input type="checkbox" name="reportReason" value="${reason}" ${report?.reasons?.includes(reason)?'checked':''}/>${reason}</label>`).join(''),cases=report?.cases?.length?report.cases:[{name:'',situation:'',action:'',next:'',deadline:''}],actions=report?.actionItems?.length?report.actionItems:[{title:'',owner:State.user.name,deadline:'',expected:'',priority:'media'}];return `<form id="reportForm" onsubmit="event.preventDefault()"><section class="form-card"><h3>1. Identificação</h3><p class="helper">O período deve corresponder exatamente aos dados utilizados no relatório.</p><div class="form-grid cols-4"><div class="field"><label>Data inicial</label><input id="reportStart" type="date" value="${report?.start||''}" required/></div><div class="field"><label>Data final</label><input id="reportEnd" type="date" value="${report?.end||''}" required/></div><div class="field"><label>Data da apresentação</label><input id="reportPresentation" type="date" value="${report?.presentation||''}" required/></div><div class="field"><label>Apresentado para</label><input id="reportPresentedTo" value="${escapeHTML(report?.presentedTo||'Direção')}" required/></div></div></section><section class="form-card"><h3>2. Indicadores — ${FREQUENCY_LABELS[frequency]}</h3><p class="helper">Cada campo contém uma definição objetiva para reduzir interpretações diferentes entre os líderes.</p><div class="form-grid cols-4">${metrics}</div><div id="computedMetrics" class="grid cols-3" style="margin-top:4px"></div></section><section class="form-card"><h3>3. Motivos e pontos de atenção</h3><p class="helper">Marque os fatores realmente relevantes. Eles alimentarão o painel de recorrências.</p><div class="check-list">${reasons}</div></section><section class="form-card"><h3>4. Leitura do período</h3><p class="helper">Registre o principal resultado, a causa, o maior risco, o avanço e as decisões necessárias.</p><div class="form-grid cols-2"><div class="field"><label>Resumo executivo</label><textarea id="reportSummary" class="large" required>${escapeHTML(report?.summary||'')}</textarea></div><div class="field"><label>Decisões necessárias / orientação à direção</label><textarea id="reportDecisions" class="large">${escapeHTML(report?.decisions||'')}</textarea></div></div></section><section class="form-card"><div class="panel-head"><div><h3>5. Casos prioritários</h3><small>Alunos, turmas, professores, clientes ou compromissos que exigem acompanhamento.</small></div><button type="button" class="btn soft small" onclick="App.addCaseRow()">Adicionar caso</button></div><div id="reportCases">${cases.map(renderCaseRow).join('')}</div></section><section class="form-card"><div class="panel-head"><div><h3>6. Plano de ação</h3><small>Cada risco relevante deve gerar ação, responsável, prazo e resultado esperado.</small></div><button type="button" class="btn soft small" onclick="App.addActionRow()">Adicionar ação</button></div><div id="reportActions">${actions.map(renderActionRow).join('')}</div></section><section class="form-card"><h3>7. Anexos e evidências</h3><p class="helper">Os arquivos selecionados serão vinculados ao relatório como evidências do período.</p><div class="field"><label>Selecionar arquivos</label><input id="reportAttachments" type="file" multiple/><small id="attachmentNames">${(report?.attachments||[]).map(escapeHTML).join(', ')||'Nenhum arquivo anexado.'}</small></div></section><div class="sticky-actions no-print"><button type="button" class="btn ghost" onclick="App.cancelReportEdit()">Cancelar</button><button type="button" class="btn soft" onclick="App.saveReport('draft')">Salvar rascunho</button><button type="button" class="btn primary" onclick="App.saveReport('sent')">Enviar para análise</button></div></form>`}
function renderCaseRow(c={}){return `<div class="form-grid cols-5 case-row" style="grid-template-columns:1.1fr 1.3fr 1.4fr 1.4fr .8fr;align-items:end;border-bottom:1px solid var(--line);padding:8px 0"><div class="field"><label>Nome / referência</label><input data-case="name" value="${escapeHTML(c.name||'')}"/></div><div class="field"><label>Situação</label><input data-case="situation" value="${escapeHTML(c.situation||'')}"/></div><div class="field"><label>Ação realizada</label><input data-case="action" value="${escapeHTML(c.action||'')}"/></div><div class="field"><label>Próximo passo</label><input data-case="next" value="${escapeHTML(c.next||'')}"/></div><div class="field"><label>Prazo</label><input data-case="deadline" type="date" value="${c.deadline||''}"/></div><button type="button" class="btn danger small" onclick="this.parentElement.remove()">Remover</button></div>`}
function renderActionRow(a={}){return `<div class="form-grid action-row" style="grid-template-columns:1.6fr 1fr .8fr 1.3fr .7fr auto;gap:10px;align-items:end;border-bottom:1px solid var(--line);padding:8px 0"><div class="field"><label>Ação</label><input data-action="title" value="${escapeHTML(a.title||'')}"/></div><div class="field"><label>Responsável</label><input data-action="owner" value="${escapeHTML(a.owner||State.user.name)}"/></div><div class="field"><label>Prazo</label><input data-action="deadline" type="date" value="${a.deadline||''}"/></div><div class="field"><label>Resultado esperado</label><input data-action="expected" value="${escapeHTML(a.expected||'')}"/></div><div class="field"><label>Prioridade</label><select data-action="priority"><option value="alta" ${a.priority==='alta'?'selected':''}>Alta</option><option value="media" ${!a.priority||a.priority==='media'?'selected':''}>Média</option><option value="baixa" ${a.priority==='baixa'?'selected':''}>Baixa</option></select></div><button type="button" class="btn danger small" onclick="this.parentElement.remove()">Remover</button></div>`}
function addCaseRow(){$('#reportCases').insertAdjacentHTML('beforeend',renderCaseRow())}
function addActionRow(){$('#reportActions').insertAdjacentHTML('beforeend',renderActionRow())}
function bindReportCalculations(){const form=$('#reportForm');if(!form)return;$$('[data-metric]',form).forEach(i=>i.addEventListener('input',updateComputedMetrics));$('#reportAttachments')?.addEventListener('change',e=>{$('#attachmentNames').textContent=[...e.target.files].map(f=>f.name).join(', ')||'Nenhum arquivo anexado.'});updateComputedMetrics()}
function updateComputedMetrics(){const sector=$('#formSector')?.value||reportSectorForForm(),freq=$('#formFrequency')?.value||State.newFrequency,get=k=>Number($(`#metric-${k}`)?.value||0);let boxes=[];if(sector==='retencao'){const rate=get('rematriculasConcluidas')/Math.max(1,get('rematriculasPrevistas'))*100;boxes.push(['Taxa de rematrícula',`${rate.toFixed(1)}%`,'Concluídas ÷ previstas']);if(freq==='quinzenal')boxes.push(['Taxa de recuperação',`${(get('alunosRecuperados')/Math.max(1,get('alunosRisco'))*100).toFixed(1)}%`,'Recuperados ÷ alunos em risco'])}if(sector==='financeiro'){if(freq==='semanal')boxes.push(['Saldo calculado',fmtMoney(get('saldoInicial')+get('entradas')-get('saidas')),'Saldo inicial + entradas − saídas']);if(freq==='quinzenal')boxes.push(['Diferença da receita',fmtMoney(get('receitaRealizada')-get('receitaPrevista')),'Realizada − prevista']);if(freq==='mensal')boxes.push(['Margem simples',`${(get('resultadoLiquido')/Math.max(1,get('receitaRecebida'))*100).toFixed(1)}%`,'Resultado líquido ÷ receita recebida'])}if(sector==='pedagogico'){const total=get('aulasRealizadas')+get('aulasCanceladas');boxes.push(['Taxa de execução',`${(get('aulasRealizadas')/Math.max(1,total)*100).toFixed(1)}%`,'Realizadas ÷ aulas previstas'])}$('#computedMetrics').innerHTML=boxes.map(([l,v,n])=>`<div class="computed-box"><small>${l}</small><b>${v}</b><span>${n}</span></div>`).join('')}
function collectRows(selector,attr){return $$(selector).map(row=>{const o={};$$(`[data-${attr}]`,row).forEach(i=>o[i.dataset[attr]]=i.value);return o}).filter(o=>attr==='action'?Boolean(o.title?.trim()):Object.values(o).some(Boolean))}
async function persistReportIntelligence(context='atualização do relatório'){await Storage.save(State.db);try{await refreshIntelligenceSnapshots();console.info(`Purple Intelligence synced after ${context}`)}catch(error){console.error(`Purple Intelligence — leitura após ${context}:`,error)}}
function setOperationalDiaryContext(key,value){
  if(key==='sector'&&operationalDiaryVisibleSectors().includes(value))State.operationalDiarySector=value;
  if(key==='date')State.operationalDiaryDate=value||todayISO();
  if(key==='unit')State.operationalDiaryUnit=value||State.db.settings.schoolName||'Purple Idiomas';
  renderPage();
}
function openOperationalDiaryEntry(id){const entry=(State.db.operationalDiaries||[]).find(item=>item.id===id);if(!entry)return toast('Diário operacional não encontrado.');if(!operationalDiaryVisibleSectors().includes(entry.sector))return toast('Acesso negado a este setor.');State.operationalDiarySector=entry.sector;State.operationalDiaryDate=entry.entryDate;State.operationalDiaryUnit=entry.unitName;go('operational-diary')}
async function saveOperationalDiary(){
  const form=$('#operationalDiaryForm');
  if(!form?.reportValidity())return;
  const entry=selectedOperationalDiaryEntry(),sector=operationalDiarySector(),unit=operationalDiaryUnit(),entryDate=State.operationalDiaryDate||todayISO();
  if(!unit)return toast('Informe a unidade.');
  if(!entryDate)return toast('Informe a data.');
  if(!operationalDiaryVisibleSectors().includes(sector))return toast('Acesso negado a este setor.');
  if(entry?!can('reports.edit'):!can('reports.create'))return toast('Operação não autorizada.');
  const metricInputs=$$('[data-diary-metric]',form),metrics={};
  for(const input of metricInputs){
    const value=Number(input.value);
    if(!Number.isFinite(value)||value<0)return toast('Os indicadores devem conter somente números iguais ou maiores que zero.');
    metrics[input.dataset.diaryMetric]=value;
  }
  const button=form.querySelector('.sticky-actions .btn.primary');
  if(button?.disabled)return;
  if(button){button.disabled=true;button.classList.add('loading')}
  const payload={id:entry?.id,sector,unit_name:unit,entry_date:entryDate,responsible_user_id:State.user.id,responsible_name:State.user.name,metrics,observation:$('#operationalDiaryObservation')?.value.trim()||''};
  try{
    const {data,error}=await Supabase.from('operational_diary_entries').upsert(payload,{onConflict:'sector,unit_name,entry_date'}).select().single();
    if(error)throw error;
    const normalized=normalizeOperationalDiary(data),index=State.db.operationalDiaries.findIndex(item=>item.id===normalized.id||item.sector===normalized.sector&&item.unitName===normalized.unitName&&item.entryDate===normalized.entryDate);
    if(index>=0)State.db.operationalDiaries[index]=normalized;else State.db.operationalDiaries.unshift(normalized);
    try{await refreshIntelligenceSnapshots()}catch(snapshotError){console.error('Purple Gestão — atualização dos indicadores do diário:',snapshotError)}
    await logAudit(entry?'Atualizou diário operacional':'Registrou diário operacional',`${SECTOR_LABELS[sector]} • ${fmtDate(entryDate)} • ${unit}`);
    toast(entry?'Diário operacional atualizado.':'Diário operacional salvo.');
    renderPage();
  }catch(error){
    toast(friendlyError(error,'salvamento do diário operacional'));
  }finally{
    if(button?.isConnected){button.disabled=false;button.classList.remove('loading')}
  }
}
function upperFormValue(value=''){return String(value||'').trim().toLocaleUpperCase('pt-BR')}
function upperLiveValue(value=''){return String(value||'').toLocaleUpperCase('pt-BR')}
async function saveReport(status){const form=$('#reportForm');if(status==='sent'&&!form.reportValidity())return;const sector=$('#formSector').value,frequency=$('#formFrequency').value,start=$('#reportStart').value,end=$('#reportEnd').value;if(!start||!end){toast('Informe o período do relatório.');return}const beforeReports=cloneValue(State.db.reports),beforeActions=cloneValue(State.db.actions),metrics={};$$('[data-metric]').forEach(i=>metrics[i.dataset.metric]=Number(i.value||0));const existingReport=State.editingReportId?State.db.reports.find(r=>r.id===State.editingReportId):null,selectedAttachments=[...($('#reportAttachments')?.files||[])].map(f=>f.name),actionItems=collectRows('.action-row','action').filter(a=>a.title?.trim());if(status==='sent'){if(!actionItems.length)return toast('Inclua pelo menos um plano de ação para enviar o relatório.');const incomplete=actionItems.find(a=>!a.owner?.trim()||!a.deadline||!a.expected?.trim());if(incomplete)return toast('Preencha responsável, prazo e resultado esperado em cada ação antes de enviar.')}const reportData={sector,frequency,period:`${fmtDate(start)} a ${fmtDate(end)}`,start,end,presentation:$('#reportPresentation').value,presentedTo:$('#reportPresentedTo').value,status,ownerId:existingReport?.ownerId||State.user.id,owner:existingReport?.owner||State.user.name,metrics,reasons:$$('input[name="reportReason"]:checked').map(i=>i.value),summary:$('#reportSummary').value.trim(),decisions:$('#reportDecisions').value.trim(),cases:collectRows('.case-row','case'),actionItems,attachments:selectedAttachments.length?selectedAttachments:[...(existingReport?.attachments||[])],updatedAt:new Date().toISOString()};let report;if(existingReport){report=existingReport;Object.assign(report,reportData)}else{report={id:uid('rep'),...reportData,createdAt:new Date().toISOString()};State.db.reports.push(report)}report.actionItems.forEach(a=>{if(!a.title)return;const existing=State.db.actions.find(x=>x.reportId===report.id&&x.title===a.title);if(existing)Object.assign(existing,{owner:a.owner,deadline:a.deadline,expected:a.expected,priority:a.priority});else State.db.actions.push({id:uid('act'),reportId:report.id,sector,title:a.title,owner:a.owner,deadline:a.deadline,expected:a.expected,priority:a.priority,status:'pending',progress:0,createdAt:new Date().toISOString()})});try{await persistReportIntelligence('report_save');logAudit(existingReport?'Atualizou relatório':status==='sent'?'Enviou relatório':'Salvou rascunho',`${SECTOR_LABELS[sector]} • ${report.period}`);State.editingReportId=null;status==='sent'?premiumToast('Relatório enviado com sucesso. Excelente entrega!'):toast('Rascunho salvo.');go('reports')}catch(error){State.db.reports=beforeReports;State.db.actions=beforeActions;toast(friendlyError(error,'salvamento do relatório'))}}
function editReport(id){const r=State.db.reports.find(x=>x.id===id);if(!r||!canEditReport(r))return;State.editingReportId=id;State.sector=r.sector;State.newFrequency=r.frequency;$('#sectorSwitcher').value=r.sector;go('new-report')}
function prefillEditingReport(){/* values are rendered directly by renderNewReport */}
function cancelReportEdit(){State.editingReportId=null;go('reports')}

function reportMetricSummary(r){return SCHEMAS[r.sector][r.frequency].metrics.map(([k,l,t])=>`<div class="summary-cell"><span>${l}</span><b>${fmtMetric(r.metrics?.[k],t)}</b></div>`).join('')}
function reportCasesTable(r){if(!r.cases?.length)return '<p class="muted">Nenhum caso prioritário informado.</p>';return `<div class="table-wrap"><table><thead><tr><th>Referência</th><th>Situação</th><th>Ação realizada</th><th>Próximo passo</th><th>Prazo</th></tr></thead><tbody>${r.cases.map(c=>`<tr><td>${escapeHTML(c.name)}</td><td>${escapeHTML(c.situation)}</td><td>${escapeHTML(c.action)}</td><td>${escapeHTML(c.next)}</td><td>${fmtDate(c.deadline)}</td></tr>`).join('')}</tbody></table></div>`}
function reportActionsTable(r){const items=r.actionItems||[];if(!items.length)return '<p class="muted">Nenhuma ação informada.</p>';return `<div class="table-wrap"><table><thead><tr><th>Ação</th><th>Responsável</th><th>Prazo</th><th>Resultado esperado</th><th>Prioridade</th></tr></thead><tbody>${items.map(a=>`<tr><td>${escapeHTML(a.title)}</td><td>${escapeHTML(a.owner)}</td><td>${fmtDate(a.deadline)}</td><td>${escapeHTML(a.expected)}</td><td>${priorityHTML(a.priority)}</td></tr>`).join('')}</tbody></table></div>`}
function openReport(id){const r=State.db.reports.find(x=>x.id===id);if(!r)return;if(!sectorAllowed(r.sector))return toast('Você não possui acesso a esse relatório.');const workflow=State.user.role==='direction'?`<div class="section-actions">${r.status==='sent'?`<button class="btn soft" onclick="App.setReportStatus('${r.id}','review')">Iniciar análise</button>`:''}${['sent','review'].includes(r.status)?`<button class="btn danger" onclick="App.requestAdjustment('${r.id}')">Solicitar ajuste</button><button class="btn success" onclick="App.approveReport('${r.id}')">Aprovar</button>`:''}${r.status==='approved'?`<button class="btn ghost" onclick="App.setReportStatus('${r.id}','archived')">Arquivar</button>`:''}</div>`:'';modal(`<div class="modal-head"><div><span class="eyebrow">${SECTOR_LABELS[r.sector]} • ${FREQUENCY_LABELS[r.frequency]}</span><h3>${escapeHTML(r.period)}</h3><div style="margin-top:8px">${statusHTML(r.status)}</div></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="kpi-strip"><span><b>Responsável:</b> ${escapeHTML(r.owner)}</span><span><b>Apresentação:</b> ${fmtDate(r.presentation)}</span><span><b>Apresentado para:</b> ${escapeHTML(r.presentedTo||'Direção')}</span></div><div class="summary-grid">${reportMetricSummary(r)}</div><section class="form-card"><h3>Resumo executivo</h3><p class="muted" style="line-height:1.65">${escapeHTML(r.summary||'Não informado.')}</p></section><section class="form-card"><h3>Decisões necessárias</h3><p class="muted" style="line-height:1.65">${escapeHTML(r.decisions||'Não informado.')}</p></section><section class="form-card"><h3>Motivos e pontos de atenção</h3><div class="check-list">${(r.reasons||[]).map(x=>`<span class="check-chip">✓ ${escapeHTML(x)}</span>`).join('')||'<span class="muted">Nenhum motivo marcado.</span>'}</div></section><section class="form-card"><h3>Casos prioritários</h3>${reportCasesTable(r)}</section><section class="form-card"><h3>Plano de ação</h3>${reportActionsTable(r)}</section>${r.attachments?.length?`<section class="form-card"><h3>Anexos</h3><p class="muted">${r.attachments.map(escapeHTML).join(', ')}</p></section>`:''}<div class="section-actions" style="margin-top:14px">${can('reports.export')?`<button class="btn ghost" onclick="window.print()">Imprimir / salvar PDF</button><button class="btn ghost" onclick="App.downloadReportJSON('${r.id}')">Baixar JSON</button>`:''}${canEditReport(r)?`<button class="btn soft" onclick="App.closeModal();App.editReport('${r.id}')">Editar</button>`:''}${workflow}</div>`)}
function downloadReportJSON(id){const r=State.db.reports.find(x=>x.id===id);if(r&&can('reports.export')&&sectorAllowed(r.sector))download(`relatorio-${r.sector}-${r.end||r.id}.json`,JSON.stringify(r,null,2));else toast('Exportação não autorizada.')}
async function setReportStatus(id,status){if(!can('reports.approve'))return toast('Alteração de status não autorizada.');const r=State.db.reports.find(x=>x.id===id),allowed={sent:['review'],approved:['archived']};if(!r||!sectorAllowed(r.sector)||!allowed[r.status]?.includes(status))return toast('Transição de status não autorizada.');const before=cloneValue(r);r.status=status;r.updatedAt=new Date().toISOString();try{await persistReportIntelligence(`report_status_${status}`);logAudit(`Alterou status para ${STATUS_LABELS[status]}`,`${SECTOR_LABELS[r.sector]} • ${r.period}`);closeModal();toast(`Relatório: ${STATUS_LABELS[status]}.`);renderPage()}catch(error){restoreRecord(r,before);toast(friendlyError(error,'atualização do status do relatório'))}}
function requestAdjustment(id){const r=State.db.reports.find(x=>x.id===id);if(!r)return;modal(`<div class="modal-head"><div><span class="eyebrow">Solicitar ajuste</span><h3>${SECTOR_LABELS[r.sector]} — ${r.period}</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="field"><label>Orientação para o líder</label><textarea id="adjustmentNote" class="large" placeholder="Informe exatamente o que deve ser corrigido..."></textarea></div><div class="section-actions"><button class="btn ghost" onclick="App.closeModal()">Cancelar</button><button class="btn danger" onclick="App.confirmAdjustment('${id}')">Solicitar ajuste</button></div>`,true)}
async function confirmAdjustment(id){const r=State.db.reports.find(x=>x.id===id),note=$('#adjustmentNote').value.trim();if(!r||!['sent','review'].includes(r.status))return toast('Este relatório não aceita solicitação de ajuste.');if(!note)return toast('Informe a orientação do ajuste.');const before=cloneValue(r);r.status='adjust';r.adjustmentNote=note;r.updatedAt=new Date().toISOString();try{await persistReportIntelligence('report_adjustment');logAudit('Solicitou ajuste em relatório',`${SECTOR_LABELS[r.sector]} • ${r.period} • ${note}`);closeModal();toast('Ajuste solicitado ao líder.');renderPage()}catch(error){restoreRecord(r,before);toast(friendlyError(error,'solicitação de ajuste'))}}
async function approveReport(id){const r=State.db.reports.find(x=>x.id===id);if(!r||!['sent','review'].includes(r.status))return toast('Este relatório não está disponível para aprovação.');if(r.ownerId===State.user.id)return toast('O autor não pode aprovar o próprio relatório.');const before=cloneValue(r);r.status='approved';r.approvedAt=new Date().toISOString();r.approvedBy=State.user.name;r.approvedById=State.user.id;try{await persistReportIntelligence('report_approval');logAudit('Aprovou relatório',`${SECTOR_LABELS[r.sector]} • ${r.period}`);closeModal();premiumToast('Relatório aprovado. Excelente decisão registrada.');renderPage()}catch(error){restoreRecord(r,before);toast(friendlyError(error,'aprovação do relatório'))}}

const FINANCIAL_STATUS={open:'Em aberto',paid:'Pago/Recebido',partial:'Parcial',overdue:'Atrasado',cancelled:'Cancelado',negotiated:'Negociado'};
function financialEntries(type='all'){return (State.db.financialEntries||[]).filter(item=>item.active!==false&&(type==='all'||item.type===type))}
function financialFilteredEntries(type){const q=(State.financialSearch||'').toLowerCase();return financialEntries(type).filter(item=>!q||[item.person,item.description,item.category,item.status,item.paymentMethod,item.account,item.notes].some(v=>String(v||'').toLowerCase().includes(q))).sort((a,b)=>String(a.dueDate||'').localeCompare(String(b.dueDate||'')))}
function financialStatusFor(item={}){if(item.status==='cancelled')return 'cancelled';if(item.status==='paid')return 'paid';if(Number(item.paidAmount||0)>0&&Number(item.paidAmount||0)<Number(item.amount||0))return 'partial';if(item.dueDate&&item.dueDate<todayISO()&&Number(item.paidAmount||0)<Number(item.amount||0))return 'overdue';return item.status||'open'}
function financialTotals(){const receivables=financialEntries('receivable'),payables=financialEntries('payable'),sum=(arr,field='amount')=>arr.reduce((total,item)=>total+Number(item[field]||0),0),openValue=arr=>arr.filter(item=>!['paid','cancelled'].includes(financialStatusFor(item))).reduce((total,item)=>total+Math.max(0,Number(item.amount||0)-Number(item.paidAmount||0)),0);return {receivableOpen:openValue(receivables),payableOpen:openValue(payables),received:sum(receivables,'paidAmount'),paid:sum(payables,'paidAmount'),receivableCount:receivables.length,payableCount:payables.length,overdue:receivables.filter(item=>financialStatusFor(item)==='overdue'),cashProjected:openValue(receivables)-openValue(payables)}}
function financialTabs(){return `<div class="settings-tabs financial-tabs"><button class="${State.financialView==='overview'?'active':''}" onclick="App.setFinancialView('overview')">Visão Geral</button><button class="${State.financialView==='receivables'?'active':''}" onclick="App.setFinancialView('receivables')">Contas a Receber</button><button class="${State.financialView==='payables'?'active':''}" onclick="App.setFinancialView('payables')">Contas a Pagar</button><button class="${State.financialView==='cashflow'?'active':''}" onclick="App.setFinancialView('cashflow')">Fluxo de Caixa</button></div>`}
function setFinancialView(view){State.financialView=view;State.financialSearch='';renderPage()}
function setFinancialSearch(value){State.financialSearch=value;renderPage()}
function renderFinancialHub(){if(!can('financial.receipts.view')&&!can('financial.receivables.view')&&!can('financial.payables.view'))return `<div class="page"><div class="empty"><div class="emoji">🔒</div><h3>Acesso restrito</h3></div></div>`;const totals=financialTotals();return `<div class="page financial-page"><section class="hero financial-hero"><div class="hero-content"><div><span class="eyebrow light">ERP Financeiro Purple</span><h2>Financeiro separado, claro e pronto para operação.</h2><p>Contas a receber, contas a pagar, fluxo de caixa e visão executiva agora funcionam em áreas próprias.</p></div><div class="hero-badge">Centro financeiro</div></div></section>${financialTabs()}<section class="grid cols-4" style="margin-bottom:16px">${metricCard('A receber em aberto',fmtMoney(totals.receivableOpen),'↙',0,`${fmtNumber(totals.receivableCount)} título(s)`)}${metricCard('A pagar em aberto',fmtMoney(totals.payableOpen),'↗',0,`${fmtNumber(totals.payableCount)} conta(s)`,true)}${metricCard('Recebido',fmtMoney(totals.received),'R$',0,'Baixas registradas')}${metricCard('Saldo projetado',fmtMoney(totals.cashProjected),'⌁',0,'Receber − pagar')}</section>${State.financialView==='receivables'?renderFinancialLedger('receivable'):State.financialView==='payables'?renderFinancialLedger('payable'):State.financialView==='cashflow'?renderFinancialCashflow():renderFinancialOverview(totals)}</div>`}
function renderFinancialOverview(totals){const alerts=[];if(totals.overdue.length)alerts.push(['red','Recebíveis atrasados',`${fmtNumber(totals.overdue.length)} título(s) vencidos. Priorize cobrança hoje.`]);if(totals.cashProjected<0)alerts.push(['red','Fluxo projetado negativo',`Falta ${fmtMoney(Math.abs(totals.cashProjected))} para cobrir as contas abertas.`]);if(!alerts.length)alerts.push(['green','Financeiro sem alerta crítico','As contas abertas não indicam risco imediato.']);return `<section class="dashboard-layout"><div class="panel"><div class="panel-head"><div><h3>Áreas financeiras</h3><small>Escolha uma área para operar</small></div></div><div class="financial-module-grid">${financialCard('Contas a Receber','Mensalidades, materiais, matrículas, acordos e parcelas.','↙',"App.setFinancialView('receivables')",`${fmtMoney(totals.receivableOpen)} aberto`)}${financialCard('Contas a Pagar','Fornecedores, folha, impostos, estrutura e softwares.','↗',"App.setFinancialView('payables')",`${fmtMoney(totals.payableOpen)} aberto`)}${financialCard('Fluxo de Caixa','Entradas, saídas, saldo realizado e saldo projetado.','⌁',"App.setFinancialView('cashflow')",`${fmtMoney(totals.cashProjected)}`)}${financialCard('Inadimplência','Títulos vencidos e plano de cobrança recomendado.','!',"App.setFinancialView('receivables')",`${fmtNumber(totals.overdue.length)} atraso(s)`)}</div></div><div class="panel"><div class="panel-head"><div><h3>Purple IA financeira</h3><small>Leitura de decisão</small></div></div><div class="alerts">${alerts.map(([tone,title,text])=>`<div class="alert ${tone}"><div class="alert-icon">${tone==='green'?'✓':'!'}</div><div><b>${escapeHTML(title)}</b><span>${escapeHTML(text)}</span></div></div>`).join('')}</div></div></section>`}
function renderFinancialLedger(type){const isReceivable=type==='receivable',rows=financialFilteredEntries(type),permission=isReceivable?'financial.receivables.view':'financial.payables.view',canEdit=can('financial.transactions.create')||can('financial.transactions.edit');if(!can(permission))return `<div class="empty"><div class="emoji">🔒</div><h3>Acesso restrito</h3></div>`;return `<section id="${isReceivable?'receivablesPanel':'payablesPanel'}" class="panel"><div class="panel-head"><div><h3>${isReceivable?'Contas a Receber':'Contas a Pagar'}</h3><small>${isReceivable?'Recebimentos separados dos pagamentos.':'Pagamentos separados dos recebimentos.'}</small></div><div class="section-actions">${canEdit?`<button class="btn primary" onclick="App.editFinancialEntry('${type}')">${isReceivable?'Novo recebimento':'Nova conta'}</button>`:''}</div></div><div class="filters"><input class="search" value="${escapeHTML(State.financialSearch||'')}" placeholder="Pesquisar pessoa, categoria, status ou observação" oninput="App.setFinancialSearch(this.value)"/></div><div class="table-wrap"><table><thead><tr><th>${isReceivable?'Aluno / Cliente':'Fornecedor'}</th><th>Descrição</th><th>Categoria</th><th>Vencimento</th><th>Valor</th><th>Baixado</th><th>Status</th><th>Ações</th></tr></thead><tbody>${rows.map(item=>financialRow(item)).join('')||`<tr><td colspan="8"><div class="empty"><p>Nenhum registro financeiro encontrado.</p></div></td></tr>`}</tbody></table></div></section>`}
function financialRow(item){const status=financialStatusFor(item),editable=can('financial.transactions.edit'),deletable=can('financial.transactions.delete');return `<tr><td>${escapeHTML(item.person||'—')}</td><td>${escapeHTML(item.description||'—')}</td><td>${escapeHTML(item.category||'—')}</td><td>${fmtDate(item.dueDate)}</td><td>${fmtMoney(item.amount)}</td><td>${fmtMoney(item.paidAmount||0)}</td><td><span class="status ${status==='paid'?'approved':status==='overdue'?'adjust':status==='partial'?'review':status==='cancelled'?'archived':'draft'}">${FINANCIAL_STATUS[status]||status}</span></td><td><div class="table-actions">${editable?`<button class="btn ghost small" onclick="App.editFinancialEntry('${item.type}','${item.id}')">Editar</button><button class="btn soft small" onclick="App.markFinancialPaid('${item.id}')">Baixar</button>`:''}${deletable?`<button class="btn danger small" onclick="App.deleteFinancialEntry('${item.id}')">Excluir</button>`:''}</div></td></tr>`}
function renderFinancialCashflow(){const entries=financialEntries().sort((a,b)=>String(a.dueDate||'').localeCompare(String(b.dueDate||''))),realized=entries.reduce((sum,item)=>sum+(item.type==='receivable'?1:-1)*Number(item.paidAmount||0),0),projected=entries.filter(item=>!['paid','cancelled'].includes(financialStatusFor(item))).reduce((sum,item)=>sum+(item.type==='receivable'?1:-1)*Math.max(0,Number(item.amount||0)-Number(item.paidAmount||0)),0);return `<section id="cashFlowPanel" class="panel"><div class="panel-head"><div><h3>Fluxo de Caixa</h3><small>Baseado nas contas cadastradas em receber e pagar</small></div></div><div class="kpi-strip"><span><b>Realizado:</b> ${fmtMoney(realized)}</span><span><b>Projetado:</b> ${fmtMoney(projected)}</span><span><b>Total estimado:</b> ${fmtMoney(realized+projected)}</span></div><div class="table-wrap" style="margin-top:14px"><table><thead><tr><th>Data</th><th>Tipo</th><th>Descrição</th><th>Pessoa</th><th>Valor aberto</th><th>Status</th></tr></thead><tbody>${entries.map(item=>`<tr><td>${fmtDate(item.dueDate)}</td><td>${item.type==='receivable'?'Entrada':'Saída'}</td><td>${escapeHTML(item.description||'—')}</td><td>${escapeHTML(item.person||'—')}</td><td>${fmtMoney(Math.max(0,Number(item.amount||0)-Number(item.paidAmount||0)))}</td><td>${FINANCIAL_STATUS[financialStatusFor(item)]}</td></tr>`).join('')||'<tr><td colspan="6"><div class="empty"><p>Nenhuma movimentação cadastrada.</p></div></td></tr>'}</tbody></table></div></section>`}
function editFinancialEntry(type,id=''){if(!can(id?'financial.transactions.edit':'financial.transactions.create'))return toast('Operação não autorizada.');const item=id?financialEntries().find(entry=>entry.id===id):null,isReceivable=type==='receivable';modal(`<div class="modal-head"><div><span class="eyebrow">Financeiro</span><h3>${item?'Editar':isReceivable?'Novo contas a receber':'Novo contas a pagar'}</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="form-grid cols-2"><div class="field"><label>${isReceivable?'Aluno / Cliente':'Fornecedor'}</label><input id="financialPerson" value="${escapeHTML(item?.person||'')}"/></div><div class="field"><label>Descrição</label><input id="financialDescription" value="${escapeHTML(item?.description||'')}"/></div><div class="field"><label>Categoria</label><input id="financialCategory" value="${escapeHTML(item?.category||(isReceivable?'Mensalidade':'Fornecedor'))}"/></div><div class="field"><label>Competência</label><input id="financialCompetence" type="month" value="${escapeHTML(item?.competence||'')}"/></div><div class="field"><label>Vencimento</label><input id="financialDueDate" type="date" value="${item?.dueDate||todayISO()}"/></div><div class="field"><label>Valor</label><input id="financialAmount" type="number" step="0.01" min="0" value="${Number(item?.amount||0)}"/></div><div class="field"><label>Valor baixado</label><input id="financialPaidAmount" type="number" step="0.01" min="0" value="${Number(item?.paidAmount||0)}"/></div><div class="field"><label>Data da baixa</label><input id="financialPaidDate" type="date" value="${item?.paidDate||''}"/></div><div class="field"><label>Forma de pagamento</label><input id="financialPaymentMethod" value="${escapeHTML(item?.paymentMethod||'PIX')}"/></div><div class="field"><label>Conta financeira</label><input id="financialAccount" value="${escapeHTML(item?.account||'Caixa / Banco')}"/></div><div class="field"><label>Status</label><select id="financialStatus">${Object.entries(FINANCIAL_STATUS).map(([k,v])=>`<option value="${k}" ${financialStatusFor(item||{})===k?'selected':''}>${v}</option>`).join('')}</select></div><div class="field"><label>Responsável</label><input id="financialOwner" value="${escapeHTML(item?.owner||State.user.name)}"/></div></div><div class="field"><label>Observações</label><textarea id="financialNotes">${escapeHTML(item?.notes||'')}</textarea></div><div class="section-actions"><button class="btn ghost" onclick="App.closeModal()">Cancelar</button><button class="btn primary" onclick="App.saveFinancialEntry('${type}','${id}')">Salvar</button></div>`,true)}
async function saveFinancialEntry(type,id=''){if(!can(id?'financial.transactions.edit':'financial.transactions.create'))return toast('Operação não autorizada.');const person=upperFormValue($('#financialPerson').value),description=upperFormValue($('#financialDescription').value),amount=Number($('#financialAmount').value||0),paidAmount=Number($('#financialPaidAmount').value||0);if(!person||!description)return toast('Informe pessoa/fornecedor e descrição.');if(amount<0||paidAmount<0)return toast('Valores não podem ser negativos.');if(paidAmount>amount)return toast('Valor baixado não pode ser maior que o valor total.');State.db.financialEntries=State.db.financialEntries||[];const existing=id?State.db.financialEntries.find(item=>item.id===id):null,before=existing?cloneValue(existing):null,payload={id:existing?.id||uid('fin'),type,person,description,category:upperFormValue($('#financialCategory').value),competence:$('#financialCompetence').value,dueDate:$('#financialDueDate').value,amount,paidAmount,paidDate:$('#financialPaidDate').value,paymentMethod:upperFormValue($('#financialPaymentMethod').value),account:upperFormValue($('#financialAccount').value),status:$('#financialStatus').value,owner:upperFormValue($('#financialOwner').value),notes:upperFormValue($('#financialNotes').value),active:true,createdAt:existing?.createdAt||new Date().toISOString(),updatedAt:new Date().toISOString()};if(existing)Object.assign(existing,payload);else State.db.financialEntries.unshift(payload);try{await Storage.save(State.db);await logAudit(existing?'Atualizou conta financeira':'Criou conta financeira',`${payload.type==='receivable'?'Receber':'Pagar'} • ${payload.description} • ${fmtMoney(payload.amount)}`);closeModal();toast('Conta financeira salva.');renderPage()}catch(error){if(existing)restoreRecord(existing,before);else State.db.financialEntries=State.db.financialEntries.filter(item=>item.id!==payload.id);toast(friendlyError(error,'salvamento financeiro'))}}
async function markFinancialPaid(id){const item=financialEntries().find(entry=>entry.id===id);if(!item||!can('financial.transactions.edit'))return toast('Operação não autorizada.');const before=cloneValue(item);item.paidAmount=Number(item.amount||0);item.paidDate=todayISO();item.status='paid';item.updatedAt=new Date().toISOString();try{await Storage.save(State.db);await logAudit('Baixou conta financeira',`${item.description} • ${fmtMoney(item.amount)}`);toast('Baixa registrada.');renderPage()}catch(error){restoreRecord(item,before);toast(friendlyError(error,'baixa financeira'))}}
async function deleteFinancialEntry(id){const item=financialEntries().find(entry=>entry.id===id);if(!item||!can('financial.transactions.delete'))return toast('Exclusão não autorizada.');if(!confirm('Deseja excluir este registro financeiro?'))return;const before=cloneValue(item);item.active=false;item.status='cancelled';item.updatedAt=new Date().toISOString();try{await Storage.save(State.db);await logAudit('Excluiu conta financeira',`${item.description} • ${fmtMoney(item.amount)}`);toast('Registro financeiro excluído.');renderPage()}catch(error){restoreRecord(item,before);toast(friendlyError(error,'exclusão financeira'))}}


function actionVisible(a){return State.user.role==='direction'||State.user.role==='viewer'||a.sector===State.user.sector}
function actionComputedStatus(a){if(a.status==='done'||a.status==='cancelled')return a.status;return daysUntil(a.deadline)<0?'overdue':a.status}
function renderActions(){const arr=State.db.actions.filter(actionVisible).sort((a,b)=>(a.deadline||'9999').localeCompare(b.deadline||'9999'));const counts={pending:0,progress:0,overdue:0,done:0};arr.forEach(a=>counts[actionComputedStatus(a)]=(counts[actionComputedStatus(a)]||0)+1);const cards=arr.map(a=>{const st=actionComputedStatus(a);return `<div class="list-card"><div class="list-card-head"><div><span class="eyebrow">${SECTOR_LABELS[a.sector]}</span><h4>${escapeHTML(a.title)}</h4></div><div>${priorityHTML(a.priority)}</div></div><p>${escapeHTML(a.expected||'Sem resultado esperado informado.')}</p><div class="list-card-meta"><span><b>Responsável:</b> ${escapeHTML(a.owner)}</span><span><b>Prazo:</b> ${fmtDate(a.deadline)}</span><span><b>Status:</b> ${st==='overdue'?'Atrasada':ACTION_STATUS[a.status]}</span></div><div class="progress"><span style="width:${Number(a.progress||0)}%"></span></div><div class="section-actions" style="margin-top:12px;justify-content:flex-start"><button class="btn ghost small" onclick="App.openAction('${a.id}')">Abrir</button>${State.user.role!=='viewer'?`<button class="btn soft small" onclick="App.advanceAction('${a.id}')">Atualizar status</button>`:''}</div></div>`}).join('');return `<div class="page"><div class="section-title"><div><h2>Planos de ação</h2><p>Acompanhe o que foi decidido, quem é o responsável e se o resultado foi alcançado.</p></div>${State.user.role!=='viewer'?`<button class="btn primary" onclick="App.newAction()">Nova ação</button>`:''}</div><section class="grid cols-4" style="margin-bottom:16px">${metricCard('Pendentes',fmtNumber(counts.pending),'○',0,'Aguardando início')}${metricCard('Em andamento',fmtNumber(counts.progress),'↗',0,'Com atualização ativa')}${metricCard('Atrasadas',fmtNumber(counts.overdue),'!',0,'Prazo vencido')}${metricCard('Concluídas',fmtNumber(counts.done),'✓',0,'Resultado registrado')}</section><div class="grid cols-3">${cards||`<div class="empty"><div class="emoji">✓</div><h3>Nenhuma ação cadastrada</h3></div>`}</div></div>`}
function newAction(){const sectors=availableSectors();modal(`<div class="modal-head"><div><span class="eyebrow">Novo plano de ação</span><h3>Definir ação</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="form-grid cols-2"><div class="field"><label>Setor</label><select id="newActionSector">${sectors.map(s=>`<option value="${s}">${SECTOR_LABELS[s]}</option>`).join('')}</select></div><div class="field"><label>Prioridade</label><select id="newActionPriority"><option value="alta">Alta</option><option value="media" selected>Média</option><option value="baixa">Baixa</option></select></div></div><div class="field"><label>Ação</label><input id="newActionTitle" placeholder="Descreva a ação de forma objetiva"/></div><div class="form-grid cols-2"><div class="field"><label>Responsável</label><input id="newActionOwner" value="${escapeHTML(State.user.name)}"/></div><div class="field"><label>Prazo</label><input id="newActionDeadline" type="date"/></div></div><div class="field"><label>Resultado esperado</label><textarea id="newActionExpected"></textarea></div><div class="section-actions"><button class="btn ghost" onclick="App.closeModal()">Cancelar</button><button class="btn primary" onclick="App.saveNewAction()">Criar ação</button></div>`,true)}
async function saveNewAction(){const title=$('#newActionTitle').value.trim(),deadline=$('#newActionDeadline').value;if(!title||!deadline)return toast('Informe a ação e o prazo.');const a={id:uid('act'),sector:$('#newActionSector').value,title,owner:$('#newActionOwner').value,deadline,expected:$('#newActionExpected').value,priority:$('#newActionPriority').value,status:'pending',progress:0,createdAt:new Date().toISOString()};State.db.actions.push(a);try{await Storage.save(State.db);logAudit('Criou plano de ação',`${SECTOR_LABELS[a.sector]} • ${a.title}`);closeModal();toast('Plano de ação criado.');renderPage()}catch(error){State.db.actions=State.db.actions.filter(item=>item.id!==a.id);toast(friendlyError(error,'criação do plano de ação'))}}
function openAction(id){const a=State.db.actions.find(x=>x.id===id);if(!a)return;modal(`<div class="modal-head"><div><span class="eyebrow">${SECTOR_LABELS[a.sector]}</span><h3>${escapeHTML(a.title)}</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="kpi-strip"><span>${priorityHTML(a.priority)}</span><span><b>Status:</b> ${actionComputedStatus(a)==='overdue'?'Atrasada':ACTION_STATUS[a.status]}</span><span><b>Prazo:</b> ${fmtDate(a.deadline)}</span></div><section class="form-card"><h3>Resultado esperado</h3><p class="muted">${escapeHTML(a.expected||'Não informado.')}</p></section><section class="form-card"><h3>Atualização</h3><p class="muted">${escapeHTML(a.updateNote||'Nenhuma atualização registrada.')}</p><div class="progress"><span style="width:${a.progress||0}%"></span></div><p class="muted" style="font-size:10px">Progresso informado: ${a.progress||0}%</p></section>${a.status==='done'?`<section class="form-card"><h3>O que foi feito?</h3><p class="muted">${escapeHTML(a.resolutionNote||'Nenhum fechamento registrado.')}</p></section>`:''}${State.user.role!=='viewer'?`<div class="section-actions"><button class="btn soft" onclick="App.closeModal();App.advanceAction('${a.id}')">Atualizar</button><button class="btn danger" onclick="App.deleteAction('${a.id}')">Excluir</button></div>`:''}`)}
function advanceAction(id){const a=State.db.actions.find(x=>x.id===id);if(!a)return;modal(`<div class="modal-head"><div><span class="eyebrow">Atualizar ação</span><h3>${escapeHTML(a.title)}</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="form-grid cols-2"><div class="field"><label>Status</label><select id="actionStatus"><option value="pending" ${a.status==='pending'?'selected':''}>Pendente</option><option value="progress" ${a.status==='progress'?'selected':''}>Em andamento</option><option value="done" ${a.status==='done'?'selected':''}>Concluída</option><option value="cancelled" ${a.status==='cancelled'?'selected':''}>Cancelada</option></select></div><div class="field"><label>Progresso (%)</label><input id="actionProgress" type="number" min="0" max="100" value="${a.progress||0}"/></div></div><div class="field"><label>Atualização / resultado parcial</label><textarea id="actionUpdate" class="large">${escapeHTML(a.updateNote||'')}</textarea></div><div class="field"><label>O que foi feito?</label><textarea id="actionResolution" class="large" placeholder="Obrigatório ao concluir a ação.">${escapeHTML(a.resolutionNote||'')}</textarea></div><div class="section-actions"><button class="btn ghost" onclick="App.closeModal()">Cancelar</button><button class="btn primary" onclick="App.saveActionUpdate('${a.id}')">Salvar atualização</button></div>`,true)}
async function saveActionUpdate(id){const a=State.db.actions.find(x=>x.id===id);if(!a)return toast('Plano de ação não encontrado.');const before=cloneValue(a),progress=Number($('#actionProgress').value||0),status=$('#actionStatus').value,resolution=$('#actionResolution').value.trim();if(!Number.isFinite(progress)||progress<0||progress>100)return toast('Informe um progresso entre 0 e 100.');if(status==='done'&&!resolution)return toast('Informe o que foi feito para concluir a ação.');a.status=status;a.progress=status==='done'?100:progress;a.updateNote=$('#actionUpdate').value;a.resolutionNote=resolution||a.resolutionNote||'';a.updatedAt=new Date().toISOString();if(status==='done'&&!a.completedAt)a.completedAt=new Date().toISOString();try{await Storage.save(State.db);logAudit('Atualizou plano de ação',`${SECTOR_LABELS[a.sector]} • ${a.title} • ${ACTION_STATUS[a.status]}`);closeModal();a.status==='done'?premiumToast('Plano de ação concluído. Excelente entrega!'):toast('Ação atualizada.');renderPage()}catch(error){restoreRecord(a,before);toast(friendlyError(error,'atualização do plano de ação'))}}
async function deleteAction(id){if(!confirm('Excluir esta ação?'))return;const a=State.db.actions.find(x=>x.id===id);try{await Storage.remove(id)}catch(error){return toast(friendlyError(error,'exclusão do plano de ação'))}State.db.actions=State.db.actions.filter(x=>x.id!==id);logAudit('Excluiu plano de ação',a?.title||id);closeModal();toast('Ação excluída.');renderPage()}

function healthLabel(level){return ({good:'Regular',warn:'Atenção',bad:'Crítico'})[level]||level}
async function refreshIntegratedCases(){
  if(!hasSupabaseClient())throw new Error('Supabase indisponível para carregar os casos integrados.');
  const {data,error}=await Supabase.rpc('list_integrated_cases');
  if(error)throw error;
  State.db.cases=Array.isArray(data)?data:[];
  State.db.casesAvailable=true;
  return State.db.cases;
}
function caseVisible(c){return State.user.role==='direction'||State.user.role==='viewer'||c[State.user.sector]?.level!=='good'||c.owner===State.user.name}
function caseSectorCell(c,sector){const d=c[sector]||{level:'good',summary:'Sem informação.'};if(State.user.role==='leader'&&State.user.sector!==sector)return `<div class="health-cell ${d.level}"><b>${SECTOR_LABELS[sector]}</b>Existe ${healthLabel(d.level).toLowerCase()} neste setor.</div>`;return `<div class="health-cell ${d.level}"><b>${SECTOR_LABELS[sector]} — ${healthLabel(d.level)}</b>${escapeHTML(d.summary||'')}</div>`}
function renderCases(){const arr=State.db.cases.filter(caseVisible).sort((a,b)=>b.updatedAt.localeCompare(a.updatedAt));const cards=arr.map(c=>`<div class="list-card"><div class="list-card-head"><div><span class="eyebrow">${escapeHTML(c.course)}</span><h4>${escapeHTML(c.student)}</h4><p>${escapeHTML(c.group)}</p></div><span class="badge">Prazo ${fmtDate(c.deadline)}</span></div><div class="case-health">${caseSectorCell(c,'retencao')}${caseSectorCell(c,'pedagogico')}${caseSectorCell(c,'financeiro')}</div><div class="list-card-meta"><span><b>Responsável:</b> ${escapeHTML(c.owner)}</span><span><b>Próximo passo:</b> ${escapeHTML(c.nextStep)}</span></div><div class="section-actions" style="justify-content:flex-start;margin-top:12px"><button class="btn ghost small" onclick="App.openCase('${c.id}')">Abrir</button>${State.user.role!=='viewer'?`<button class="btn soft small" onclick="App.editCase('${c.id}')">Atualizar</button>`:''}</div></div>`).join('');const critical=arr.filter(c=>['bad'].includes(c.retencao.level)||['bad'].includes(c.pedagogico.level)||['bad'].includes(c.financeiro.level)).length;return `<div class="page"><div class="section-title"><div><h2>Casos integrados</h2><p>Conecte retenção, pedagógico e financeiro sem expor conteúdo de outro setor aos líderes.</p></div>${State.user.role!=='viewer'?`<button class="btn primary" onclick="App.editCase()">Novo caso</button>`:''}</div><section class="grid cols-4" style="margin-bottom:16px">${metricCard('Casos ativos',fmtNumber(arr.length),'◎',0,'Visíveis para o seu perfil')}${metricCard('Casos críticos',fmtNumber(critical),'!',0,'Pelo menos um setor crítico')}${metricCard('Com prazo vencido',fmtNumber(arr.filter(c=>daysUntil(c.deadline)<0).length),'◷',0,'Exigem atualização')}${metricCard('Atualizados hoje',fmtNumber(arr.filter(c=>fmtDate(c.updatedAt.slice(0,10))===fmtDate(new Date().toISOString().slice(0,10))).length),'↻',0,'Movimentações recentes')}</section><div class="grid cols-2">${cards||`<div class="empty"><div class="emoji">◎</div><h3>Nenhum caso visível</h3></div>`}</div></div>`}
function openCase(id){const c=State.db.cases.find(x=>x.id===id);if(!c||!caseVisible(c))return;modal(`<div class="modal-head"><div><span class="eyebrow">${escapeHTML(c.course)} • ${escapeHTML(c.group)}</span><h3>${escapeHTML(c.student)}</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="case-health">${caseSectorCell(c,'retencao')}${caseSectorCell(c,'pedagogico')}${caseSectorCell(c,'financeiro')}</div><section class="form-card" style="margin-top:14px"><h3>Plano integrado</h3><p><b>Responsável:</b> ${escapeHTML(c.owner)}</p><p><b>Próximo passo:</b> ${escapeHTML(c.nextStep)}</p><p><b>Prazo:</b> ${fmtDate(c.deadline)}</p></section>${State.user.role!=='viewer'?`<div class="section-actions"><button class="btn soft" onclick="App.closeModal();App.editCase('${c.id}')">Atualizar caso</button></div>`:''}`)}
function editCase(id=null){const c=id?State.db.cases.find(x=>x.id===id):null;const editableSectors=State.user.role==='direction'?['retencao','pedagogico','financeiro']:[State.user.sector];const sectorFields=editableSectors.map(s=>{const d=c?.[s]||{level:'good',summary:''};return `<section class="form-card"><h3>${SECTOR_LABELS[s]}</h3><div class="form-grid cols-2"><div class="field"><label>Classificação</label><select id="case-${s}-level"><option value="good" ${d.level==='good'?'selected':''}>Regular</option><option value="warn" ${d.level==='warn'?'selected':''}>Atenção</option><option value="bad" ${d.level==='bad'?'selected':''}>Crítico</option></select></div><div class="field"><label>Resumo do setor</label><textarea id="case-${s}-summary">${escapeHTML(d.summary||'')}</textarea></div></div></section>`}).join('');modal(`<div class="modal-head"><div><span class="eyebrow">${c?'Atualizar':'Novo'} caso integrado</span><h3>${c?escapeHTML(c.student):'Cadastrar acompanhamento'}</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="form-grid cols-3"><div class="field"><label>Aluno / referência</label><input id="caseStudent" value="${escapeHTML(c?.student||'')}" ${State.user.role==='leader'&&c?'disabled':''}/></div><div class="field"><label>Curso</label><input id="caseCourse" value="${escapeHTML(c?.course||'')}"/></div><div class="field"><label>Turma</label><input id="caseGroup" value="${escapeHTML(c?.group||'')}"/></div></div>${sectorFields}<section class="form-card"><h3>Plano de acompanhamento</h3><div class="form-grid cols-3"><div class="field"><label>Responsável</label><input id="caseOwner" value="${escapeHTML(c?.owner||State.user.name)}"/></div><div class="field"><label>Próximo passo</label><input id="caseNext" value="${escapeHTML(c?.nextStep||'')}"/></div><div class="field"><label>Prazo</label><input id="caseDeadline" type="date" value="${c?.deadline||''}"/></div></div></section><div class="section-actions"><button class="btn ghost" onclick="App.closeModal()">Cancelar</button><button class="btn primary" onclick="App.saveCase('${id||''}')">Salvar caso</button></div>`,false)}
async function saveCase(id){
  const student=$('#caseStudent').value.trim();
  if(!student)return toast('Informe o aluno ou referência.');
  const current=id?State.db.cases.find(item=>item.id===id):null;
  if(id&&!current)return toast('O caso não está mais disponível. Atualize a página.');
  const caseId=current?.id||uid('case');
  const editable=State.user.role==='direction'?['retencao','pedagogico','financeiro']:[State.user.sector];
  const sectorPayload={};
  editable.forEach(sector=>{
    sectorPayload[sector]={
      level:$(`#case-${sector}-level`).value,
      summary:$(`#case-${sector}-summary`).value.trim(),
      expectedUpdatedAt:current?.[sector]?.updatedAt||null
    };
  });
  const payload={
    p_case_id:caseId,
    p_student:student,
    p_course:$('#caseCourse').value.trim(),
    p_group:$('#caseGroup').value.trim(),
    p_owner:$('#caseOwner').value.trim(),
    p_next_step:$('#caseNext').value.trim(),
    p_deadline:$('#caseDeadline').value||null,
    p_expected_core_updated_at:current?.coreUpdatedAt||null,
    p_sector_payload:sectorPayload
  };
  let saved=false;
  try{
    const {error}=await Supabase.rpc('save_integrated_case',payload);
    if(error)throw error;
    saved=true;
    await refreshIntegratedCases();
    logAudit(id?'Atualizou caso integrado':'Criou caso integrado',`${student} • ${payload.p_course}`);
    closeModal();toast('Caso salvo.');renderPage();
  }catch(error){
    const technical=[error?.message,error?.details,error?.hint].filter(Boolean).join(' ');
    if(technical.includes('CASE_CORE_CONFLICT')||technical.includes('CASE_SECTOR_CONFLICT')){
      try{await refreshIntegratedCases()}catch(refreshError){console.error('Purple Gestão — recarga dos casos integrados:',refreshError)}
      closeModal();renderPage();
      return toast('Este caso foi atualizado por outra pessoa. Revise os dados e tente novamente.');
    }
    if(saved){
      console.error('Purple Gestão — caso salvo, mas a lista não foi recarregada:',error);
      closeModal();
      return toast('Caso salvo, mas a lista não pôde ser atualizada. Recarregue a página.');
    }
    console.error('Purple Gestão — salvamento do caso integrado:',error);
    toast(friendlyError(error,'salvamento do caso integrado'));
  }
}
function catalogCanView(){return State.user.role!=='viewer'}
function catalogCanEdit(){return State.user.role!=='viewer'}
function normalizeStudentStatus(value=''){const raw=String(value||'').trim().toLowerCase();const map={'ativa':'Ativo','ativo':'Ativo','em andamento':'Matrícula em andamento','matricula em andamento':'Matrícula em andamento','matrícula em andamento':'Matrícula em andamento','inativa':'Inativo','inativo':'Inativo','trancada':'Trancado','trancado':'Trancado','transferida':'Transferido','transferido':'Transferido','concluida':'Concluído','concluído':'Concluído','cancelada':'Cancelado','cancelado':'Cancelado','prospect':'Prospect','lista de espera':'Lista de espera','acompanhamento':'Ativo'};return STUDENT_STATUS_OPTIONS.includes(value)?value:(map[raw]||value||'Ativo')}
function studentStatusOptions(current=''){const normalized=normalizeStudentStatus(current),values=STUDENT_STATUS_OPTIONS.includes(normalized)?STUDENT_STATUS_OPTIONS:[normalized,...STUDENT_STATUS_OPTIONS];return values.map(status=>`<option value="${escapeHTML(status)}" ${status===normalized?'selected':''}>${escapeHTML(status)}</option>`).join('')}
function officialStudents(){return State.db.students||[]}
function officialStudentCounts(){const rows=officialStudents(),count=status=>rows.filter(s=>normalizeStudentStatus(s.situation)===status).length;return {total:rows.length,active:count('Ativo'),inactive:count('Inativo'),locked:count('Trancado'),cancelled:count('Cancelado'),inProgress:count('Matrícula em andamento'),prospects:count('Prospect'),waiting:count('Lista de espera')}}
function studentCatalogScore(s){const freq=Number(s.frequency||0),financial=s.financialStatus==='Em dia'?10:s.financialStatus==='Atraso leve'?6:2,base=freq*0.75+financial*5;return Math.max(0,Math.min(100,Math.round(base)))}
function catalogSortByName(arr){return [...arr].sort((a,b)=>String(a.name||'').localeCompare(String(b.name||'')))}
function catalogMatches(item,query,extra=''){return !query||`${Object.values(item||{}).filter(v=>typeof v==='string'||typeof v==='number').join(' ')} ${extra}`.toLowerCase().includes(query)}
function setCatalogSearch(kind,value){State.catalogSearch={...(State.catalogSearch||{}),[kind]:String(value||'').trim().toLowerCase()};const caret=kind==='students'?{id:'studentSearchInput',value:String(value||''),start:$('#studentSearchInput')?.selectionStart||String(value||'').length}:null;renderPage();if(caret)requestAnimationFrame(()=>{const input=$(`#${caret.id}`);if(input){input.focus();const pos=Math.min(caret.start,input.value.length);input.setSelectionRange?.(pos,pos)}})}
function catalogTimeline(items=[]){return `<div class="timeline">${(items||[]).map(item=>`<div class="timeline-item"><b>${escapeHTML(item.title)}</b><p>${escapeHTML(item.detail||'')}</p><time>${fmtDateTime(item.at)}</time></div>`).join('')||'<div class="empty"><p>Sem histórico registrado.</p></div>'}</div>`}
function onlyDigits(value=''){return String(value||'').replace(/\D/g,'')}
function formatPhoneBR(value=''){const d=onlyDigits(value).slice(0,11);if(!d)return '';if(d.length<=2)return `(${d}`;if(d.length<=7)return `(${d.slice(0,2)})${d.slice(2)}`;return `(${d.slice(0,2)})${d.slice(2,7)}-${d.slice(7)}`}
function formatCepBR(value=''){const d=onlyDigits(value).slice(0,8);if(!d)return '';return d.length>5?`${d.slice(0,5)}-${d.slice(5)}`:d}
function formatCpfBR(value=''){const d=onlyDigits(value).slice(0,11);if(!d)return '';if(d.length<=3)return d;if(d.length<=6)return `${d.slice(0,3)}.${d.slice(3)}`;if(d.length<=9)return `${d.slice(0,3)}.${d.slice(3,6)}.${d.slice(6)}`;return `${d.slice(0,3)}.${d.slice(3,6)}.${d.slice(6,9)}-${d.slice(9)}`}
function validateStudentCpfField(currentId=''){const field=$('#studentDocument'),status=$('#studentDocumentStatus');if(!field)return true;field.value=formatCpfBR(field.value);const digits=onlyDigits(field.value);const duplicate=digits&&(State.db.students||[]).some(student=>student.id!==currentId&&onlyDigits(student.document||'')===digits);if(status){status.textContent=!digits?'':duplicate?'CPF já cadastrado.':'✓ Documento sem duplicidade aparente.';status.className=duplicate?'error':'success'}return !duplicate}
function validateStudentWhatsappField(){const field=$('#studentWhatsapp'),status=$('#studentWhatsappStatus');if(!field)return true;field.value=formatPhoneBR(field.value);const valid=onlyDigits(field.value).length>=10;if(status){status.textContent=!field.value?'':valid?'✓ WhatsApp válido.':'⚠ WhatsApp inválido.';status.className=valid?'success':'error'}return !field.value||valid}
function openStudentBirthPicker(){const picker=$('#studentBirthPicker');if(!picker)return;picker.showPicker?picker.showPicker():picker.click()}
function syncStudentBirthFromPicker(){const picker=$('#studentBirthPicker'),field=$('#studentBirthDate');if(!picker||!field)return;field.value=studentBirthDisplay(picker.value);updateStudentAgePreviewWithCep()}
function addStudentResponsibleRow(){return addStudentFullResponsibleRow()}
function addStudentFullResponsibleRow(){const host=$('#studentResponsibleRows')||document.querySelector('[data-student-tab-panel="responsavel"]');if(!host)return;const row=document.createElement('div');row.className='clean-card student-responsible-row';row.dataset.responsibleRow=uid();row.innerHTML=`<div class="clean-grid cols-3"><label>Nome<input class="student-resp-name"/></label><label>Parentesco<input class="student-resp-type"/></label><label>CPF<input class="student-resp-document" oninput="this.value=App.formatCpfBR?App.formatCpfBR(this.value):this.value"/></label><label>Telefone<input class="student-resp-phone" oninput="this.value=App.formatPhoneBR(this.value)"/></label><label>WhatsApp<input class="student-resp-whatsapp" oninput="this.value=App.formatPhoneBR(this.value)"/></label><label>Email<input class="student-resp-email" type="email"/></label></div><div class="section-actions"><label class="clean-check"><input class="student-resp-financial" type="checkbox"/> Financeiro</label><label class="clean-check"><input class="student-resp-pedagogical" type="checkbox"/> Pedagógico</label><button type="button" class="btn danger small" onclick="App.removeStudentResponsibleRow(this)">Remover</button></div>`;host.appendChild(row);row.querySelector('input')?.focus()}
function removeStudentResponsibleRow(button){button?.closest('[data-responsible-row],.student-responsible-row')?.remove()}
function uppercaseTypedValue(value=''){return String(value||'').trim().toLocaleUpperCase('pt-BR')}
function uppercaseStudentFormValues(){const skipTypes=new Set(['hidden','date','number','checkbox','file']);$$('.clean-student-form input,.clean-student-form textarea').forEach(field=>{if(skipTypes.has(field.type)||field.type==='email'||field.id==='studentBirthDate'||field.id==='studentCep'||field.id==='studentDocument'||field.classList.contains('student-resp-document'))return;field.value=upperFormValue(field.value)});$$('.clean-student-form input[type="email"]').forEach(field=>{field.value=String(field.value||'').trim().toLowerCase()})}
async function lookupStudentCep(){const input=$('#studentCep'),cep=onlyDigits(input?.value||'');if(input)input.value=formatCepBR(cep);if(cep.length!==8)return;const status=$('#studentCepStatus');if(status)status.textContent='Buscando CEP...';try{const response=await fetch(`https://viacep.com.br/ws/${cep}/json/`);if(!response.ok)throw new Error(`HTTP ${response.status}`);const data=await response.json();if(data.erro)throw new Error('CEP não encontrado');const fill=(id,value)=>{const el=$(`#${id}`);if(el&&value)el.value=value};fill('studentAddress',data.logradouro);fill('studentDistrict',data.bairro);fill('studentCity',data.localidade);fill('studentState',data.uf);if(status)status.textContent='Endereço preenchido pelo CEP.'}catch(error){console.warn('Purple Gestão — busca de CEP:',error);if(status)status.textContent='Não foi possível localizar este CEP.'}}
function bindPhoneMask(id){const input=$(`#${id}`);if(input)input.value=formatPhoneBR(input.value)}
function studentBirthISO(value=''){const raw=String(value||'').trim();if(!raw)return '';const br=raw.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);if(br)return `${br[3]}-${br[2]}-${br[1]}`;const iso=raw.match(/^(\d{4})-(\d{2})-(\d{2})/);return iso?`${iso[1]}-${iso[2]}-${iso[3]}`:''}
function studentBirthDisplay(value=''){const iso=studentBirthISO(value);if(!iso)return '';const [y,m,d]=iso.split('-');return `${d}/${m}/${y}`}
function formatDateBR(value=''){const d=onlyDigits(value).slice(0,8);if(d.length<=2)return d;if(d.length<=4)return `${d.slice(0,2)}/${d.slice(2)}`;return `${d.slice(0,2)}/${d.slice(2,4)}/${d.slice(4)}`}
function studentAgeParts(birthDate=''){const iso=studentBirthISO(birthDate);if(!iso)return null;const birth=new Date(`${iso}T00:00:00`),today=new Date();if(Number.isNaN(birth.getTime())||birth>today)return null;let years=today.getFullYear()-birth.getFullYear(),months=today.getMonth()-birth.getMonth(),days=today.getDate()-birth.getDate();if(days<0){months--;days+=new Date(today.getFullYear(),today.getMonth(),0).getDate()}if(months<0){years--;months+=12}return {years,months,days,totalYears:years}}
function studentAgeLabel(birthDate=''){const age=studentAgeParts(birthDate);return age?`${age.years} ano(s), ${age.months} mês(es) e ${age.days} dia(s)`:'Informe a data de nascimento'}
function isStudentMinorFromForm(){const age=studentAgeParts($('#studentBirthDate')?.value||'');return Boolean(age&&age.totalYears<18)}
function updateStudentAgePreview(){const label=$('#studentAgePreview');if(label)label.textContent=studentAgeLabel($('#studentBirthDate')?.value||'');const minor=isStudentMinorFromForm(),box=$('#studentMinorNotice');if(box)box.classList.toggle('hidden',!minor);toggleFinancialResponsible()}
function repeatFinancialResponsibleFromStudent(){const copy=(from,to)=>{const source=$(`#${from}`),target=$(`#${to}`);if(source&&target)target.value=source.value};copy('studentName','studentFinancialResponsibleName');copy('studentDocument','studentFinancialResponsibleDocument');copy('studentPhone','studentFinancialResponsiblePhone');copy('studentWhatsapp','studentFinancialResponsibleWhatsapp');copy('studentEmail','studentFinancialResponsibleEmail');const relation=$('#studentFinancialResponsibleRelationship');if(relation)relation.value='Próprio aluno'}
function openNewStudent(){try{return editStudentCleanTopTabs()}catch(error){console.error('openNewStudent fallback',error);return editStudentClean()}}
function toggleFinancialResponsible(){const same=$('#studentFinancialSame')?.checked,minor=isStudentMinorFromForm();const fields=['studentFinancialResponsibleName','studentFinancialResponsibleDocument','studentFinancialResponsiblePhone','studentFinancialResponsibleWhatsapp','studentFinancialResponsibleEmail','studentFinancialResponsibleRelationship'];fields.forEach(id=>{const el=$(`#${id}`);if(el)el.disabled=Boolean(same&&!minor)});if(same&&!minor)repeatFinancialResponsibleFromStudent()}
function renderStudentsLegacy(){if(!catalogCanView())return `<div class="page"><div class="empty"><div class="emoji">🔒</div><h3>Acesso restrito</h3></div></div>`;const all=catalogSortByName(State.db.students||[]),query=State.catalogSearch?.students||'',arr=all.filter(s=>catalogMatches(s,query,`${classLabelById(s.classId)} ${teacherLabelById(s.teacherId)} ${bookLabelById(s.bookId)}`));const stats=[metricCard('Alunos',fmtNumber(all.length),'◉',0,query?`${fmtNumber(arr.length)} encontrado(s)`:'Cadastro ativo'),metricCard('Frequência média',`${fmtNumber(all.reduce((s,x)=>s+Number(x.frequency||0),0)/Math.max(1,all.length),1)}%`,'↻',0,'Base atual'),metricCard('Em atraso financeiro',fmtNumber(all.filter(x=>x.financialStatus!=='Em dia').length),'!',0,'Exige acompanhamento'),metricCard('Acompanhamentos',fmtNumber(all.filter(x=>String(x.situation).toLowerCase()!=='ativa').length),'◎',0,'Casos em atenção')].join('');const rows=arr.map(s=>`<div class="list-card"><div class="list-card-head"><div><span class="eyebrow">${escapeHTML(s.level||'Aluno')}</span><h4>${escapeHTML(s.name)}</h4><p>${escapeHTML(s.guardian||'Responsável não informado')}</p></div><span class="badge">${fmtNumber(studentCatalogScore(s))}/100</span></div><div class="list-card-meta"><span><b>Situação:</b> ${escapeHTML(s.situation||'—')}</span><span><b>Turma:</b> ${escapeHTML(classLabelById(s.classId))}</span><span><b>Professor:</b> ${escapeHTML(teacherLabelById(s.teacherId))}</span><span><b>Frequência:</b> ${fmtNumber(s.frequency||0,1)}%</span></div><div class="section-actions" style="justify-content:flex-start;margin-top:12px">${catalogCanEdit()?`<button class="btn ghost small" onclick="App.editStudent('${s.id}')">Editar</button><button class="btn soft small" onclick="App.deleteStudent('${s.id}')">Excluir</button>`:''}<button class="btn ghost small" onclick="App.openStudent('${s.id}')">Abrir</button></div></div>`).join('');return `<div class="page"><div class="section-title"><div><h2>Alunos</h2><p>Cadastro completo, histórico e acompanhamento acadêmico.</p></div>${catalogCanEdit()?'<button class="btn primary" onclick="App.openNewStudent()">Novo aluno</button>':''}</div><section class="grid cols-4" style="margin-bottom:16px">${stats}</section><div class="field"><input type="search" value="${escapeHTML(query)}" placeholder="Pesquisar por aluno, responsável, documento, turma, professor, status ou livro" oninput="App.setCatalogSearch('students',this.value)"/></div><div class="grid cols-2">${rows||'<div class="empty"><div class="emoji">◉</div><h3>Nenhum aluno encontrado</h3></div>'}</div></div>`}
function studentPhone(s){return formatPhoneBR(s.phone||s.whatsapp||s.guardianPhone||'')||'—'}
function studentWhatsApp(s){return formatPhoneBR(s.whatsapp||s.phone||s.guardianPhone||'')||studentPhone(s)}
function studentLastClass(s){const event=(s.timeline||[]).find(item=>/aula|presença|frequência/i.test(`${item.title} ${item.detail}`));return event?fmtDate(event.at):'—'}
function studentNextClass(s){const schedule=classLabelById(s.classId)==='—'?'':(State.db.classes||[]).find(x=>x.id===s.classId)?.schedule;return schedule||'—'}
function studentFilterMatches(s,filter){const situation=normalizeStudentStatus(s.situation),financial=String(s.financialStatus||'').toLowerCase(),freq=Number(s.frequency||0);if(filter==='all')return true;if(filter==='active')return situation==='Ativo';if(filter==='inactive')return situation==='Inativo';if(filter==='pending')return situation==='Matrícula em andamento'||/pend|acompanhamento/i.test(`${s.notes||''} ${s.occurrences||''}`);if(filter==='delinquent')return financial&&!financial.includes('em dia');if(filter==='birthday')return String(s.birthDate||'').slice(5,7)===String(new Date().getMonth()+1).padStart(2,'0');if(filter==='new')return (s.timeline||[]).some(item=>/matrícula|cadastro/i.test(item.title||''));if(filter==='renewal')return /rematr/i.test(`${s.notes||''} ${s.occurrences||''} ${s.situation||''}`);if(filter==='absent')return freq>0&&freq<85;if(filter==='replacement')return /reposição|reposicao/i.test(`${s.occurrences||''} ${s.notes||''}`);return true}
function setStudentFilter(filter){State.studentFilter=filter;renderPage()}
function setTeacherFilter(filter){State.teacherFilter=filter;renderPage()}
function selectedStudent(){return (State.db.students||[]).find(x=>x.id===State.selectedStudentId)||null}
function selectedStudentListItem(){return (State.db.students||[]).find(x=>x.id===State.studentListSelectedId)||null}
function openStudent(id){const s=(State.db.students||[]).find(x=>x.id===id);if(!s)return toast('Aluno não encontrado.');State.selectedStudentId=s.id;State.studentListSelectedId=s.id;State.studentTab='profile';renderPage()}
function selectStudentRow(id,rowKey=''){const same=State.studentListSelectedId===id&&State.studentListSelectedRowKey===rowKey;State.studentListSelectedId=same?'':id;State.studentListSelectedRowKey=same?'':rowKey;renderPage()}
function editSelectedStudent(){const s=selectedStudentListItem();if(!s)return toast('Selecione um aluno primeiro.');editStudentCleanTopTabs(s.id)}
function confirmDeleteSelectedStudent(){const s=selectedStudentListItem();if(!s)return toast('Selecione um aluno primeiro.');modal(`<div class="modal-head"><div><span class="eyebrow">Alunos</span><h3>Excluir aluno</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><p class="muted">Tem certeza que deseja excluir este aluno?</p><div class="section-actions"><button class="btn ghost" onclick="App.closeModal()">Cancelar</button><button class="btn danger" onclick="App.deleteSelectedStudentConfirmed()">Confirmar exclusão</button></div>`,true)}
function deleteStudent(id){const s=(State.db.students||[]).find(x=>x.id===id);if(!s)return toast('Aluno não encontrado.');State.studentListSelectedId=s.id;State.studentListSelectedRowKey='';confirmDeleteSelectedStudent()}
async function deleteSelectedStudentConfirmed(){const s=selectedStudentListItem();if(!s){closeModal();return toast('Selecione um aluno primeiro.')}const before=cloneValue(State.db.students||[]);State.db.students=(State.db.students||[]).filter(x=>x.id!==s.id);try{if(hasSupabaseClient())await deleteStudentRecord(s);else await Storage.save(State.db);State.studentListSelectedId='';if(State.selectedStudentId===s.id)State.selectedStudentId='';await logAudit('Excluiu aluno',s.name);closeModal();renderPage();toast('Aluno excluído.')}catch(error){State.db.students=before;toast(friendlyError(error,'exclusão do aluno'))}}
function closeStudentDrawer(){State.selectedStudentId='';State.studentListSelectedId='';State.studentTab='search';renderPage()}
function studentActionTarget(id=''){const student=id?(State.db.students||[]).find(x=>x.id===id):selectedStudent()||(State.db.students||[])[0];if(!student){toast('Selecione um aluno primeiro.');return null}State.selectedStudentId=student.id;return student}
function studentStatusBadge(s){const financial=String(s.financialStatus||'').toLowerCase(),situation=normalizeStudentStatus(s.situation);const cls=financial&&!financial.includes('em dia')?'rejected':['Matrícula em andamento','Trancado','Lista de espera','Prospect'].includes(situation)?'sent':['Cancelado','Inativo'].includes(situation)?'archived':'approved';return `<span class="status ${cls}">${escapeHTML(situation)}</span>`}
function studentFinancialBadge(s){const bad=String(s.financialStatus||'').toLowerCase()!=='em dia';return `<span class="status ${bad?'rejected':'approved'}">${escapeHTML(s.financialStatus||'—')}</span>`}
function renderStudentAvatar(s){return `<span class="student-avatar">${escapeHTML((s.name||'A').charAt(0))}</span>`}
function studentDrawerTimeline(s){const base=[...(s.timeline||[])];if(s.contract)base.push({at:s.updatedAt||new Date().toISOString(),title:'Contrato vinculado',detail:s.contract});if(s.financialStatus)base.push({at:s.updatedAt||new Date().toISOString(),title:'Situação financeira',detail:s.financialStatus});if(s.occurrences)base.push({at:s.updatedAt||new Date().toISOString(),title:'Ocorrência registrada',detail:s.occurrences});return catalogTimeline(base.sort((a,b)=>String(b.at||'').localeCompare(String(a.at||''))))}
function studentQuickActionLegacy(action,id=''){if(action==='new')return openNewStudent();if(action==='import')return openStudentImport();if(action==='export')return openStudentExport();const s=studentActionTarget(id);if(!s)return;if(action==='edit')return editStudent(s.id);if(action==='delete')return deleteStudent(s.id);if(action==='whatsapp'){State.whatsappConversationId=`student-${s.id}`;return openNavItem('whatsapp','','')}if(action==='classes')return openNavItem('classes','','');if(action==='agenda')return modal(`<div class="modal-head"><div><span class="eyebrow">Agenda do aluno</span><h3>${escapeHTML(s.name)}</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="kpi-strip"><span><b>Turma:</b> ${escapeHTML(classLabelById(s.classId))}</span><span><b>Próxima aula:</b> ${escapeHTML(studentNextClass(s))}</span><span><b>Professor:</b> ${escapeHTML(teacherLabelById(s.teacherId))}</span></div><div class="section-actions"><button class="btn primary" onclick="App.closeModal();App.openNavItem('classes','','')">Abrir turmas</button></div>`,true);if(action==='frequency')return modal(`<div class="modal-head"><div><span class="eyebrow">Frequência</span><h3>${escapeHTML(s.name)}</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><section class="grid cols-3"><div class="metric-card"><div class="label">Frequência atual</div><div class="value">${fmtNumber(s.frequency||0,1)}%</div><div class="note">Base cadastrada</div></div><div class="metric-card"><div class="label">Última aula</div><div class="value">${escapeHTML(studentLastClass(s))}</div><div class="note">Timeline do aluno</div></div><div class="metric-card"><div class="label">Risco</div><div class="value">${studentCatalogScore(s)<75?'Alto':'Baixo'}</div><div class="note">Score operacional</div></div></section>`,true);if(action==='financial')return modal(`<div class="modal-head"><div><span class="eyebrow">Financeiro do aluno</span><h3>${escapeHTML(s.name)}</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="alert ${String(s.financialStatus||'').toLowerCase()==='em dia'?'green':'yellow'}"><div class="alert-icon">R$</div><div><b>${escapeHTML(s.financialStatus||'—')}</b><span>Use o Centro Financeiro para lançar ou consultar títulos vinculados.</span></div></div><div class="section-actions"><button class="btn primary" onclick="App.closeModal();App.openNavItem('financial','','financeiro')">Abrir financeiro</button></div>`,true);if(action==='ia')return analyzeStudent(s.id);const titles={contacts:'Contatos',contract:'Contrato',material:'Material',occurrences:'Ocorrências',documents:'Documentos',favorite:'Favoritos',pending:'Pendências',responsible:'Responsável',history:'Histórico',certificates:'Certificados'};return modal(`<div class="modal-head"><div><span class="eyebrow">${titles[action]||'Aluno'}</span><h3>${escapeHTML(s.name)}</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div>${studentContextBlock(s,action)}<div class="section-actions"><button class="btn ghost" onclick="App.closeModal()">Fechar</button><button class="btn primary" onclick="App.closeModal();App.editStudent('${s.id}')">Editar cadastro</button></div>`,true)}
function studentContextBlock(s,action){if(action==='contacts')return `<div class="kpi-strip"><span><b>Telefone:</b> ${escapeHTML(studentPhone(s))}</span><span><b>WhatsApp:</b> ${escapeHTML(studentWhatsApp(s))}</span><span><b>Responsável:</b> ${escapeHTML(s.guardian||'—')}</span></div>`;if(action==='contract')return `<div class="form-card"><h3>Contrato</h3><p>${escapeHTML(s.contract||'Nenhum contrato informado.')}</p></div>`;if(action==='material')return `<div class="form-card"><h3>Material</h3><p>${escapeHTML(bookLabelById(s.bookId))}</p></div>`;if(action==='occurrences')return `<div class="form-card"><h3>Ocorrências</h3><p>${escapeHTML(s.occurrences||'Nenhuma ocorrência registrada.')}</p></div>`;if(action==='documents')return `<div class="form-card"><h3>Documentos</h3><p class="muted">Área preparada para organizar arquivos do aluno. Upload real será conectado ao Storage quando aprovado.</p></div>`;if(action==='favorite')return `<div class="alert green"><div class="alert-icon">⭐</div><div><b>Favorito operacional</b><span>Aluno destacado para acompanhamento rápido nesta sessão.</span></div></div>`;if(action==='pending')return `<div class="form-card"><h3>Pendências</h3><p>${escapeHTML(s.notes||s.occurrences||'Nenhuma pendência registrada.')}</p></div>`;if(action==='responsible')return `<div class="form-card"><h3>Responsável</h3><p>${escapeHTML(s.guardian||'Responsável não informado.')}</p></div>`;if(action==='history')return studentDrawerTimeline(s);if(action==='certificates')return `<div class="form-card"><h3>Certificados</h3><p class="muted">Nenhum certificado emitido para este aluno.</p></div>`;return `<p class="muted">Contexto operacional do aluno.</p>`}
function analyzeStudent(id){const s=studentActionTarget(id);if(!s)return;const score=studentCatalogScore(s),risk=score<70?'alto':score<85?'médio':'baixo',actions=[];if(Number(s.frequency||0)<85)actions.push('Agendar contato com o responsável para entender faltas.');if(String(s.financialStatus||'').toLowerCase()!=='em dia')actions.push('Vincular cobrança ao financeiro e registrar próxima data de retorno.');if(String(s.situation||'').toLowerCase()!=='ativa')actions.push('Criar plano de acompanhamento com Retenção e Pedagógico.');if(!actions.length)actions.push('Manter acompanhamento preventivo e registrar próximos marcos no histórico.');modal(`<div class="modal-head"><div><span class="eyebrow">Purple IA</span><h3>Análise do aluno</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="kpi-strip"><span><b>Aluno:</b> ${escapeHTML(s.name)}</span><span><b>Score:</b> ${score}/100</span><span><b>Risco de evasão:</b> ${risk}</span><span><b>Financeiro:</b> ${escapeHTML(s.financialStatus||'—')}</span></div><section class="form-card"><h3>Resumo</h3><p>${escapeHTML(s.evaluation||'Sem parecer acadêmico detalhado.')}</p></section><section class="form-card"><h3>Sugestões de ação</h3><ol class="purple-ia-steps">${actions.map(action=>`<li>${escapeHTML(action)}</li>`).join('')}</ol></section>`,true)}
function studentColumnAliases(){return {code:['codigo','código','matricula','matrícula','ra'],name:['nome','nome do aluno','aluno','name'],document:['cpf','documento','document'],birthDate:['data de nascimento','nascimento','birthdate'],phone:['telefone','fone','phone'],whatsapp:['whatsapp','zap','celular'],guardian:['responsável','responsavel','pai','mãe','mae','guardian'],address:['endereço','endereco','address'],city:['cidade','city'],email:['email','e-mail'],teacherName:['professor','teacher'],className:['turma','classe','class'],bookName:['livro','material','book'],level:['módulo','modulo','nível','nivel','level'],situation:['situação','situacao','status'],enrollmentDate:['data de matrícula','data de matricula','data matricula'],notes:['observações','observacoes','obs','notes']}}
function normalizeHeader(value=''){return String(value||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().trim()}
function splitDelimitedLine(line,separator=';'){const out=[];let cur='',quote=false;for(let i=0;i<line.length;i++){const ch=line[i],next=line[i+1];if(ch==='"'&&quote&&next==='"'){cur+='"';i++;continue}if(ch==='"'){quote=!quote;continue}if(ch===separator&&!quote){out.push(cur.trim());cur='';continue}cur+=ch}out.push(cur.trim());return out}
function parseDelimitedText(text=''){const clean=String(text||'').replace(/^\uFEFF/,'').trim();if(!clean)return [];const lines=clean.split(/\r?\n/).filter(Boolean),separator=(lines[0].match(/;/g)||[]).length>=(lines[0].match(/,/g)||[]).length?';':',';const headers=splitDelimitedLine(lines[0],separator);return lines.slice(1).map(line=>{const cells=splitDelimitedLine(line,separator),row={};headers.forEach((header,index)=>row[header]=cells[index]||'');return row})}
async function inflateZipEntry(bytes,method){if(method===0)return bytes;if(method!==8)throw new Error('Formato Excel não suportado.');if(!window.DecompressionStream)throw new Error('Seu navegador não possui descompactação nativa para XLSX. Salve como CSV.');const stream=new Blob([bytes]).stream().pipeThrough(new DecompressionStream('deflate-raw'));return new Uint8Array(await new Response(stream).arrayBuffer())}
function zipEntries(view){let end=-1;for(let i=view.byteLength-22;i>=0&&i>view.byteLength-66000;i--){if(view.getUint32(i,true)===0x06054b50){end=i;break}}if(end<0)throw new Error('Arquivo XLSX inválido.');let offset=view.getUint32(end+16,true),total=view.getUint16(end+10,true),entries=[];for(let n=0;n<total;n++){if(view.getUint32(offset,true)!==0x02014b50)break;const method=view.getUint16(offset+10,true),size=view.getUint32(offset+20,true),nameLen=view.getUint16(offset+28,true),extraLen=view.getUint16(offset+30,true),commentLen=view.getUint16(offset+32,true),local=view.getUint32(offset+42,true),name=new TextDecoder().decode(new Uint8Array(view.buffer,offset+46,nameLen));entries.push({name,method,size,local});offset+=46+nameLen+extraLen+commentLen}return entries}
