function xmlText(node){return Array.from(node?.getElementsByTagName('t')||[]).map(x=>x.textContent||'').join('')}
function columnIndex(ref=''){const letters=String(ref||'').match(/[A-Z]+/)?.[0]||'A';return [...letters].reduce((sum,ch)=>sum*26+ch.charCodeAt(0)-64,0)-1}
async function parseXlsxFile(file){const view=new DataView(await file.arrayBuffer()),entries=zipEntries(view),sheetEntry=entries.find(e=>/^xl\/worksheets\/sheet\d+\.xml$/.test(e.name)),sharedEntry=entries.find(e=>e.name==='xl/sharedStrings.xml');if(!sheetEntry)throw new Error('Nenhuma aba encontrada no Excel.');const parser=new DOMParser(),shared=sharedEntry?Array.from(parser.parseFromString(await readZipText(view,sharedEntry),'application/xml').getElementsByTagName('si')).map(xmlText):[],sheet=parser.parseFromString(await readZipText(view,sheetEntry),'application/xml'),rows=Array.from(sheet.getElementsByTagName('row')).map(row=>{const cells=[];Array.from(row.getElementsByTagName('c')).forEach(cell=>{const idx=columnIndex(cell.getAttribute('r')),type=cell.getAttribute('t'),valueNode=cell.getElementsByTagName('v')[0];let value=valueNode?.textContent||'';if(type==='s')value=shared[Number(value)]||'';if(type==='inlineStr')value=xmlText(cell);cells[idx]=value});return cells});const headers=(rows.shift()||[]).map(x=>String(x||'').trim());return rows.filter(row=>row.some(Boolean)).map(row=>{const out={};headers.forEach((header,index)=>{if(header)out[header]=row[index]||''});return out})}
function mapStudentImportRow(row){const aliases=studentColumnAliases(),headers=Object.keys(row),pick=key=>{const found=headers.find(header=>aliases[key].includes(normalizeHeader(header)));return found?String(row[found]||'').trim():''};return {code:pick('code'),name:pick('name'),document:pick('document'),birthDate:pick('birthDate'),phone:pick('phone'),whatsapp:pick('whatsapp'),guardian:pick('guardian'),address:pick('address'),city:pick('city'),email:pick('email'),teacherName:pick('teacherName'),className:pick('className'),bookName:pick('bookName'),level:pick('level'),situation:normalizeStudentStatus(pick('situation')),enrollmentDate:pick('enrollmentDate'),notes:pick('notes')}}
function catalogIdByName(list=[],name=''){const wanted=String(name||'').trim().toLowerCase();if(!wanted)return '';return (list||[]).find(item=>String(item.name||item.title||'').trim().toLowerCase()===wanted)?.id||''}
function importedStudentRelations(row){return {teacherId:catalogIdByName(State.db.teachers,row.teacherName),classId:catalogIdByName(State.db.classes,row.className),bookId:catalogIdByName(State.db.books,row.bookName)}}
function studentIdentity(value=''){return String(value||'').replace(/\D/g,'')}
function studentMatch(imported){const students=officialStudents();return students.find(s=>imported.document&&studentIdentity(s.document)===studentIdentity(imported.document))||students.find(s=>imported.code&&String(s.code||s.contract||'').toLowerCase()===imported.code.toLowerCase())||students.find(s=>imported.phone&&studentIdentity(studentPhone(s))===studentIdentity(imported.phone))||students.find(s=>imported.whatsapp&&studentIdentity(studentWhatsApp(s))===studentIdentity(imported.whatsapp))||students.find(s=>imported.email&&String(s.email||'').toLowerCase()===imported.email.toLowerCase())||null}
function analyzeStudentImport(rows){const mapped=rows.map(mapStudentImportRow),seenDocs=new Set(),seenCodes=new Set(),seenPhones=new Set();let empty=0,errors=[],duplicates=0,existing=0;const analyzed=mapped.map((row,index)=>{const rowErrors=[];if(!row.name)rowErrors.push('Nome vazio');if(!row.situation)row.situation='Ativo';if(!row.document&&!row.code&&!row.phone&&!row.whatsapp&&!row.email)rowErrors.push('Sem CPF, código, telefone, WhatsApp ou e-mail');const doc=studentIdentity(row.document),code=String(row.code||'').trim().toLowerCase(),phone=studentIdentity(row.whatsapp||row.phone);if(doc&&seenDocs.has(doc))rowErrors.push('CPF duplicado no arquivo');if(code&&seenCodes.has(code))rowErrors.push('Código/matrícula duplicado no arquivo');if(phone&&seenPhones.has(phone))rowErrors.push('Telefone/WhatsApp duplicado no arquivo');if(doc)seenDocs.add(doc);if(code)seenCodes.add(code);if(phone)seenPhones.add(phone);const match=studentMatch(row);if(match)existing++;if(rowErrors.length){empty++;errors.push(`Linha ${index+2}: ${rowErrors.join(', ')}`)}if(rowErrors.some(e=>/duplicado/.test(e)))duplicates++;return {...row,matchId:match?.id||'',matchName:match?.name||'',errors:rowErrors}});return {rows:analyzed,total:analyzed.length,newCount:analyzed.filter(r=>!r.matchId).length,existingCount:existing,duplicateCount:duplicates,emptyCount:empty,errors}}
function openStudentImport(){if(!catalogCanEdit())return toast('Importação não autorizada.');State.studentImportPreview=null;modal(`<div class="modal-head"><div><span class="eyebrow">Importar Alunos</span><h3>Importação com pré-visualização</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><p class="muted">Importe CSV ou Excel (.xlsx). A primeira aba será lida, pré-validada e gravada somente após confirmação.</p><div class="field"><label>Arquivo</label><input id="studentImportFile" type="file" accept=".csv,.txt,.xlsx" onchange="App.previewStudentImport(this.files[0])"/><small>Colunas reconhecidas automaticamente: Nome, CPF, nascimento, telefone, WhatsApp, responsável, endereço, cidade, e-mail, professor, turma, livro, módulo, situação, matrícula e observações.</small></div><div id="studentImportPreview"></div>`,true)}
function renderStudentImportPreview(){const preview=State.studentImportPreview,target=$('#studentImportPreview');if(!preview||!target)return;target.innerHTML=`<section class="grid cols-4 import-summary"><div class="metric-card"><div class="label">Registros</div><div class="value">${fmtNumber(preview.total)}</div><div class="note">Linhas lidas</div></div><div class="metric-card"><div class="label">Novos</div><div class="value">${fmtNumber(preview.newCount)}</div><div class="note">Sem correspondência</div></div><div class="metric-card"><div class="label">Existentes</div><div class="value">${fmtNumber(preview.existingCount)}</div><div class="note">Encontrados na base</div></div><div class="metric-card"><div class="label">Alertas</div><div class="value">${fmtNumber(preview.errors.length)}</div><div class="note">Campos vazios/duplicidades</div></div></section>${preview.errors.length?`<div class="alert yellow"><div class="alert-icon">!</div><div><b>Revisar antes de importar</b><span>${escapeHTML(preview.errors.slice(0,4).join(' • '))}${preview.errors.length>4?'...':''}</span></div></div>`:''}<div class="form-grid cols-2"><div class="field"><label>Quando aluno já existir</label><select id="studentImportMode"><option value="ignore">Ignorar</option><option value="fill">Atualizar apenas campos vazios</option><option value="update">Atualizar cadastro</option><option value="overwrite">Sobrescrever todas as informações</option></select></div><div class="field"><label>Confirmar gravação</label><button class="btn primary full" onclick="App.confirmStudentImport(this)">Importar para a base oficial</button></div></div><div class="table-wrap"><table><thead><tr><th>Nome</th><th>CPF</th><th>WhatsApp</th><th>Status</th><th>Resultado</th></tr></thead><tbody>${preview.rows.slice(0,8).map(row=>`<tr><td>${escapeHTML(row.name||'—')}</td><td>${escapeHTML(row.document||'—')}</td><td>${escapeHTML(row.whatsapp||row.phone||'—')}</td><td>${escapeHTML(row.situation||'Ativo')}</td><td>${row.errors.length?escapeHTML(row.errors.join(', ')):(row.matchId?`Existente: ${escapeHTML(row.matchName)}`:'Novo aluno')}</td></tr>`).join('')}</tbody></table></div>`}
async function previewStudentImport(file){if(!file)return;const ext=file.name.split('.').pop().toLowerCase();try{const rows=ext==='xlsx'?await parseXlsxFile(file):parseDelimitedText(await file.text());State.studentImportPreview=analyzeStudentImport(rows);renderStudentImportPreview()}catch(error){State.studentImportPreview={rows:[],total:0,newCount:0,existingCount:0,duplicateCount:0,emptyCount:0,errors:[friendlyError(error,'leitura do arquivo')]};renderStudentImportPreview()}}
async function confirmStudentImport(button=null){const preview=State.studentImportPreview;if(!preview?.rows?.length)return toast('Nenhum registro válido para importar.');const mode=$('#studentImportMode')?.value||'ignore',before=cloneValue(State.db.students||[]),now=new Date().toISOString();let created=0,updated=0,ignored=0;button&&(button.disabled=true);try{for(const row of preview.rows){if(row.errors.length){ignored++;continue}const relations=importedStudentRelations(row);let target=row.matchId?(State.db.students||[]).find(s=>s.id===row.matchId):null;if(target){if(mode==='ignore'){ignored++;continue}const prior=normalizeStudentStatus(target.situation),patch={code:row.code,name:row.name,document:row.document,birthDate:row.birthDate,phone:row.phone,whatsapp:row.whatsapp,guardian:row.guardian,address:row.address,city:row.city,email:row.email,teacherId:relations.teacherId,classId:relations.classId,bookId:relations.bookId,level:row.level,situation:row.situation,notes:row.notes,enrollmentDate:row.enrollmentDate};Object.entries(patch).forEach(([key,value])=>{if(mode==='overwrite'||(mode==='update'&&value)||(mode==='fill'&&!target[key]&&value))target[key]=value});const next=normalizeStudentStatus(target.situation);target.timeline=target.timeline||[];if(prior!==next)target.timeline.unshift({at:now,title:'Status alterado por importação',detail:`${prior} → ${next} • ${State.user.name}`});target.updatedAt=now;updated++;continue}State.db.students.unshift({id:uid('stu'),code:row.code,name:row.name,document:row.document,birthDate:row.birthDate,phone:row.phone,whatsapp:row.whatsapp,guardian:row.guardian,address:row.address,city:row.city,email:row.email,teacherId:relations.teacherId,classId:relations.classId,bookId:relations.bookId,level:row.level,situation:row.situation||'Ativo',financialStatus:'Em dia',frequency:0,evaluation:'',occurrences:'',notes:row.notes,enrollmentDate:row.enrollmentDate,timeline:[{at:now,title:'Aluno importado',detail:`Cadastro criado por ${State.user.name}.`}],updatedAt:now});created++}await Storage.save(State.db);await logAudit('Importou alunos',`${created} novos • ${updated} atualizados • ${ignored} ignorados`);State.studentImportPreview=null;closeModal();renderPage();toast('Importação concluída. Base oficial atualizada.')}catch(error){State.db.students=before;toast(friendlyError(error,'importação de alunos'))}finally{button&&(button.disabled=false)}}
function studentsForExport(scope='filtered'){const all=officialStudents(),query=State.catalogSearch?.students||'',filter=State.studentFilter||'all';return scope==='all'?all:all.filter(s=>catalogMatches(s,query,`${studentPhone(s)} ${studentWhatsApp(s)} ${s.guardian||''} ${s.document||''} ${s.code||''} ${s.contract||''} ${s.email||''} ${classLabelById(s.classId)} ${teacherLabelById(s.teacherId)} ${bookLabelById(s.bookId)}`)).filter(s=>studentFilterMatches(s,filter))}
