async function saveStudentEnrollment(id){if(!catalogCanEdit())return toast('Operação não autorizada.');const s=(State.db.students||[]).find(x=>x.id===id);if(!s)return toast('Aluno não encontrado.');const before=cloneValue(s),beforeFinancial=cloneValue(State.db.financialEntries||[]),monthly=Number($('#enrollmentMonthlyValue').value||0),installments=Math.max(1,Number($('#enrollmentInstallments').value||1));if(monthly<0)return toast('Valor não pode ser negativo.');Object.assign(s,{coursePackage:$('#enrollmentPackage').value.trim(),coursePlan:$('#enrollmentPlan').value,courseType:$('#enrollmentType').value,courseMonthlyValue:monthly,courseInstallments:installments,courseFirstDueDate:$('#enrollmentFirstDueDate').value,courseStartDate:$('#enrollmentStartDate').value,courseEndDate:$('#enrollmentEndDate').value,situation:normalizeStudentStatus($('#enrollmentSituation').value),classId:$('#enrollmentClass').value||'',teacherId:$('#enrollmentTeacher').value||'',bookId:$('#enrollmentBook').value||'',courseNotes:$('#enrollmentNotes').value.trim(),contract:studentCourseContractNumber(s),updatedAt:new Date().toISOString()});s.timeline=s.timeline||[];s.timeline.unshift({at:new Date().toISOString(),title:'Matrícula atualizada',detail:`${s.coursePackage||'Pacote'} • ${fmtMoney(monthly)} • ${installments} parcela(s)`});try{if($('#enrollmentCreateInstallments')?.checked)createStudentInstallments(s,monthly,installments,$('#enrollmentFirstDueDate').value,false);await Storage.save(State.db);await logAudit('Atualizou matrícula do aluno',`${s.name} • ${s.coursePackage}`);closeModal();toast('Matrícula salva.');renderPage()}catch(error){restoreRecord(s,before);State.db.financialEntries=beforeFinancial;toast(friendlyError(error,'matrícula do aluno'))}}
function createStudentInstallments(s,monthly=Number(s.courseMonthlyValue||0),installments=Number(s.courseInstallments||12),firstDue=s.courseFirstDueDate||todayISO(),replace=false){State.db.financialEntries=State.db.financialEntries||[];const contract=studentCourseContractNumber(s);if(replace)State.db.financialEntries=State.db.financialEntries.filter(x=>!(x.contract===contract&&x.studentId===s.id&&x.category==='Mensalidade'));for(let i=0;i<installments;i++){State.db.financialEntries.push({id:uid('fin'),type:'receivable',person:s.name,student:s.name,studentId:s.id,contract,description:`Mensalidade ${String(i+1).padStart(2,'0')}/${String(installments).padStart(2,'0')} • ${s.coursePackage||'Curso Purple'}`,category:'Mensalidade',competence:addMonthsISO(firstDue,i).slice(0,7),dueDate:addMonthsISO(firstDue,i),amount:monthly,paidAmount:0,paymentMethod:'A definir',account:'Caixa / Banco',status:'open',owner:State.user.name,notes:'Parcela gerada pela matrícula do aluno.',active:true,createdAt:new Date().toISOString(),updatedAt:new Date().toISOString()})}}
