function followUpTimeFromAt(at=''){const raw=String(at||'');if(raw.includes('T'))return raw.slice(11,16);return ''}
function studentFollowUpLegacyEntry(item,index){const title=String(item.title||'Follow-up'),detail=String(item.detail||''),type=(title.split('—')[1]||title).trim()||'Follow-up',nextMatch=detail.match(/Próximo retorno:\s*([^•]+)/i);return {id:`legacy-${index}`,legacy:true,at:item.at||new Date().toISOString(),contactDate:String(item.at||'').slice(0,10)||todayISO(),contactTime:followUpTimeFromAt(item.at),nextDate:nextMatch?nextMatch[1].trim():'',nextTime:'',employee:item.actor||State.user?.name||'—',type,result:/sem resposta/i.test(detail)?'Sem resposta':/pendente/i.test(detail)?'Pendente':'Contato realizado',subject:detail||title,done:!/pendente|sem resposta|retornar/i.test(detail),title,detail}}
function studentFollowUpItems(s){const saved=(Array.isArray(s.followUpEntries)?s.followUpEntries:[]).map(row=>({...row,at:row.at||row.createdAt||row.contactDate||new Date().toISOString()}));const timeline=(s.timeline||[]).filter(item=>/follow|contato|whatsapp|ligação|ligacao|email|e-mail|ocorrência|ocorrencia|retorno/i.test(`${item.title||''} ${item.detail||''}`)).map(studentFollowUpLegacyEntry);const extra=[];if(s.occurrences)extra.push({id:'occurrences',legacy:true,at:s.updatedAt||new Date().toISOString(),contactDate:String(s.updatedAt||'').slice(0,10)||'',contactTime:followUpTimeFromAt(s.updatedAt),nextDate:'',nextTime:'',employee:'—',type:'Ocorrência',result:'Registrado',subject:s.occurrences,done:true,title:'Ocorrência registrada',detail:s.occurrences});if(s.notes)extra.push({id:'notes',legacy:true,at:s.updatedAt||new Date().toISOString(),contactDate:String(s.updatedAt||'').slice(0,10)||'',contactTime:followUpTimeFromAt(s.updatedAt),nextDate:'',nextTime:'',employee:'—',type:'Observação',result:'Registrado',subject:s.notes,done:true,title:'Observação do atendimento',detail:s.notes});return [...saved,...timeline,...extra].sort((a,b)=>String(b.at||'').localeCompare(String(a.at||'')))}
function studentFollowUpContent(s){const items=studentFollowUpItems(s);return `<div class="student-followup-panel"><section class="form-card student-followup-form"><h3>Novo follow-up</h3><p class="muted">Registre o contato feito com aluno ou responsável. Depois, clique no histórico para abrir a caixa com todos os detalhes.</p><div class="form-grid cols-4"><div class="field"><label>Data do contato</label><input id="studentFollowupDate" type="date" value="${todayISO()}"/></div><div class="field"><label>Horário</label><input id="studentFollowupTime" type="time" value="${new Date().toTimeString().slice(0,5)}"/></div><div class="field"><label>Próximo contato</label><input id="studentFollowupNext" type="date"/></div><div class="field"><label>Horário</label><input id="studentFollowupNextTime" type="time"/></div><div class="field wide"><label>Nome do funcionário</label><input id="studentFollowupEmployee" value="${escapeHTML(State.user?.name||'')}"/></div><div class="field"><label>Tipo de follow-up</label><select id="studentFollowupType"><option value="">Selecione</option><option>Pedagógico</option><option>Financeiro</option><option>Retenção</option><option>WhatsApp</option><option>Ligação</option><option>E-mail</option><option>Presencial</option><option>Ocorrência</option></select></div><div class="field"><label>Efetuado</label><select id="studentFollowupDone"><option value="true">Sim</option><option value="false">Não</option></select></div><div class="field"><label>Resultado</label><select id="studentFollowupResult"><option value="">Selecione</option><option>Contato realizado</option><option>Sem resposta</option><option>Retornar depois</option><option>Resolvido</option><option>Pendente</option><option>Encaminhado</option></select></div></div><div class="field"><label>Assunto</label><textarea id="studentFollowupNote" placeholder="Descreva o contato, combinado, orientação, pendência ou próximo passo."></textarea></div><div class="section-actions" style="justify-content:flex-start"><button class="btn primary small" onclick="App.saveStudentFollowUp('${s.id}')">Registrar follow-up</button><button class="btn ghost small" onclick="App.studentQuickAction('contacts','${s.id}')">Ver contatos</button></div></section><section class="form-card student-followup-history"><div class="panel-head"><div><h3>Histórico de follow-up</h3><small>Clique em uma linha para abrir os detalhes.</small></div><span class="status review">${fmtNumber(items.length)} contato(s)</span></div><div class="table-wrap student-followup-table"><table><thead><tr><th>Data</th><th>Horário</th><th>Atendente</th><th>Tipo</th><th>Resultado</th><th>Próximo contato</th><th>Efetuado</th></tr></thead><tbody>${items.map(item=>`<tr onclick="App.openStudentFollowUpDetail('${s.id}','${item.id}')"><td>${fmtDate(item.contactDate||item.at)}</td><td>${escapeHTML(item.contactTime||followUpTimeFromAt(item.at)||'—')}</td><td>${escapeHTML(item.employee||'—')}</td><td>${escapeHTML(item.type||'Follow-up')}</td><td>${escapeHTML(item.result||'—')}</td><td>${item.nextDate?`${escapeHTML(fmtDate(item.nextDate))}${item.nextTime?` ${escapeHTML(item.nextTime)}`:''}`:'—'}</td><td><span class="status ${item.done===false?'draft':'approved'}">${item.done===false?'Não':'Sim'}</span></td></tr>`).join('')||'<tr><td colspan="7"><div class="empty"><p>Nenhum contato ou ocorrência registrada para este aluno.</p></div></td></tr>'}</tbody></table></div></section></div>`}
function openStudentFollowUpDetail(id,itemId){const s=(State.db.students||[]).find(x=>x.id===id);if(!s)return toast('Aluno não encontrado.');const item=studentFollowUpItems(s).find(x=>x.id===itemId);if(!item)return toast('Follow-up não encontrado.');modal(`<div class="modal-head"><div><span class="eyebrow">Follow-up</span><h3>Detalhes do contato</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="followup-detail-box"><div class="form-grid cols-4"><div class="field"><label>Data do contato</label><input value="${escapeHTML(fmtDate(item.contactDate||item.at))}" disabled/></div><div class="field"><label>Horário</label><input value="${escapeHTML(item.contactTime||followUpTimeFromAt(item.at)||'—')}" disabled/></div><div class="field"><label>Próximo contato</label><input value="${escapeHTML(item.nextDate?fmtDate(item.nextDate):'—')}" disabled/></div><div class="field"><label>Horário</label><input value="${escapeHTML(item.nextTime||'—')}" disabled/></div></div><div class="form-grid cols-2"><div class="field"><label>Nome do funcionário</label><input value="${escapeHTML(item.employee||'—')}" disabled/></div><div class="field"><label>Tipo de follow-up</label><input value="${escapeHTML(item.type||'Follow-up')}" disabled/></div></div><div class="field"><label>Assunto</label><textarea class="large" disabled>${escapeHTML(item.subject||item.detail||'')}</textarea></div><div class="followup-done-box"><b>Efetuado</b><label><input type="radio" ${item.done!==false?'checked':''} disabled/> Sim</label><label><input type="radio" ${item.done===false?'checked':''} disabled/> Não</label></div></div><div class="section-actions"><button class="btn primary" onclick="App.closeModal()">Sair</button></div>`,true)}
async function saveStudentFollowUp(id){const s=(State.db.students||[]).find(x=>x.id===id);if(!s)return toast('Aluno não encontrado.');const type=$('#studentFollowupType')?.value||'Follow-up',result=$('#studentFollowupResult')?.value||'Contato realizado',next=$('#studentFollowupNext')?.value||'',note=$('#studentFollowupNote')?.value.trim()||'';const before=cloneValue(s),entry={id:uid('fup'),at:new Date().toISOString(),contactDate:$('#studentFollowupDate')?.value||todayISO(),contactTime:$('#studentFollowupTime')?.value||new Date().toTimeString().slice(0,5),nextDate:next,nextTime:$('#studentFollowupNextTime')?.value||'',employee:$('#studentFollowupEmployee')?.value.trim()||State.user?.name||'Usuário do sistema',type,result,subject:note||'Contato registrado no prontuário do aluno.',done:$('#studentFollowupDone')?.value!=='false'};s.followUpEntries=Array.isArray(s.followUpEntries)?s.followUpEntries:[];s.followUpEntries.unshift(entry);s.timeline=s.timeline||[];s.timeline.unshift({at:new Date().toISOString(),title:`Follow-up — ${type}`,detail:[`Resultado: ${result}`,entry.nextDate?`Próximo contato: ${fmtDate(entry.nextDate)}${entry.nextTime?` ${entry.nextTime}`:''}`:'',entry.subject].filter(Boolean).join(' • ')});s.updatedAt=new Date().toISOString();try{await Storage.save(State.db);await logAudit('Registrou follow-up',`${s.name} • ${type} • ${result}`);toast('Follow-up registrado.');renderPage()}catch(error){console.error('Purple Gestão — erro ao salvar follow-up:',error);restoreRecord(s,before);toast(friendlyError(error,'registro de follow-up'))}}
function studentDetailContent(s){if(!s)return `<div class="student-detail-empty"><div class="emoji">◉</div><h3>Selecione um aluno na listagem</h3><p>Depois de selecionar, use as abas para consultar cadastro, cursos, pagamentos, horários, frequência, notas, contatos e dados da matrícula sem sair desta tela.</p></div>`;const tab=State.studentTab||'profile',moneyRows=studentMoneyRows(s);if(tab==='search')return `<div class="student-detail-grid"><div class="form-card"><h3>Resultado selecionado</h3><div class="kpi-strip"><span><b>Código:</b> ${escapeHTML(s.code||s.contract||s.document||'—')}</span><span><b>Aluno:</b> ${escapeHTML(s.name)}</span><span><b>Status:</b> ${escapeHTML(normalizeStudentStatus(s.situation))}</span></div><p class="muted">Use os filtros acima para localizar rapidamente por nome, código, responsável, WhatsApp, turma ou situação.</p></div>${studentDrawerTimeline(s)}</div>`;if(tab==='profile')return `<div class="student-detail-grid"><div class="form-card"><h3>Cadastro do aluno</h3><div class="form-grid cols-3"><div class="field"><label>Código</label><input value="${escapeHTML(s.code||s.contract||'')}" disabled/></div><div class="field"><label>Nome</label><input value="${escapeHTML(s.name||'')}" disabled/></div><div class="field"><label>CPF / Documento</label><input value="${escapeHTML(s.document||'')}" disabled/></div><div class="field"><label>Data de nascimento</label><input value="${escapeHTML(s.birthDate||'')}" disabled/></div><div class="field"><label>Cidade</label><input value="${escapeHTML(s.city||'')}" disabled/></div><div class="field"><label>Situação</label><input value="${escapeHTML(normalizeStudentStatus(s.situation))}" disabled/></div></div><div class="section-actions"><button class="btn primary small" onclick="App.editStudent('${s.id}')">Alterar cadastro</button></div></div><div class="form-card"><h3>Observações</h3><p class="muted">${escapeHTML(s.notes||'Nenhuma observação registrada.')}</p></div></div>`;if(tab==='courses')return `<div class="student-detail-grid"><div class="form-card"><h3>Cursos e turma</h3><div class="kpi-strip"><span><b>Turma:</b> ${escapeHTML(classLabelById(s.classId))}</span><span><b>Professor:</b> ${escapeHTML(teacherLabelById(s.teacherId))}</span><span><b>Livro:</b> ${escapeHTML(bookLabelById(s.bookId))}</span><span><b>Módulo:</b> ${escapeHTML(s.level||'—')}</span></div><div class="section-actions"><button class="btn ghost small" onclick="App.openNavItem('classes','','')">Abrir turmas</button></div></div><div class="form-card"><h3>Material</h3><p class="muted">${escapeHTML(bookLabelById(s.bookId))}</p></div></div>`;if(tab==='payments')return `<div class="student-detail-grid"><div class="form-card"><h3>Financeiro do aluno</h3><div class="alert ${String(s.financialStatus||'').toLowerCase()==='em dia'?'green':'yellow'}"><div class="alert-icon">R$</div><div><b>${escapeHTML(s.financialStatus||'—')}</b><span>Situação financeira registrada na base oficial.</span></div></div><div class="section-actions"><button class="btn primary small" onclick="App.openNavItem('financial','','financeiro')">Abrir centro financeiro</button></div></div><div class="table-wrap"><table><thead><tr><th>Descrição</th><th>Valor</th><th>Status</th><th>Vencimento</th></tr></thead><tbody>${moneyRows.map(x=>`<tr><td>${escapeHTML(x.description||'Lançamento')}</td><td>${fmtMoney(x.amount||x.value||0)}</td><td>${escapeHTML(x.status||'—')}</td><td>${fmtDate(x.dueDate||x.date||x.createdAt)}</td></tr>`).join('')||'<tr><td colspan="4">Nenhum lançamento financeiro vinculado nominalmente a este aluno.</td></tr>'}</tbody></table></div></div>`;if(tab==='schedule')return `<div class="student-detail-grid"><div class="form-card"><h3>Horários</h3><div class="kpi-strip"><span><b>Horário da turma:</b> ${escapeHTML(studentNextClass(s))}</span><span><b>Última aula:</b> ${escapeHTML(studentLastClass(s))}</span><span><b>Professor:</b> ${escapeHTML(teacherLabelById(s.teacherId))}</span></div></div><div class="form-card"><h3>Agenda rápida</h3><p class="muted">Reposições, aulas e compromissos do aluno ficam centralizados aqui conforme os vínculos forem cadastrados.</p></div></div>`;if(tab==='frequency')return `<div class="student-detail-grid"><section class="grid cols-3">${metricCard('Frequência atual',`${fmtNumber(s.frequency||0,1)}%`,'◫',0,'Base do cadastro')}${metricCard('Última aula',studentLastClass(s),'◴',0,'Histórico do aluno')}${metricCard('Risco operacional',studentCatalogScore(s)<75?'Alto':'Baixo','!',0,`${studentCatalogScore(s)}/100`)}</section><div class="form-card"><h3>Controle de frequência</h3><p class="muted">${Number(s.frequency||0)<85?'Aluno abaixo do nível ideal de presença. Recomenda-se contato ativo.':'Frequência dentro do esperado.'}</p></div></div>`;if(tab==='grades')return `<div class="student-detail-grid"><div class="form-card"><h3>Notas e parecer</h3><div class="kpi-strip"><span><b>Score:</b> ${studentCatalogScore(s)}/100</span><span><b>Frequência:</b> ${fmtNumber(s.frequency||0,1)}%</span><span><b>Situação:</b> ${escapeHTML(normalizeStudentStatus(s.situation))}</span></div><p class="muted" style="margin-top:12px">${escapeHTML(s.evaluation||'Sem notas ou parecer acadêmico registrado.')}</p></div><div class="form-card"><h3>Ocorrências</h3><p class="muted">${escapeHTML(s.occurrences||'Nenhuma ocorrência registrada.')}</p></div></div>`;if(tab==='contacts')return `<div class="student-detail-grid"><div class="form-card"><h3>Contatos</h3><div class="form-grid cols-2"><div class="field"><label>Telefone</label><input value="${escapeHTML(studentPhone(s))}" disabled/></div><div class="field"><label>WhatsApp</label><input value="${escapeHTML(studentWhatsApp(s))}" disabled/></div><div class="field"><label>E-mail</label><input value="${escapeHTML(s.email||'')}" disabled/></div><div class="field"><label>Responsável</label><input value="${escapeHTML(s.guardian||'')}" disabled/></div></div><div class="section-actions"><button class="btn primary small" onclick="App.studentQuickAction('whatsapp','${s.id}')">Abrir WhatsApp</button></div></div><div class="form-card"><h3>Endereço</h3><p class="muted">${escapeHTML([s.address,s.city].filter(Boolean).join(' • ')||'Endereço não informado.')}</p></div></div>`;if(tab==='enrollment')return `<div class="student-detail-grid"><div class="form-card"><h3>Dados da matrícula</h3><div class="kpi-strip"><span><b>Contrato:</b> ${escapeHTML(s.contract||'—')}</span><span><b>Matrícula:</b> ${fmtDate(s.enrollmentDate)}</span><span><b>Status:</b> ${escapeHTML(normalizeStudentStatus(s.situation))}</span><span><b>Financeiro:</b> ${escapeHTML(s.financialStatus||'—')}</span></div></div>${studentDrawerTimeline(s)}</div>`;return `<p class="muted">Selecione uma aba.</p>`}
function studentQuickAction(action,id=''){if(action==='new')return openNewStudent();if(action==='import')return openStudentImport();if(action==='export')return openStudentExport();const s=studentActionTarget(id);if(!s)return;if(action==='edit')return editStudentCleanTopTabs(s.id);if(action==='delete')return deleteStudent(s.id);const map={search:'search',profile:'profile',classes:'courses',material:'courses',financial:'payments',agenda:'schedule',frequency:'frequency',occurrences:'grades',documents:'contacts',contacts:'contacts',responsible:'contacts',contract:'courses',history:'contacts',pending:'contacts',followup:'contacts',more:'profile',certificates:'courses',favorite:'profile',whatsapp:'contacts'};if(map[action]){State.studentTab=map[action];return renderPage()}if(action==='ia')return analyzeStudent(s.id);return renderPage()}
function openStudentActions(id){const s=(State.db.students||[]).find(x=>x.id===id);if(!s)return toast('Aluno não encontrado.');modal(`<div class="modal-head"><div><span class="eyebrow">Ações do aluno</span><h3>${escapeHTML(s.name)}</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="student-actions-menu"><button onclick="App.closeModal();App.openStudent('${s.id}')">Abrir prontuário</button><button onclick="App.closeModal();App.editStudent('${s.id}')">Editar cadastro</button><button onclick="App.closeModal();App.setStudentTab('courses');App.openStudent('${s.id}')">Cursos / Matrícula</button><button onclick="App.closeModal();App.setStudentTab('payments');App.openStudent('${s.id}')">Financeiro</button><button onclick="App.closeModal();App.setStudentTab('contacts');App.openStudent('${s.id}')">Follow-up / Contatos</button><button onclick="App.closeModal();App.setStudentTab('schedule');App.openStudent('${s.id}')">Horários</button><button onclick="App.closeModal();App.setStudentTab('frequency');App.openStudent('${s.id}')">Frequência</button><button onclick="App.closeModal();App.setStudentTab('grades');App.openStudent('${s.id}')">Notas</button><button class="danger" onclick="App.closeModal();App.deleteStudent('${s.id}')">Excluir cadastro do aluno</button></div>`,true)}
function renderStudentDrawer(s){return `<section class="student-erp-detail"><div class="student-detail-head"><div>${s?`${renderStudentAvatar(s)}<div><span class="eyebrow">Aluno selecionado</span><h3>${escapeHTML(s.name)}</h3><small>${escapeHTML([s.code||s.contract||s.document,studentWhatsApp(s)].filter(Boolean).join(' • '))}</small></div>`:'<div><span class="eyebrow">Aluno selecionado</span><h3>Nenhum aluno selecionado</h3><small>Clique em uma linha da listagem.</small></div>'}</div>${s?`<button class="btn ghost small" onclick="App.closeStudentDrawer()">Limpar seleção</button>`:''}</div><div class="student-detail-tabs">${[['search','Procura'],['profile','Cadastro'],['courses','Cursos'],['payments','Pagamentos'],['schedule','Horários'],['frequency','Controle de Frequência'],['grades','Notas'],['contacts','Contatos'],['enrollment','Dados da Matrícula']].map(([tab,label])=>studentTabButton(tab,label)).join('')}</div><div class="student-detail-body">${studentDetailContent(s)}</div></section>`}
function renderStudents(){if(!catalogCanView())return `<div class="page"><div class="empty"><div class="emoji">🔒</div><h3>Acesso restrito</h3></div></div>`;const all=catalogSortByName(State.db.students||[]),query=State.catalogSearch?.students||'',filter=State.studentFilter||'all',official=officialStudentCounts(),arr=all.filter(s=>catalogMatches(s,query,`${studentPhone(s)} ${studentWhatsApp(s)} ${s.guardian||''} ${s.document||''} ${s.code||''} ${s.contract||''} ${s.email||''} ${classLabelById(s.classId)} ${teacherLabelById(s.teacherId)} ${bookLabelById(s.bookId)}`)).filter(s=>studentFilterMatches(s,filter)),selected=selectedStudent();const filters=[['all','Todos'],['active','Ativos'],['inactive','Inativos'],['pending','Pendentes'],['delinquent','Inadimplentes'],['birthday','Aniversariantes'],['new','Novos'],['renewal','Rematrícula'],['absent','Faltosos'],['replacement','Reposição']];const rows=arr.map(s=>`<tr class="${selected?.id===s.id?'selected':''}" onclick="App.openStudent('${s.id}')"><td class="student-code">${escapeHTML(s.code||s.contract||s.document||'—')}</td><td><b>${escapeHTML(s.name)}</b></td><td>${escapeHTML(s.socialName||'')}</td><td>${escapeHTML(studentPhone(s))}</td><td>${escapeHTML(studentWhatsApp(s))}</td><td>${escapeHTML(s.city||'—')}</td><td>${escapeHTML(s.guardian||'—')}</td><td>${studentStatusBadge(s)}</td><td>${escapeHTML(s.document||'—')}</td><td class="student-row-actions"><button type="button" class="student-kebab" title="Ações do aluno" onclick="event.stopPropagation();App.openStudentActions('${s.id}')">⋯</button></td></tr>`).join('');const cards=arr.map(s=>`<button class="student-mobile-card ${selected?.id===s.id?'selected':''}" onclick="App.openStudent('${s.id}')"><div>${renderStudentAvatar(s)}<span><b>${escapeHTML(s.name)}</b><small>${escapeHTML(s.guardian||'Responsável não informado')}</small></span><button type="button" class="student-kebab" title="Ações do aluno" onclick="event.stopPropagation();App.openStudentActions('${s.id}')">⋯</button></div><div class="student-mobile-meta"><span>${escapeHTML(classLabelById(s.classId))}</span><span>${fmtNumber(s.frequency||0,1)}%</span><span>${escapeHTML(normalizeStudentStatus(s.situation))}</span></div></button>`).join('');return `<div class="page students-center-page student-erp-page"><div class="student-erp-shell"><aside class="student-erp-side"><div class="student-side-title">${appIcon('◉')}<b>Alunos</b></div>${studentSideButton('new','✚','Novo Aluno',true)}${studentSideButton('edit','✎','Alterar Aluno')}${studentSideButton('delete','🗑','Excluir Aluno')}${studentSideButton('pending','◇','Novo Follow-up')}${studentSideButton('occurrences','!','Anotações')}${studentSideButton('occurrences','!','Ocorrências')}${studentSideButton('whatsapp','☏','WhatsApp Web')}${studentSideButton('documents','☰','Documentos')}${studentSideButton('profile','▧','Ficha de Cadastro')}${studentSideButton('export','↗','Mais Opções')}</aside><main class="student-erp-main"><div class="student-erp-ribbon">${studentActionButton('profile','◉','Alunos',true)}${studentActionButton('classes','▤','Grade de Horários')}${studentActionButton('frequency','✓','Marcar Presença')}${studentActionButton('whatsapp','☏','WhatsApp')}${studentActionButton('financial','R$','Recebimento')}${studentActionButton('pending','◇','Follow-up')}${studentActionButton('occurrences','!','Ocorrências')}${studentActionButton('export','↗','Relatórios Personalizados')}${studentActionButton('import','↙','Importar')}</div><div class="student-erp-tabs">${[['search','Procura'],['profile','Cadastro'],['courses','Cursos'],['payments','Pagamentos'],['schedule','Horários'],['frequency','Controle de Frequência'],['grades','Notas'],['contacts','Contatos'],['enrollment','Dados da Matrícula']].map(([tab,label])=>studentTabButton(tab,label)).join('')}</div><section class="student-erp-filters"><div class="field"><label>Procurar</label><input type="search" value="${escapeHTML(query)}" placeholder="Código, nome do aluno, responsável, WhatsApp, CPF ou e-mail" oninput="App.setCatalogSearch('students',this.value)"/></div><div class="field"><label>Ordenar por</label><select onchange="App.setCatalogSearch('students',document.querySelector('.student-erp-filters input').value)"><option>Código</option><option>Nome do Aluno</option><option>Situação</option></select></div><div class="field"><label>Filtrar por</label><select onchange="App.setStudentFilter(this.value)">${filters.map(([key,label])=>`<option value="${key}" ${filter===key?'selected':''}>${label}</option>`).join('')}</select></div><div class="student-filter-chips">${filters.map(([key,label])=>`<button class="${filter===key?'active':''}" onclick="App.setStudentFilter('${key}')">${label}</button>`).join('')}</div></section><section class="grid cols-4 student-kpis">${metricCard('Alunos ativos',fmtNumber(official.active),'◉',0,'Status = Ativo')}${metricCard('Matrículas em andamento',fmtNumber(official.inProgress),'✚',0,'Status oficial')}${metricCard('Inativos / trancados',fmtNumber(official.inactive+official.locked),'◷',0,'Base oficial')}${metricCard('Cancelados',fmtNumber(official.cancelled),'!',0,'Status = Cancelado')}</section><section class="student-erp-table-panel"><div class="table-wrap students-table"><table><thead><tr><th>Código</th><th>Nome do Aluno</th><th>Nome Social</th><th>Telefone</th><th>WhatsApp</th><th>Cidade</th><th>Responsável</th><th>Situação</th><th>RA</th><th>Ações</th></tr></thead><tbody>${rows||'<tr><td colspan="10"><div class="empty"><div class="emoji">◉</div><h3>Nenhum aluno encontrado</h3></div></td></tr>'}</tbody></table></div><div class="student-mobile-list">${cards||'<div class="empty"><h3>Nenhum aluno encontrado</h3></div>'}</div><div class="student-erp-footer"><span>Nº de Alunos: ${fmtNumber(arr.length)}</span><span>Base oficial Purple Gestão</span></div></section>${renderStudentDrawer(selected)}</main></div></div>`}

function studentDetailContentNext(s){
  if(!s)return `<div class="student-detail-empty"><div class="emoji">◉</div><h3>Selecione um aluno</h3><p>A listagem é o ponto de partida. Ao selecionar, o Purple abre o prontuário completo sem tirar você do módulo.</p></div>`;
  const tab=State.studentTab&&State.studentTab!=='search'?State.studentTab:'profile',financial=studentFinancialTotals(s),moneyRows=financial.rows;
  if(tab==='profile')return `<div class="student-detail-grid"><div class="form-card"><h3>Cadastro</h3><div class="form-grid cols-3"><div class="field"><label>Código</label><input value="${escapeHTML(s.code||s.contract||s.document||'')}" disabled/></div><div class="field"><label>Nome do aluno</label><input value="${escapeHTML(s.name||'')}" disabled/></div><div class="field"><label>CPF / Documento</label><input value="${escapeHTML(s.document||'')}" disabled/></div><div class="field"><label>Data de nascimento</label><input value="${escapeHTML(s.birthDate||'')}" disabled/></div><div class="field"><label>Idade</label><input value="${escapeHTML(studentAgeLabel(s.birthDate||''))}" disabled/></div><div class="field"><label>Situação</label><input value="${escapeHTML(normalizeStudentStatus(s.situation))}" disabled/></div><div class="field"><label>Telefone</label><input value="${escapeHTML(studentPhone(s))}" disabled/></div><div class="field"><label>WhatsApp</label><input value="${escapeHTML(studentWhatsApp(s))}" disabled/></div><div class="field"><label>E-mail</label><input value="${escapeHTML(s.email||'')}" disabled/></div></div><div class="section-actions" style="justify-content:flex-start"><button class="btn primary small" onclick="App.editStudent('${s.id}')">Editar cadastro</button></div></div><div class="form-card"><h3>Responsáveis</h3><div class="kpi-strip"><span><b>Responsável legal:</b> ${escapeHTML(s.responsibleName||s.guardian||'—')}</span><span><b>Telefone:</b> ${escapeHTML(formatPhoneBR(s.responsiblePhone||s.guardianPhone||'')||'—')}</span><span><b>Financeiro:</b> ${escapeHTML(s.financialResponsibleName||'—')}</span><span><b>Telefone financeiro:</b> ${escapeHTML(formatPhoneBR(s.financialResponsiblePhone||'')||'—')}</span></div></div><div class="form-card"><h3>Observações</h3><p class="muted">${escapeHTML(s.notes||s.evaluation||'Nenhuma observação registrada.')}</p></div></div>`;
  if(tab==='courses')return `<div class="student-detail-grid"><div class="form-card"><h3>Matrícula do aluno</h3><p class="muted">Esta é a área operacional para efetivar curso, contrato, turma, professor, material e situação da matrícula.</p><div class="table-wrap"><table><thead><tr><th>Contrato</th><th>Turma</th><th>Professor</th><th>Livro</th><th>Módulo</th><th>Data</th><th>Situação</th></tr></thead><tbody><tr><td>${escapeHTML(s.contract||'—')}</td><td>${escapeHTML(classLabelById(s.classId))}</td><td>${escapeHTML(teacherLabelById(s.teacherId))}</td><td>${escapeHTML(bookLabelById(s.bookId))}</td><td>${escapeHTML(s.level||'—')}</td><td>${fmtDate(s.enrollmentDate)}</td><td>${escapeHTML(normalizeStudentStatus(s.situation))}</td></tr></tbody></table></div><div class="section-actions" style="justify-content:flex-start;margin-top:12px"><button class="btn primary small" onclick="App.editStudent('${s.id}')">Editar matrícula</button><button class="btn ghost small" onclick="App.studentQuickAction('documents','${s.id}')">Contrato e documentos</button></div></div><div class="form-card"><h3>Contrato e material</h3><div class="kpi-strip"><span><b>Contrato:</b> ${escapeHTML(s.contract||'Não informado')}</span><span><b>Material:</b> ${escapeHTML(bookLabelById(s.bookId))}</span><span><b>Responsável financeiro:</b> ${escapeHTML(s.financialResponsibleName||s.guardian||'—')}</span></div><p class="muted" style="margin-top:12px">Quando o upload de contrato for conectado, ele ficará vinculado a esta matrícula.</p></div></div>`;
  if(tab==='payments')return `<div class="student-detail-grid"><section class="grid cols-3">${metricCard('Total pago',fmtMoney(financial.paid),'R$',0,`${fmtNumber(financial.paidRows.length)} parcela(s) pagas`)}${metricCard('A pagar',fmtMoney(financial.open),'R$',0,`${fmtNumber(financial.openRows.length)} parcela(s) a vencer/vencidas`,true)}${metricCard('Contrato financeiro',fmtMoney(financial.total),'▧',0,`${fmtNumber(moneyRows.length)} lançamento(s)`)}</section><div class="form-card"><h3>Financeiro do aluno</h3><div class="alert ${String(s.financialStatus||'').toLowerCase()==='em dia'?'green':'yellow'}"><div class="alert-icon">R$</div><div><b>${escapeHTML(s.financialStatus||'—')}</b><span>Parcelas pagas, abertas e vencidas vinculadas ao aluno.</span></div></div><div class="section-actions" style="justify-content:flex-start;margin-top:12px"><button class="btn primary small" onclick="App.openNavItem('financial','','financeiro')">Abrir centro financeiro</button><button class="btn ghost small" onclick="App.editFinancialEntry('receivable')">Novo recebimento</button></div></div><div class="table-wrap"><table><thead><tr><th>Parcela / descrição</th><th>Valor</th><th>Pago</th><th>A pagar</th><th>Status</th><th>Vencimento</th></tr></thead><tbody>${moneyRows.map(x=>{const amount=Number(x.amount||x.value||0),paid=Number(x.paidAmount||0),open=Math.max(0,amount-paid);return `<tr><td>${escapeHTML(x.description||'Lançamento')}</td><td>${fmtMoney(amount)}</td><td>${fmtMoney(paid)}</td><td>${fmtMoney(open)}</td><td>${escapeHTML(FINANCIAL_STATUS[financialStatusFor(x)]||x.status||'—')}</td><td>${fmtDate(x.dueDate||x.date||x.createdAt)}</td></tr>`}).join('')||'<tr><td colspan="6">Nenhum lançamento financeiro vinculado nominalmente a este aluno.</td></tr>'}</tbody></table></div></div>`;
  if(tab==='schedule')return `<div class="student-detail-grid"><div class="form-card"><h3>Horários</h3><div class="student-calendar-strip"><span><b>Turma</b>${escapeHTML(classLabelById(s.classId))}</span><span><b>Horário</b>${escapeHTML(studentNextClass(s))}</span><span><b>Professor</b>${escapeHTML(teacherLabelById(s.teacherId))}</span><span><b>Última aula</b>${escapeHTML(studentLastClass(s))}</span></div></div><div class="form-card"><h3>Reposições e agenda</h3><p class="muted">Reposições, aulas extras e compromissos do aluno ficam centralizados nesta aba conforme os vínculos forem cadastrados.</p></div></div>`;
  if(tab==='frequency')return `<div class="student-detail-grid"><section class="grid cols-3">${metricCard('Frequência atual',`${fmtNumber(s.frequency||0,1)}%`,'◫',0,'Base do cadastro')}${metricCard('Última aula',studentLastClass(s),'◴',0,'Histórico do aluno')}${metricCard('Risco operacional',studentCatalogScore(s)<75?'Alto':'Baixo','!',0,`${studentCatalogScore(s)}/100`)}</section><div class="form-card"><h3>Controle de frequência</h3><p class="muted">${Number(s.frequency||0)<85?'Aluno abaixo do nível ideal de presença. Recomenda-se contato ativo.':'Frequência dentro do esperado.'}</p></div></div>`;
  if(tab==='grades')return `<div class="student-detail-grid"><div class="form-card"><h3>Notas e parecer</h3><div class="kpi-strip"><span><b>Score:</b> ${studentCatalogScore(s)}/100</span><span><b>Frequência:</b> ${fmtNumber(s.frequency||0,1)}%</span><span><b>Situação:</b> ${escapeHTML(normalizeStudentStatus(s.situation))}</span></div><p class="muted" style="margin-top:12px">${escapeHTML(s.evaluation||'Sem notas ou parecer acadêmico registrado.')}</p></div><div class="form-card"><h3>Ocorrências</h3><p class="muted">${escapeHTML(s.occurrences||'Nenhuma ocorrência registrada.')}</p></div></div>`;
  if(tab==='contacts')return `<div class="student-detail-grid"><div class="form-card"><h3>Contatos</h3><div class="form-grid cols-2"><div class="field"><label>Telefone</label><input value="${escapeHTML(studentPhone(s))}" disabled/></div><div class="field"><label>WhatsApp</label><input value="${escapeHTML(studentWhatsApp(s))}" disabled/></div><div class="field"><label>E-mail</label><input value="${escapeHTML(s.email||'')}" disabled/></div><div class="field"><label>Responsável</label><input value="${escapeHTML(s.guardian||'')}" disabled/></div></div><div class="section-actions" style="justify-content:flex-start"><button class="btn primary small" onclick="App.studentQuickAction('whatsapp','${s.id}')">Abrir WhatsApp</button></div></div><div class="form-card"><h3>Endereço</h3><p class="muted">${escapeHTML([s.address,s.city].filter(Boolean).join(' • ')||'Endereço não informado.')}</p></div></div>`;
  if(tab==='followup'){const items=studentFollowUpItems(s);return `<div class="student-detail-grid"><div class="form-card"><h3>Novo follow-up</h3><p class="muted">Registre contatos feitos com o aluno ou responsável, tipo de contato, resultado e próximo retorno.</p><div class="form-grid cols-3"><div class="field"><label>Tipo de contato</label><select id="studentFollowupType"><option value="">Selecione</option><option>WhatsApp</option><option>Ligação</option><option>E-mail</option><option>Presencial</option><option>Reunião</option><option>Ocorrência</option></select></div><div class="field"><label>Resultado</label><select id="studentFollowupResult"><option value="">Selecione</option><option>Contato realizado</option><option>Sem resposta</option><option>Retornar depois</option><option>Resolvido</option><option>Pendente</option><option>Encaminhado</option></select></div><div class="field"><label>Próximo retorno</label><input id="studentFollowupNext" type="date"/></div></div><div class="field"><label>Observação</label><textarea id="studentFollowupNote" placeholder="Ex.: falei com a mãe, combinamos retorno amanhã, aluno faltou por motivo de saúde..."></textarea></div><div class="section-actions" style="justify-content:flex-start"><button class="btn primary small" onclick="App.saveStudentFollowUp('${s.id}')">Registrar follow-up</button><button class="btn ghost small" onclick="App.studentQuickAction('contacts','${s.id}')">Ver contatos</button></div></div><div class="form-card"><h3>Histórico de follow-up</h3>${items.length?`<div class="timeline">${items.map(item=>`<div class="timeline-item"><b>${escapeHTML(item.title||'Follow-up')}</b><p>${escapeHTML(item.detail||'')}</p><time>${fmtDateTime(item.at)}</time></div>`).join('')}</div>`:'<div class="empty"><p>Nenhum contato ou ocorrência registrada para este aluno.</p></div>'}</div></div>`}
  if(tab==='documents')return `<div class="student-detail-grid"><div class="form-card"><h3>Documentos</h3><p class="muted">Central para contrato, ficha de cadastro, comprovantes, documentos pessoais e anexos pedagógicos.</p><div class="kpi-strip"><span><b>Contrato:</b> ${escapeHTML(s.contract||'Não informado')}</span><span><b>Ficha:</b> Cadastro Purple</span><span><b>Status:</b> ${escapeHTML(normalizeStudentStatus(s.situation))}</span></div></div><div class="form-card"><h3>Observações documentais</h3><p class="muted">${escapeHTML(s.notes||'Nenhuma observação documental registrada.')}</p></div></div>`;
  if(tab==='history')return `<div class="student-detail-grid"><div class="form-card"><h3>Timeline inteligente</h3><p class="muted">Matrícula, pagamentos, ocorrências, mensagens, reposições e alterações importantes em ordem cronológica.</p>${studentDrawerTimeline(s)}</div></div>`;
  if(tab==='more')return `<div class="student-detail-grid"><div class="form-card"><div class="empty"><div class="emoji">◇</div><h3>Em breve</h3><p>Vamos definir juntos quais ações avançadas devem entrar aqui sem poluir a rotina da secretaria.</p></div></div></div>`;
  if(tab==='whatsapp')return `<div class="student-detail-grid"><div class="form-card"><h3>WhatsApp</h3><div class="kpi-strip"><span><b>Aluno:</b> ${escapeHTML(s.name)}</span><span><b>WhatsApp:</b> ${escapeHTML(studentWhatsApp(s))}</span><span><b>Responsável:</b> ${escapeHTML(s.guardian||'—')}</span></div><div class="alert blue" style="margin-top:12px"><div class="alert-icon">☏</div><div><b>Contexto pronto para atendimento</b><span>O atendente consulta o histórico do aluno antes de abrir a central de comunicação.</span></div></div><div class="section-actions" style="justify-content:flex-start;margin-top:12px"><button class="btn primary small" onclick="App.openNavItem('whatsapp','','')">Abrir central WhatsApp</button><button class="btn ghost small" onclick="App.studentQuickAction('history','${s.id}')">Ver histórico</button></div></div><div class="form-card"><h3>Resumo para conversa</h3><p class="muted">${escapeHTML(s.evaluation||s.notes||'Sem resumo de atendimento registrado.')}</p></div></div>`;
  return `<p class="muted">Selecione uma aba.</p>`;
}
function studentToolPanel(){return `<aside class="student-erp-side"><div class="student-side-title">${appIcon('◉')}<b>Alunos</b></div>${studentSideButton('new','✚','Novo Aluno',true)}${studentSideButton('import','↙','Importar')}${studentSideButton('export','↗','Exportar')}${studentSideButton('followup','◇','Follow-up')}${studentSideButton('occurrences','!','Ocorrências')}${studentSideButton('whatsapp','☏','WhatsApp')}${studentSideButton('documents','☰','Documentos')}${studentSideButton('more','◎','Mais Ações')}</aside>`}
function studentModuleToolbar(){return `<div class="student-erp-ribbon">${studentActionButton('classes','▤','Grade de Horários')}${studentActionButton('frequency','✓','Marcar Presença')}${studentActionButton('financial','R$','Recebimento')}${studentActionButton('contacts','☎','Contatos')}${studentActionButton('material','▣','Material')}${studentActionButton('ia','✦','Analisar aluno')}</div>`}
function studentCompactValue(value){return escapeHTML(value||'—')}
function studentCompactField(label,value,wide=false){return `<span class="${wide?'wide':''}"><b>${escapeHTML(label)}</b><em>${studentCompactValue(value)}</em></span>`}
function studentCompactSection(title,fields){return `<section class="student-profile-section"><h3>${escapeHTML(title)}</h3><div class="student-profile-fields">${fields.join('')}</div></section>`}
function studentDetailContentNextV2(s){
  const tab=State.studentTab&&State.studentTab!=='search'?State.studentTab:'profile';
  if(tab==='courses')return studentCoursesContent(s,studentFinancialTotals(s));
  if(tab==='payments')return studentFinancialContent(s,studentFinancialTotals(s));
  if(tab==='schedule')return studentScheduleContent(s);
  if(tab==='frequency')return studentAttendanceContent(s);
  if(tab==='grades')return studentGradesContent(s);
  if(tab==='followup')return studentFollowUpContent(s);
  if(tab!=='profile')return studentDetailContentNext(s);
  const birth=fmtDate(s.birthDate),created=fmtDate(s.createdAt||s.enrollmentDate),updated=fmtDate(s.updatedAt),sex=s.sex||s.gender||s.sexo||'—';
  return `<div class="student-profile-compact"><aside class="student-profile-summary">${renderStudentAvatar(s)}<h3>${escapeHTML(s.name||'Aluno')}</h3><p>${escapeHTML(studentAgeLabel(s.birthDate||''))}</p><div>${studentCompactField('Código',s.code||s.contract||s.document)}${studentCompactField('Data cadastro',created)}${studentCompactField('Situação',normalizeStudentStatus(s.situation))}${studentCompactField('Resp. financeiro',s.financialResponsibleName||s.guardian)}${studentCompactField('Última alteração',updated)}</div><button class="btn primary small" onclick="App.editStudent('${s.id}')">Editar cadastro</button></aside><main class="student-profile-sheet">${studentCompactSection('Dados pessoais',[studentCompactField('Nome do aluno',s.name,true),studentCompactField('Nome social',s.socialName,true),studentCompactField('Data nascimento',birth),studentCompactField('Idade',studentAgeLabel(s.birthDate||'')),studentCompactField('Sexo',sex)])}${studentCompactSection('Documentos',[studentCompactField('CPF',s.document),studentCompactField('R.A.',s.ra||s.registration||''),studentCompactField('RG',s.rg||''),studentCompactField('Data emissão',fmtDate(s.rgIssueDate||s.documentIssueDate)),studentCompactField('Emissor',s.rgIssuer||s.documentIssuer||'')])}${studentCompactSection('Endereço',[studentCompactField('CEP',s.zip||s.cep||''),studentCompactField('Endereço',s.address,true),studentCompactField('Número',s.number||s.addressNumber||''),studentCompactField('Complemento',s.complement||''),studentCompactField('Bairro',s.district||s.neighborhood||''),studentCompactField('Cidade',s.city)])}${studentCompactSection('Contato',[studentCompactField('WhatsApp',studentWhatsApp(s)),studentCompactField('Celular/SMS',formatPhoneBR(s.mobile||s.smsPhone||s.phone||'')),studentCompactField('Telefone',studentPhone(s)),studentCompactField('Telefone contato',formatPhoneBR(s.contactPhone||s.responsiblePhone||s.guardianPhone||'')),studentCompactField('E-mail',s.email,true)])}${studentCompactSection('Responsáveis',[studentCompactField('Responsável legal',s.responsibleName||s.guardian,true),studentCompactField('Parentesco',s.responsibleRelationship||''),studentCompactField('Telefone responsável',formatPhoneBR(s.responsiblePhone||s.guardianPhone||'')),studentCompactField('Resp. financeiro',s.financialResponsibleName||'',true),studentCompactField('Parentesco financeiro',s.financialResponsibleRelationship||''),studentCompactField('Telefone financeiro',formatPhoneBR(s.financialResponsiblePhone||''))])}<section class="student-profile-section notes"><h3>Observações</h3><p>${escapeHTML(s.notes||s.evaluation||'Nenhuma observação registrada.')}</p></section></main></div>`;
}
function renderStudentRecord(s){
  const tab=State.studentTab&&State.studentTab!=='search'?State.studentTab:'profile';
  State.studentTab=tab;
  return `<div class="page student-erp-page student-record-page"><div class="student-erp-shell">${studentToolPanel()}<main class="student-erp-main"><section class="student-record-hero"><button class="btn ghost small" onclick="App.closeStudentDrawer()">← Voltar para lista</button><div class="student-record-main">${renderStudentAvatar(s)}<div><span class="eyebrow">Prontuário do aluno</span><h2>${escapeHTML(s.name)}</h2><p>${escapeHTML([normalizeStudentStatus(s.situation),classLabelById(s.classId),teacherLabelById(s.teacherId)].filter(Boolean).join(' • '))}</p></div></div><div class="student-record-status">${studentStatusBadge(s)}${studentFinancialBadge(s)}</div></section><div class="student-detail-tabs student-record-tabs">${studentTabs().map(([t,label])=>studentTabButton(t,label)).join('')}</div><section class="student-record-body">${studentDetailContentNextV2(s)}</section></main></div></div>`;
}
function renderStudentsNext(){
  if(!catalogCanView())return `<div class="page"><div class="empty"><div class="emoji">🔒</div><h3>Acesso restrito</h3></div></div>`;
  const selected=selectedStudent();
  if(selected)return renderStudentRecord(selected);
  const all=catalogSortByName(State.db.students||[]),query=State.catalogSearch?.students||'',filter=State.studentFilter||'all',arr=all.filter(s=>catalogMatches(s,query,`${studentPhone(s)} ${studentWhatsApp(s)} ${s.guardian||''} ${s.document||''} ${s.code||''} ${s.contract||''} ${s.email||''} ${classLabelById(s.classId)} ${teacherLabelById(s.teacherId)} ${bookLabelById(s.bookId)}`)).filter(s=>studentFilterMatches(s,filter));
  const filters=[['all','Todos'],['active','Ativos'],['inactive','Inativos'],['pending','Pendentes'],['delinquent','Inadimplentes'],['birthday','Aniversariantes'],['new','Novos'],['renewal','Rematrícula'],['absent','Faltosos'],['replacement','Reposição']];
  const selectedListId=State.studentListSelectedId||'',selectedRowKey=State.studentListSelectedRowKey||'',hasSelected=Boolean(arr.find(s=>s.id===selectedListId)),actionsDisabled=!hasSelected||!catalogCanEdit();
  const rows=arr.map((s,index)=>{const rowKey=`${s.id}-${index}`;return `<tr data-student-row="${escapeHTML(rowKey)}" class="${selectedListId===s.id&&selectedRowKey===rowKey?'selected':''}" onclick="App.selectStudentRow('${s.id}','${rowKey}')" ondblclick="App.openStudent('${s.id}')"><td class="student-select-cell"><input type="radio" name="studentSelectedRow" ${selectedListId===s.id&&selectedRowKey===rowKey?'checked':''} onclick="event.stopPropagation();App.selectStudentRow('${s.id}','${rowKey}')" aria-label="Selecionar ${escapeHTML(s.name)}"/></td><td class="student-code">${escapeHTML(s.code||s.contract||s.document||'—')}</td><td><b>${escapeHTML(s.name)}</b></td><td>${escapeHTML(s.socialName||'')}</td><td>${escapeHTML(studentPhone(s))}</td><td>${escapeHTML(studentWhatsApp(s))}</td><td>${escapeHTML(s.city||'—')}</td><td>${escapeHTML(s.guardian||'—')}</td><td>${studentStatusBadge(s)}</td><td>${escapeHTML(s.document||'—')}</td></tr>`}).join('');
  const cards=arr.map(s=>`<button class="student-mobile-card ${selectedListId===s.id?'selected':''}" onclick="App.selectStudentRow('${s.id}')"><div>${renderStudentAvatar(s)}<span><b>${escapeHTML(s.name)}</b><small>${escapeHTML(s.guardian||'Responsável não informado')}</small></span></div><div class="student-mobile-meta"><span>${escapeHTML(classLabelById(s.classId))}</span><span>${fmtNumber(s.frequency||0,1)}%</span><span>${escapeHTML(normalizeStudentStatus(s.situation))}</span></div></button>`).join('');
  return `<div class="page student-erp-page student-list-page"><div class="student-erp-shell">${studentToolPanel()}<main class="student-erp-main"><section class="student-erp-filters"><div class="field"><label>Procurar</label><input id="studentSearchInput" type="search" value="${escapeHTML(query)}" placeholder="Código, nome do aluno, responsável, WhatsApp, CPF ou e-mail" oninput="App.setCatalogSearch('students',this.value)"/></div><div class="field"><label>Ordenar por</label><select><option>Código</option><option>Nome do Aluno</option><option>Situação</option></select></div><div class="field"><label>Filtrar por</label><select onchange="App.setStudentFilter(this.value)">${filters.map(([key,label])=>`<option value="${key}" ${filter===key?'selected':''}>${label}</option>`).join('')}</select></div></section><section class="student-erp-table-panel"><div class="student-table-top-actions"><div class="student-filter-chips">${filters.map(([key,label])=>`<button class="${filter===key?'active':''}" onclick="App.setStudentFilter('${key}')">${label}</button>`).join('')}</div><div class="student-actions-inline"><span>Ações</span><button class="btn ghost small" ${actionsDisabled?'disabled':''} onclick="App.editSelectedStudent()">Editar</button><button class="btn danger small" ${actionsDisabled?'disabled':''} onclick="App.confirmDeleteSelectedStudent()">Excluir</button></div></div><div class="table-wrap students-table"><table><thead><tr><th>Selecionar</th><th>Código</th><th>Nome do Aluno</th><th>Nome Social</th><th>Telefone</th><th>WhatsApp</th><th>Cidade</th><th>Responsável</th><th>Situação</th><th>RA</th></tr></thead><tbody>${rows||'<tr><td colspan="10"><div class="empty"><div class="emoji">◉</div><h3>Nenhum aluno encontrado</h3></div></td></tr>'}</tbody></table></div><div class="student-mobile-list">${cards||'<div class="empty"><h3>Nenhum aluno encontrado</h3></div>'}</div><div class="student-erp-footer"><span>Nº de Alunos: ${fmtNumber(arr.length)}</span><span>${hasSelected?'Aluno selecionado para ações':'Selecione um aluno para editar ou excluir'}</span></div></section></main></div></div>`;
}

function studentReadOnlyField(label,value,wide=false){return `<span class="${wide?'wide':''}"><b>${escapeHTML(label)}</b><em>${escapeHTML(value||'—')}</em></span>`}
function studentReadOnlySection(title,fields){return `<section class="student-read-section"><h3>${escapeHTML(title)}</h3><div class="student-read-grid">${fields.join('')}</div></section>`}
function studentCompactResponsibles(s={}){
  const source=Array.isArray(s.responsibles)?s.responsibles:[];
  if(source.length)return source.map(item=>({
    name:item?.name||item?.responsibleName||item?.financialResponsibleName||'',
    type:item?.type||item?.relationship||item?.responsibleType||'Responsável financeiro',
    document:item?.document||item?.cpf||'',
    cpf:item?.cpf||item?.document||'',
    phone:item?.phone||item?.responsiblePhone||'',
    whatsapp:item?.whatsapp||item?.responsibleWhatsapp||'',
    email:item?.email||item?.responsibleEmail||'',
    financial:item?.financial!==false,
    pedagogical:item?.pedagogical!==false,
    birthDate:item?.birthDate||'',
    sex:item?.sex||'',
    socialName:item?.socialName||'',
    zip:item?.zip||item?.cep||'',
    address:item?.address||'',
    number:item?.number||'',
    district:item?.district||item?.neighborhood||'',
    city:item?.city||'',
    state:item?.state||item?.uf||''
  }));
  const fallback=studentPrimaryResponsible(s);
  return fallback?.name||fallback?.cpf||fallback?.email?[fallback]:[];
}
function studentReadOnlyResponsibles(s){const rows=studentCompactResponsibles(s||{});return `<section class="student-read-section"><h3>Responsáveis</h3><div class="table-wrap"><table class="compact-table"><thead><tr><th>Nome</th><th>Parentesco</th><th>CPF</th><th>Telefone</th><th>WhatsApp</th><th>Email</th><th>Financeiro</th><th>Pedagógico</th></tr></thead><tbody>${rows.map(r=>`<tr><td>${escapeHTML(r.name||'—')}</td><td>${escapeHTML(r.type||'—')}</td><td>${escapeHTML(r.document||r.cpf||'—')}</td><td>${escapeHTML(formatPhoneBR(r.phone||''))}</td><td>${escapeHTML(formatPhoneBR(r.whatsapp||''))}</td><td>${escapeHTML(r.email||'—')}</td><td>${r.financial?'Sim':'—'}</td><td>${r.pedagogical?'Sim':'—'}</td></tr>`).join('')||'<tr><td colspan="8">Nenhum responsável cadastrado.</td></tr>'}</tbody></table></div></section>`}
function studentDataContentFull(s){return `<div class="student-readonly-page">${studentReadOnlySection('Dados pessoais',[studentReadOnlyField('Nome do aluno',s.name,true),studentReadOnlyField('Data de nascimento',fmtDate(s.birthDate)),studentReadOnlyField('Idade',studentAgeLabel(s.birthDate||'')),studentReadOnlyField('Sexo',s.sex||s.gender||s.sexo),studentReadOnlyField('Nome social',s.socialName,true),studentReadOnlyField('CPF',s.document),studentReadOnlyField('RG',s.rg),studentReadOnlyField('Data emissão',fmtDate(s.documentIssueDate||s.rgIssueDate)),studentReadOnlyField('Emissor',s.documentIssuer||s.rgIssuer)])}${studentReadOnlySection('Endereço',[studentReadOnlyField('CEP',s.zip||s.cep),studentReadOnlyField('Endereço',s.address,true),studentReadOnlyField('Número',s.number||s.addressNumber),studentReadOnlyField('Complemento',s.complement),studentReadOnlyField('Bairro',s.district||s.neighborhood),studentReadOnlyField('Cidade',s.city),studentReadOnlyField('UF',s.state||s.uf)])}${studentReadOnlySection('Contato',[studentReadOnlyField('WhatsApp',studentWhatsApp(s)),studentReadOnlyField('Celular',formatPhoneBR(s.mobile||s.smsPhone||'')),studentReadOnlyField('Operadora',s.phoneCarrier),studentReadOnlyField('Telefone',studentPhone(s)),studentReadOnlyField('Telefone de contato',formatPhoneBR(s.contactPhone||s.responsiblePhone||'')),studentReadOnlyField('Email',s.email,true),studentReadOnlyField('Aceita WhatsApp',s.acceptWhatsapp===false?'Não':'Sim')])}${studentReadOnlyResponsibles(s)}${studentReadOnlySection('Filiação',[studentReadOnlyField('Nome do pai',s.fatherName,true),studentReadOnlyField('Nome da mãe',s.motherName,true),studentReadOnlyField('Telefone',formatPhoneBR(s.parentPhone||'')),studentReadOnlyField('Email',s.parentEmail,true)])}${studentReadOnlySection('Dados adicionais',[studentReadOnlyField('Profissão',s.profession),studentReadOnlyField('Local de trabalho',s.workplace,true),studentReadOnlyField('Telefone comercial',formatPhoneBR(s.workPhone||'')),studentReadOnlyField('Horário de trabalho',s.workHours)])}<section class="student-read-section"><h3>Diagnóstico</h3><p>${escapeHTML(s.diagnosis||s.diagnosticReport||'Não informado.')}</p></section><section class="student-read-section"><h3>Observações</h3><p>${escapeHTML(s.notes||'Nenhuma observação registrada.')}</p></section><div class="section-actions"><button class="btn primary small" onclick="App.editStudent('${s.id}')">Editar dados</button></div></div>`}
function studentCoursesContentFull(s,financial=studentFinancialTotals(s)){const rows=studentCourseRows(s),cancelFee=studentCourseCancellationFee(s);return `<div class="student-course-panel student-prontuario-grid"><aside class="student-module-actions"><button class="btn primary small" onclick="App.openStudentEnrollment('${s.id}')">Efetuar matrícula</button><button class="btn danger small" onclick="App.openStudentCancellation('${s.id}')">Cancelar curso</button><button class="btn ghost small" onclick="App.generateStudentContract('${s.id}')">Contrato / Promissória</button><button class="btn danger small" onclick="App.deleteStudentCoursePackage?App.deleteStudentCoursePackage('${s.id}'):App.toast('Exclusão de pacote será configurada após selecionar o contrato.')">Excluir pacote</button><button class="btn ghost small" onclick="App.openStudentClassLink('${s.id}')">Trocar / Vincular turma</button><button class="btn ghost small" onclick="App.generateStudentDeclaration('${s.id}')">Declaração / Requerimento</button></aside><main class="student-module-main"><section class="form-card"><div class="panel-head"><div><h3>Cursos / Pacotes</h3><small>Matrícula, mensalidade, material e vínculo com turma.</small></div><span class="status approved">${escapeHTML(normalizeStudentStatus(s.situation))}</span></div><div class="table-wrap"><table><thead><tr><th>Curso / Pacote</th><th>Turma</th><th>Data início</th><th>Previsão término</th><th>Status</th><th>Tipo de aula</th><th>Assinatura</th></tr></thead><tbody>${rows.map(row=>`<tr><td>${escapeHTML(row.package)}</td><td>${escapeHTML(row.className)}</td><td>${fmtDate(row.start)}</td><td>${fmtDate(row.end)}</td><td>${escapeHTML(row.status)}</td><td>${escapeHTML(row.type)}</td><td>${escapeHTML(row.signature||'Pendente')}</td></tr>`).join('')||'<tr><td colspan="7">Nenhum curso vinculado.</td></tr>'}</tbody></table></div></section><section class="grid cols-4">${metricCard('Mensalidade',fmtMoney(s.courseMonthlyValue||financial.openRows[0]?.amount||0),'R$',0,'Plano atual')}${metricCard('Parcelas abertas',fmtNumber(financial.openRows.length),'▤',0,fmtMoney(financial.open))}${metricCard('Acordo cancelamento',fmtMoney(cancelFee),'%',0,'10% das mensalidades a vencer')}${metricCard('Turma',classLabelById(s.classId),'◴',0,teacherLabelById(s.teacherId))}</section><section class="form-card"><h3>Fluxo da matrícula</h3><div class="student-enrollment-flow"><span>1. Selecionar curso</span><span>2. Selecionar turma</span><span>3. Definir plano mensalidade/material</span><span>4. Gerar financeiro automaticamente</span></div></section></main></div>`}
function studentPaymentsContentFull(s){const financial=studentFinancialTotals(s),rows=financial.rows,first=studentFirstOpenFinancialEntry(s);return `<div class="student-financial-panel"><section class="student-financial-actions"><button class="btn success small" onclick="${first?`App.openStudentReceivePayment('${s.id}','${first.id}')`:`App.toast('Nenhuma parcela em aberto para receber.')`}">Receber</button><button class="btn ghost small" onclick="${first?`App.editFinancialEntry('receivable','${first.id}')`:`App.toast('Nenhuma parcela selecionada.')`}">Editar parcela</button><button class="btn ghost small" onclick="App.toast('Geração de boleto será integrada ao provedor financeiro.')">Gerar boleto</button></section><section class="student-financial-summary"><span><b>Total pago</b>${fmtMoney(financial.paid)}</span><span><b>A pagar</b>${fmtMoney(financial.open)}</span><span><b>Total contrato</b>${fmtMoney(financial.total)}</span></section><section class="form-card"><h3>Pagamentos do aluno</h3><div class="table-wrap student-financial-table"><table><thead><tr><th>Parcelas</th><th>Valor</th><th>Vencimento</th><th>Status</th><th>Forma de pagamento</th><th>Ações</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${escapeHTML(x.description||x.historic||'Parcela')}</td><td>${fmtMoney(x.amount||x.value||0)}</td><td>${fmtDate(x.dueDate||x.date||x.createdAt)}</td><td><span class="status ${financialStatusFor(x)==='paid'?'approved':financialStatusFor(x)==='overdue'?'adjust':'draft'}">${escapeHTML(FINANCIAL_STATUS[financialStatusFor(x)]||x.status||'—')}</span></td><td>${escapeHTML(x.paymentMethod||x.method||'—')}</td><td><div class="table-actions"><button class="btn success small" onclick="App.openStudentReceivePayment('${s.id}','${x.id}')">Receber</button><button class="btn ghost small" onclick="App.editFinancialEntry('receivable','${x.id}')">Editar parcela</button><button class="btn ghost small" onclick="App.toast('Geração de boleto será integrada ao provedor financeiro.')">Gerar boleto</button></div></td></tr>`).join('')||'<tr><td colspan="6">Nenhuma parcela cadastrada.</td></tr>'}</tbody></table></div></section></div>`}
function studentContactsContentFull(s){return `<div class="student-contacts-panel">${studentFollowUpContent(s)}</div>`}
function studentPrimaryResponsible(s={}){const rows=Array.isArray(s.responsibles)?s.responsibles:[];return rows.find(r=>r?.financial)||rows[0]||{name:s.financialResponsibleName||s.responsibleName||s.guardian||'',type:s.financialResponsibleRelationship||s.responsibleRelationship||'Responsável financeiro',document:s.financialResponsibleDocument||s.responsibleDocument||'',rg:s.financialResponsibleRg||'',birthDate:s.financialResponsibleBirth||'',sex:s.financialResponsibleSex||'',socialName:'',zip:s.financialResponsibleCep||'',address:s.financialResponsibleAddress||'',number:s.financialResponsibleNumber||'',district:s.financialResponsibleDistrict||'',city:s.financialResponsibleCity||'',state:s.financialResponsibleState||'',phone:s.financialResponsiblePhone||s.responsiblePhone||'',whatsapp:s.financialResponsibleWhatsapp||s.responsibleWhatsapp||'',email:s.financialResponsibleEmail||s.responsibleEmail||'',financial:true,pedagogical:true}}
function setStudentDataSubTab(tab='pessoais'){$$('[data-student-data-tab-button]').forEach(btn=>btn.classList.toggle('active',btn.dataset.studentDataTabButton===tab));$$('[data-student-data-tab-panel]').forEach(panel=>panel.classList.toggle('active',panel.dataset.studentDataTabPanel===tab))}
function editStudentDataSubTab(id){const active=document.querySelector('[data-student-data-tab-button].active')?.dataset.studentDataTabButton||'pessoais';editStudentCleanTopTabs(id);requestAnimationFrame(()=>switchStudentFormTab(active==='responsavel'?'responsavel':active==='adicionais'?'observacoes':'cadastro'))}
function studentDataTabButton(key,label,active=false){return `<button class="${active?'active':''}" data-student-data-tab-button="${key}" onclick="App.setStudentDataSubTab('${key}')">${escapeHTML(label)}</button>`}
