function studentDataContentFull(s){const r=studentPrimaryResponsible(s);return `<div class="student-readonly-page student-data-tabs-page"><div class="student-data-tabs-bar"><nav class="student-data-tabs">${studentDataTabButton('pessoais','Dados pessoais',true)}${studentDataTabButton('responsavel','Responsável financeiro')}${studentDataTabButton('adicionais','Dados adicionais')}</nav><button class="btn primary small" onclick="App.editStudentDataSubTab('${s.id}')">Editar aba</button></div>${studentDataPanel('pessoais',true,`${studentReadOnlySection('Dados pessoais',[studentReadOnlyField('Nome do aluno',s.name,true),studentReadOnlyField('Data de nascimento',fmtDate(s.birthDate)),studentReadOnlyField('Idade',studentAgeLabel(s.birthDate||'')),studentReadOnlyField('Sexo',s.sex||s.gender||s.sexo),studentReadOnlyField('Nome social',s.socialName,true)])}${studentReadOnlySection('Documentos',[studentReadOnlyField('CPF',s.document),studentReadOnlyField('RG',s.rg),studentReadOnlyField('Data emissão',fmtDate(s.documentIssueDate||s.rgIssueDate)),studentReadOnlyField('Emissor',s.documentIssuer||s.rgIssuer)])}${studentReadOnlySection('Endereço',[studentReadOnlyField('CEP',s.zip||s.cep),studentReadOnlyField('Endereço',s.address,true),studentReadOnlyField('Número',s.number||s.addressNumber),studentReadOnlyField('Complemento',s.complement),studentReadOnlyField('Bairro',s.district||s.neighborhood),studentReadOnlyField('Cidade',s.city),studentReadOnlyField('UF',s.state||s.uf)])}${studentReadOnlySection('Contato',[studentReadOnlyField('WhatsApp',studentWhatsApp(s)),studentReadOnlyField('Celular',formatPhoneBR(s.mobile||s.smsPhone||'')),studentReadOnlyField('Telefone',studentPhone(s)),studentReadOnlyField('Telefone de contato',formatPhoneBR(s.contactPhone||s.responsiblePhone||'')),studentReadOnlyField('Email',s.email,true),studentReadOnlyField('Aceita WhatsApp',s.acceptWhatsapp===false?'Não':'Sim')])}`)}${studentDataPanel('responsavel',false,`${studentReadOnlySection('Dados pessoais do responsável',[studentReadOnlyField('Nome responsável',r.name,true),studentReadOnlyField('Parentesco',r.type||r.relationship),studentReadOnlyField('Data de nascimento',fmtDate(r.birthDate)),studentReadOnlyField('Sexo',r.sex),studentReadOnlyField('Nome social',r.socialName,true),studentReadOnlyField('Responsável financeiro',r.financial===false?'Não':'Sim'),studentReadOnlyField('Responsável pedagógico',r.pedagogical===false?'Não':'Sim')])}${studentReadOnlySection('Documentos',[studentReadOnlyField('CPF',r.document||r.cpf),studentReadOnlyField('RG',r.rg)])}${studentReadOnlySection('Endereço',[studentReadOnlyField('CEP',r.zip||r.cep),studentReadOnlyField('Endereço',r.address,true),studentReadOnlyField('Número',r.number),studentReadOnlyField('Bairro',r.district||r.neighborhood),studentReadOnlyField('Cidade',r.city),studentReadOnlyField('UF',r.state||r.uf)])}${studentReadOnlySection('Contato',[studentReadOnlyField('WhatsApp',formatPhoneBR(r.whatsapp||'')),studentReadOnlyField('Telefone',formatPhoneBR(r.phone||'')),studentReadOnlyField('Email',r.email,true)])}${studentReadOnlyResponsibles(s)}`)}${studentDataPanel('adicionais',false,`${studentReadOnlySection('Filiação',[studentReadOnlyField('Nome do pai',s.fatherName,true),studentReadOnlyField('Nome da mãe',s.motherName,true),studentReadOnlyField('Telefone',formatPhoneBR(s.parentPhone||'')),studentReadOnlyField('Email',s.parentEmail,true)])}${studentReadOnlySection('Dados adicionais',[studentReadOnlyField('Profissão',s.profession),studentReadOnlyField('Local de trabalho',s.workplace,true),studentReadOnlyField('Telefone comercial',formatPhoneBR(s.workPhone||'')),studentReadOnlyField('Horário de trabalho',s.workHours)])}<section class="student-read-section"><h3>Diagnóstico</h3><p>${escapeHTML(s.diagnosis||s.diagnosticReport||'Não informado.')}</p></section><section class="student-read-section"><h3>Observações</h3><p>${escapeHTML(s.notes||'Nenhuma observação registrada.')}</p></section>`)}<div class="section-actions"><button class="btn primary small" onclick="App.editStudentDataSubTab('${s.id}')">Editar aba atual</button><button class="btn ghost small" onclick="App.editStudent('${s.id}')">Editar cadastro completo</button></div></div>`}
function studentDetailContentNextV2(s){const tab=State.studentTab||'profile';if(tab==='courses')return studentCoursesContentFull(s,studentFinancialTotals(s));if(tab==='payments')return studentPaymentsContentFull(s);if(tab==='schedule')return studentScheduleContent(s);if(tab==='frequency')return studentAttendanceContent(s);if(tab==='grades')return studentGradesContent(s);if(tab==='contacts')return studentContactsContentFull(s);return studentDataContentFull(s)}
function renderStudentRecord(s){State.studentTab=State.studentTab||'profile';return `<div class="page student-erp-page student-record-page"><div class="student-erp-shell">${studentToolPanel()}<main class="student-erp-main student-prontuario"><section class="student-record-hero student-prontuario-header"><button class="btn ghost small" onclick="App.closeStudentDrawer()">← Voltar para lista</button><div class="student-record-main">${renderStudentAvatar(s)}<div><span class="eyebrow">Prontuário do aluno</span><h2>${escapeHTML(s.name)}</h2><p>${escapeHTML([studentPhone(s),studentWhatsApp(s)].filter(x=>x&&x!=='—').join(' • ')||'Contato não informado')}</p></div></div><div class="student-record-status">${studentStatusBadge(s)}<button class="btn ghost small" onclick="App.editStudent('${s.id}')">Editar</button><button class="btn ghost small" onclick="App.openStudent('${s.id}')">Atualizar</button><button class="btn ghost small" onclick="App.setStudentTab('contacts')">Histórico</button></div></section><nav class="student-detail-tabs student-record-tabs">${studentTabs().map(([t,label])=>studentTabButton(t,label)).join('')}</nav><section class="student-record-body">${studentDetailContentNextV2(s)}</section></main></div></div>`}

function setupStudentCleanForm(){const modalEl=$('#modalRoot .modal');modalEl?.classList.add('clean-student-modal');const cpf=$('#studentDocument');if(cpf){cpf.value=formatCpfBR(cpf.value);cpf.addEventListener('input',()=>{cpf.value=formatCpfBR(cpf.value)})}$$('.student-resp-document').forEach(field=>{field.value=formatCpfBR(field.value);field.addEventListener('input',()=>{field.value=formatCpfBR(field.value)})});$$('.clean-student-form input,.clean-student-form textarea').forEach(field=>field.addEventListener('blur',uppercaseStudentFormValues));requestAnimationFrame(()=>$('#studentName')?.focus());$$('.clean-student-form input,.clean-student-form select,.clean-student-form textarea').filter(el=>!el.disabled&&el.type!=='hidden').forEach((el,index,fields)=>el.addEventListener('keydown',event=>{if(event.key!=='Enter'||el.tagName==='TEXTAREA')return;event.preventDefault();fields[index+1]?.focus()}));updateStudentAgePreviewWithCep();validateStudentWhatsappField();toggleStudentDiagnosisField()}
function toggleStudentDiagnosisField(){const field=$('#studentDiagnosis'),check=$('#studentHasDiagnosis');if(!field||!check)return;field.disabled=!check.checked;if(!check.checked)field.value='Não possui';if(check.checked&&field.value==='Não possui')field.value=''}
