function renderMeetings(){const items=commitmentRows(),editable=can('meetings.edit'),filter=State.meetingFilter||'future',filtered=items.filter(item=>filter==='all'?true:filter==='today'?item.status==='today':filter==='week'?item.status==='week':filter==='month'?item.status==='month':filter==='overdue'?item.status==='overdue':filter==='done'?item.status==='done':['future','today','week'].includes(item.status)),cards=filtered.map(item=>`<div class="list-card coffee-card" data-meeting-search="${escapeHTML(`${item.title} ${item.meta} ${item.source}`.toLowerCase())}"><div class="list-card-head"><div><span class="eyebrow">${item.source}</span><h4>${escapeHTML(item.title)}</h4></div><span class="status ${item.status==='done'?'approved':item.status==='overdue'?'rejected':item.status==='today'?'sent':'draft'}">${item.status==='done'?'Concluída':item.status==='overdue'?'Atrasada':item.status==='today'?'Hoje':item.status==='week'?'7 dias':'30 dias'}</span></div><p>${escapeHTML(item.meta)}</p><div class="list-card-meta"><span><b>Data:</b> ${fmtDate(item.date)}</span><span><b>Prioridade:</b> ${item.priority}</span><span><b>Status:</b> ${item.status}</span></div><div class="section-actions" style="justify-content:flex-start;margin-top:12px">${item.kind==='meeting'&&editable?`<button class="btn ghost small" onclick="App.editMeeting('${item.id}')">Abrir reunião</button><button class="btn soft small" onclick="App.toggleMeetingStatus('${item.id}')">${item.status==='done'?'Reabrir':'Concluir'}</button><button class="btn danger small" onclick="App.deleteMeeting('${item.id}')">Excluir</button>`:''}${item.kind==='action'?`<button class="btn ghost small" onclick="App.openAction('${item.id}')">Abrir ação</button>`:''}${item.kind==='report'?`<button class="btn ghost small" onclick="App.openReport('${item.id}')">Abrir relatório</button>`:''}</div></div>`).join('');return `<div class="page"><div class="section-title"><div><h2>Próximos compromissos</h2><p>Centro operacional com origem, prioridade e prazos.</p></div>${editable?`<button class="btn primary" onclick="App.editMeeting()">Nova reunião</button>`:''}</div><div class="commitment-tabs">${[['future','Próximos 30 dias'],['today','Hoje'],['week','Esta semana'],['month','30 dias'],['overdue','Atrasados'],['done','Concluídos']].map(([key,label])=>`<button class="${filter===key?'active':''}" onclick="App.setMeetingFilter('${key}')">${label}</button>`).join('')}</div><div class="field"><input type="search" placeholder="Pesquisar compromissos" oninput="App.filterMeetings(this.value)"/></div><section class="grid cols-4" style="margin-bottom:16px">${metricCard('Hoje',fmtNumber(items.filter(m=>m.status==='today').length),'◷',0,'Demandas do dia')}${metricCard('Esta semana',fmtNumber(items.filter(m=>m.status==='week').length),'▣',0,'Em até 7 dias')}${metricCard('30 dias',fmtNumber(items.filter(m=>m.status==='month').length),'⌛',0,'Em até 30 dias')}${metricCard('Atrasados',fmtNumber(items.filter(m=>m.status==='overdue').length),'!',0,'Precisam de reação')}</section><div class="grid cols-2">${cards||`<div class="empty"><div class="emoji">◷</div><h3>Nenhum compromisso nesta visão</h3></div>`}</div></div>`}
function filterMeetings(value){const q=value.trim().toLowerCase();$$('[data-meeting-search]').forEach(item=>item.classList.toggle('hidden',!item.dataset.meetingSearch.includes(q)))}
function setMeetingFilter(filter){State.meetingFilter=filter;renderPage()}
function editMeeting(id=null){const m=id?State.db.meetings.find(x=>x.id===id):null;const sectors=availableSectors();modal(`<div class="modal-head"><div><span class="eyebrow">${m?'Editar':'Nova'} reunião</span><h3>Agenda de apresentação</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="form-grid cols-2"><div class="field"><label>Título</label><input id="meetingTitle" value="${escapeHTML(m?.title||'Reunião individual — Relatório')}"/></div><div class="field"><label>Setor</label><select id="meetingSector">${sectors.map(s=>`<option value="${s}" ${m?.sector===s?'selected':''}>${SECTOR_LABELS[s]}</option>`).join('')}</select></div></div><div class="form-grid cols-3"><div class="field"><label>Data</label><input id="meetingDate" type="date" value="${m?.date||''}"/></div><div class="field"><label>Horário</label><input id="meetingTime" type="time" value="${m?.time||'09:00'}"/></div><div class="field"><label>Participante</label><input id="meetingParticipant" value="${escapeHTML(m?.participant||'')}"/></div></div><div class="field"><label>Pauta / observações</label><textarea id="meetingNotes" class="large">${escapeHTML(m?.notes||'')}</textarea></div><div class="section-actions"><button class="btn ghost" onclick="App.closeModal()">Cancelar</button><button class="btn primary" onclick="App.saveMeeting('${id||''}')">Salvar reunião</button></div>`,true)}
async function saveMeeting(id){const values={title:upperFormValue($('#meetingTitle').value),sector:$('#meetingSector').value,date:$('#meetingDate').value,time:$('#meetingTime').value,participant:upperFormValue($('#meetingParticipant').value),notes:upperFormValue($('#meetingNotes').value)};if(!values.title||!values.date)return toast('Informe o título e a data.');let m=id?State.db.meetings.find(x=>x.id===id):null;const created=!m,before=m?cloneValue(m):null;if(!m){m={id:uid('meet'),owner:State.user.name,status:'scheduled'};State.db.meetings.push(m)}Object.assign(m,values);try{await Storage.save(State.db);logAudit(id?'Atualizou reunião':'Agendou reunião',`${m.title} • ${fmtDate(m.date)} ${m.time}`);closeModal();toast('Reunião salva.');renderPage()}catch(error){if(created)State.db.meetings=State.db.meetings.filter(item=>item.id!==m.id);else restoreRecord(m,before);toast(friendlyError(error,'salvamento da reunião'))}}
async function toggleMeetingStatus(id){const m=State.db.meetings.find(x=>x.id===id);if(!m)return toast('Reunião não encontrada.');const before=cloneValue(m);m.status=m.status==='done'?'scheduled':'done';try{await Storage.save(State.db);logAudit('Alterou status da reunião',`${m.title} • ${m.status==='done'?'Concluída':'Agendada'}`);renderPage();toast('Status da reunião atualizado.')}catch(error){restoreRecord(m,before);toast(friendlyError(error,'alteração da reunião'))}}
async function deleteMeeting(id){const m=State.db.meetings.find(x=>x.id===id);if(!m||!can('meetings.edit'))return toast('Exclusão não autorizada.');if(!confirm('Excluir esta reunião?'))return;try{await Storage.remove(id)}catch(e){return toast(friendlyError(e,'exclusão de reunião'))}State.db.meetings=State.db.meetings.filter(x=>x.id!==id);logAudit('Excluiu reunião',`${m.title} • ${fmtDate(m.date)}`);toast('Reunião excluída.');renderPage()}

function generateNotifications(){if(State.db.settings.notifications===false)return [];const list=[];State.db.reports.filter(r=>sectorAllowed(r.sector)).forEach(r=>{if(r.status==='sent')list.push({id:`rep-sent-${r.id}`,icon:'▦',title:'Relatório aguardando análise',text:`${SECTOR_LABELS[r.sector]} • ${r.period}`,date:r.createdAt||r.presentation,level:'yellow'});if(r.status==='adjust'&&(State.user.role==='direction'||r.ownerId===State.user.id))list.push({id:`rep-adjust-${r.id}`,icon:'!',title:'Ajuste solicitado',text:`${SECTOR_LABELS[r.sector]} • ${r.adjustmentNote||r.period}`,date:r.updatedAt||r.presentation,level:'red'})});State.db.actions.filter(actionVisible).forEach(a=>{const d=daysUntil(a.deadline);if(!['done','cancelled'].includes(a.status)&&d<0)list.push({id:`act-over-${a.id}`,icon:'◷',title:'Plano de ação atrasado',text:`${a.title} • prazo ${fmtDate(a.deadline)}`,date:a.deadline,level:'red'});else if(!['done','cancelled'].includes(a.status)&&d>=0&&d<=3)list.push({id:`act-soon-${a.id}`,icon:'✓',title:'Prazo de ação próximo',text:`${a.title} • ${d===0?'vence hoje':`vence em ${d} dia(s)`}`,date:a.deadline,level:'yellow'})});State.db.meetings.filter(meetingVisible).forEach(m=>{const d=daysUntil(m.date);if(m.status!=='done'&&d>=0&&d<=2)list.push({id:`meet-${m.id}`,icon:'◷',title:'Reunião próxima',text:`${m.title} • ${fmtDate(m.date)} às ${m.time}`,date:m.date,level:'blue'})});operationalDiaryVisibleSectors().forEach(sector=>{const diary=operationalDiaryEntries().find(entry=>entry.sector===sector&&entry.entryDate===todayISO());if(!diary)list.push({id:`diary-missing-${sector}-${todayISO()}`,icon:'◨',title:'Diário operacional pendente',text:`${SECTOR_LABELS[sector]} ainda não registrou o diário de ${fmtDate(todayISO())}.`,date:todayISO(),level:'yellow'});const snapshot=todayOperationalDiarySnapshot(sector);if(snapshot&&sector==='financeiro'&&Math.abs(intelligenceMetric(snapshot,'divergenciaFinanceira','derivedMetrics'))>0.01)list.push({id:`diary-divergence-${snapshot.sourceId}`,icon:'R$',title:'Divergência financeira diária',text:`O diário financeiro apresenta divergência de ${fmtMoney(intelligenceMetric(snapshot,'divergenciaFinanceira','derivedMetrics'))}.`,date:snapshot.periodEnd||snapshot.sourceUpdatedAt,level:'red'});const criticalGoals=Object.values(snapshot?.goalStatus||{}).filter(goal=>goal?.status==='critical');if(snapshot&&criticalGoals.length)list.push({id:`diary-critical-${snapshot.sourceId}`,icon:'!',title:'Indicador diário crítico',text:`${SECTOR_LABELS[sector]}: ${criticalGoals[0].label} fora do limite esperado.`,date:snapshot.periodEnd||snapshot.sourceUpdatedAt,level:'red'})});if(State.user.role==='direction'){const fin=latestIntelligenceSnapshot('financeiro','semanal');if(fin&&intelligenceMetric(fin,'inadimplencia')>=State.db.settings.delinquencyAlert)list.push({id:`threshold-delinquency-${fin.sourceId||fin.periodEnd}`,icon:'R$',title:'Alerta de inadimplência',text:`O valor consolidado (${fmtMoney(intelligenceMetric(fin,'inadimplencia'))}) ultrapassou o limite configurado.`,date:fin.presentationDate||fin.periodEnd,level:'red'});const ret=latestIntelligenceSnapshot('retencao','semanal');if(ret&&intelligenceMetric(ret,'alunosRisco')>=State.db.settings.retentionRisk)list.push({id:`threshold-retention-${ret.sourceId||ret.periodEnd}`,icon:'!',title:'Alerta de retenção',text:`${fmtNumber(intelligenceMetric(ret,'alunosRisco'))} alunos em risco, acima do limite configurado.`,date:ret.presentationDate||ret.periodEnd,level:'yellow'})}return list.sort((a,b)=>String(b.date).localeCompare(String(a.date)))}
function updateNotificationBadge(){const n=generateNotifications().filter(x=>!State.db.readNotifications.includes(x.id)).length;const b=$('#notificationCount');if(b)b.textContent=n}
function renderNotifications(){const arr=generateNotifications();return `<div class="page"><div class="section-title"><div><h2>Notificações</h2><p>Alertas automáticos de relatórios, prazos, reuniões e indicadores críticos.</p></div><button class="btn ghost" onclick="App.markAllNotificationsRead()">Marcar todas como lidas</button></div><div class="notification-list">${arr.map(n=>`<div class="notification ${State.db.readNotifications.includes(n.id)?'':'unread'}"><div class="notification-icon">${n.icon}</div><div style="flex:1"><h4>${escapeHTML(n.title)}</h4><p>${escapeHTML(n.text)}</p><time>${fmtDateTime(n.date)}</time></div>${!State.db.readNotifications.includes(n.id)?`<button class="btn ghost small" onclick="App.markNotificationRead('${n.id}')">Marcar lida</button>`:''}</div>`).join('')||`<div class="empty"><div class="emoji">🔔</div><h3>Nenhuma notificação</h3><p>Está tudo em dia.</p></div>`}</div></div>`}
async function markNotificationRead(id){const before=[...State.db.readNotifications];if(!State.db.readNotifications.includes(id))State.db.readNotifications.push(id);try{await Storage.save(State.db);renderPage()}catch(error){State.db.readNotifications=before;toast(friendlyError(error,'leitura da notificação'))}}
