function legacySetWhatsAppTab(tab){if(!whatsappTabs().some(x=>x[0]===tab))return;State.whatsappTab=tab;renderPage()}
function setWhatsAppSearch(value){State.whatsappSearch=value||'';renderPage()}
function whatsappState(){const scope=State.user?.accessScope==='all_sectors'?'Todas as unidades':'Unidade do usuário';return {...State.whatsappConnection,unit:scope,provider:State.whatsappConnection?.provider||'Evolution API'}}
async function evolutionRequest(action,payload={},method='POST'){
  const options={method,headers:{'Content-Type':'application/json'}};
  if(method!=='GET')options.body=JSON.stringify({action,...payload});
  const url=method==='GET'?`/api/evolution?action=${encodeURIComponent(action)}`:'/api/evolution';
  const response=await fetch(url,options);
  const data=await response.json().catch(()=>({}));
  if(!response.ok||data.error)throw Object.assign(new Error(data.error||'Falha na integração com Evolution API.'),{response,data,status:response.status});
  return data;
}
function normalizeWhatsAppConnection(data={}){
  const qr=data.qrcode?.base64||data.qrcode?.qrcode?.base64||data.raw?.qrcode?.base64||State.whatsappConnection?.qrcode||null;
  return {...State.whatsappConnection,configured:data.configured!==false,missing:data.missing||[],status:data.status||data.raw?.instance?.status||State.whatsappConnection?.status||'Desconhecido',connected:Boolean(data.connected),device:data.device||State.whatsappConnection?.device||'WhatsApp Business',number:formatPhoneBR(data.number||State.whatsappConnection?.number||''),lastSync:data.lastSync?fmtDateTime(data.lastSync):new Date().toLocaleString('pt-BR'),qrcode:qr}
}
async function refreshWhatsAppConnection({quiet=false}={}){
  if(State.whatsappRuntimeLoading)return;
  State.whatsappRuntimeLoading=true;
  try{
    const config=await evolutionRequest('config',{},'GET');
    if(!config.configured){
      State.whatsappConnection={...State.whatsappConnection,configured:false,status:'Evolution API não configurada',missing:config.missing||[],lastSync:new Date().toLocaleString('pt-BR')};
      if(!quiet)toast(`Configure na Vercel: ${(config.missing||[]).join(', ')}`);
      return;
    }
    const status=await evolutionRequest('status',{},'GET');
    State.whatsappConnection=normalizeWhatsAppConnection(status);
    if(!quiet)toast('Status do WhatsApp atualizado.');
  }catch(error){
    console.error('[Purple Gestão] WhatsApp/Evolution',error);
    State.whatsappConnection={...State.whatsappConnection,status:'Desconectado',connected:false,lastSync:new Date().toLocaleString('pt-BR'),error:error.message};
    if(!quiet)toast('Não foi possível consultar a Evolution API.');
  }finally{
    State.whatsappRuntimeLoading=false;
    if(State.page==='whatsapp')renderPage();
  }
}
function scheduleWhatsAppRuntimeRefresh(){if(State.whatsappRuntimeLoading||State.whatsappRuntimeLoaded)return;State.whatsappRuntimeLoaded=true;setTimeout(()=>refreshWhatsAppConnection({quiet:true}),0)}
function whatsappExtraMessages(id){return (State.whatsappMessages||[]).filter(msg=>msg.conversationId===id).map(msg=>({from:'agent',at:msg.at,text:msg.text}))}
function whatsappConversationSeed(){
  const students=(State.db.students||[]).slice(0,8).map((student,index)=>{const id=`student-${student.id}`,baseMessages=[{from:'contact',at:'09:12',text:`Olá, gostaria de confirmar informações sobre ${student.name||'o aluno'}.`},{from:'agent',at:'09:18',text:'Olá! Vou verificar os dados no Purple Gestão e retorno por aqui.'}];return {id,name:student.name||'Aluno Purple',phone:formatPhoneBR(student.whatsapp||student.phone||student.guardianPhone||'(27)99205-2581'),type:'Aluno',tag:index%2?'Aluno':'Responsável',unread:index===0?2:0,favorite:index===1,pending:index<3,stage:index<2?'Em Atendimento':index<4?'Aguardando Resposta':'Aluno Ativo',sentiment:index===0?'atenção':'estável',linkedStudent:student.name||'',className:classLabelById(student.classId),teacher:teacherLabelById(student.teacherId),financial:student.financialStatus||'—',frequency:`${fmtNumber(student.frequency||0,1)}%`,lastPayment:student.financialStatus==='Em dia'?'Mensalidade regular':'Verificar pendência',occurrences:student.occurrences||'Sem ocorrência crítica',nextClass:'Próxima aula conforme TWR',lastService:student.timeline?.[0]?.title||'Atendimento inicial',tags:[student.situation||'Ativo',student.financialStatus||'Financeiro'],last:`${student.guardian||'Responsável'} • ${student.situation||'Acompanhamento ativo'}`,messages:[...baseMessages,...whatsappExtraMessages(id)]}});
  const fallback=[{id:'lead-1',name:'Lead novo — Conversation',phone:'(27)99205-2581',type:'Lead',tag:'Lead',unread:1,favorite:false,pending:true,stage:'Novo Lead',sentiment:'quente',linkedStudent:'Ainda não vinculado',className:'Interesse em inglês',teacher:'—',financial:'Sem contrato',frequency:'—',lastPayment:'—',occurrences:'Solicitou valores e horários',nextClass:'Aguardando agendamento',lastService:'Primeiro contato comercial',tags:['Lead','Comercial'],last:'Pediu valores e horários disponíveis.',messages:[{from:'contact',at:'10:05',text:'Bom dia! Gostaria de saber os horários de inglês.'},{from:'agent',at:'10:08',text:'Bom dia! Posso te ajudar com as opções da Purple.'},...whatsappExtraMessages('lead-1')]},{id:'teacher-1',name:'Professor — alinhamento',phone:'Interno',type:'Professor',tag:'Professor',unread:0,favorite:true,pending:false,stage:'Finalizadas',sentiment:'estável',linkedStudent:'—',className:'Turmas da semana',teacher:(State.db.teachers||[])[0]?.name||'Equipe pedagógica',financial:'—',frequency:'—',lastPayment:'—',occurrences:'Alinhamento pedagógico',nextClass:'Ver TWR',lastService:'Planejamento semanal',tags:['Professor','Pedagógico'],last:'Alinhamento sobre planejamento semanal.',messages:[{from:'contact',at:'08:40',text:'Preciso confirmar o material da aula de hoje.'},{from:'agent',at:'08:46',text:'Perfeito. Acesse o TWR e confira a preparação inteligente da aula.'},...whatsappExtraMessages('teacher-1')]}];
  return students.length?students.concat(fallback):fallback
}
function whatsappConversations(){const list=whatsappConversationSeed(),filter=State.whatsappFilter||'all',query=String(State.whatsappSearch||'').toLowerCase().trim();return list.filter(item=>(!query||`${item.name} ${item.phone} ${item.last} ${item.linkedStudent} ${item.tags?.join(' ')}`.toLowerCase().includes(query))&&(filter==='all'||(filter==='unread'&&item.unread>0)||(filter==='today'&&item.pending)||(filter==='yesterday'&&item.favorite)||(filter==='week'&&item.type!=='Professor')||(filter==='favorite'&&item.favorite)||(filter==='ai'&&item.sentiment==='atenção')||(filter==='noresponse'&&item.pending)||(filter==='closed'&&item.stage==='Finalizadas')||(filter==='lead'&&item.type==='Lead')||(filter==='students'&&item.type==='Aluno')||(filter==='teachers'&&item.type==='Professor')))}
function whatsappActiveConversation(){const all=whatsappConversationSeed();return all.find(item=>item.id===State.whatsappConversationId)||whatsappConversations()[0]||all[0]}
function setWhatsAppConversation(id){State.whatsappConversationId=id;State.whatsappTab='conversations';renderPage()}
function setWhatsAppFilter(filter){State.whatsappFilter=filter;State.whatsappConversationId='';renderPage()}
async function whatsappConnectionAction(action){
  if(!can('whatsapp.manage'))return toast('Somente usuários autorizados podem gerenciar a conexão.');
  try{
    if(action==='refresh')return refreshWhatsAppConnection();
    const result=await evolutionRequest(action,{});
    if(action==='disconnect'){
      State.whatsappConnection={...State.whatsappConnection,connected:false,status:'Desconectado',qrcode:null,lastSync:new Date().toLocaleString('pt-BR')};
      toast('WhatsApp desconectado.');
      return renderPage();
    }
    State.whatsappConnection=normalizeWhatsAppConnection(result);
    State.whatsappConnection.status=result.status||'Aguardando leitura do QR Code';
    toast(action==='reconnect'?'Reconexão solicitada.':'Conexão iniciada.');
    renderPage();
  }catch(error){
    console.error('[Purple Gestão] Falha na ação do WhatsApp',error);
    const missing=error.data?.missing?.join(', ');
    State.whatsappConnection={...State.whatsappConnection,status:'Erro de conexão',error:error.message,lastSync:new Date().toLocaleString('pt-BR'),missing:error.data?.missing||State.whatsappConnection.missing};
    toast(missing?`Configure na Vercel: ${missing}`:'Não foi possível concluir a ação no WhatsApp.');
    renderPage();
  }
}
