function writeWhatsAppWithAI(mode='reply'){const active=whatsappActiveConversation(),field=$('#whatsappComposer');const texts={reply:`Olá, ${active?.name?.split(' ')[0]||'tudo bem'}! Revisei seu histórico aqui na Purple e quero te ajudar da forma mais simples possível. Pode me confirmar o melhor horário para conversarmos?`,summary:`Resumo: ${active?.name||'Contato'} está em ${active?.stage||'atendimento'}, financeiro ${active?.financial||'—'} e última demanda: ${active?.last||'—'}.`,risk:`Atenção: este contato merece acompanhamento porque há pendência de resposta, situação financeira ou risco operacional. Sugestão: registrar follow-up ainda hoje.`};if(field){field.value=texts[mode]||texts.reply;field.focus?.();toast('Sugestão preparada pela Purple IA. Revise antes de enviar.')}else modal(`<div class="modal-head"><div><span class="eyebrow">Assistente Purple</span><h3>Análise da conversa</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><p class="muted">${escapeHTML(texts[mode]||texts.summary)}</p><div class="section-actions"><button class="btn primary" onclick="App.closeModal()">Fechar</button></div>`,true)}
function openWhatsAppAiAction(action){writeWhatsAppWithAI(action)}
function openWhatsAppAttachment(type){const input=$('#whatsappFileInput');if(input){input.dataset.kind=type||'document';input.click();return}toast('Abra uma conversa para anexar arquivos.')}
function appendWhatsAppTimeline(active,title,detail){const student=serviceCenterActiveStudent(active);if(!student)return;student.timeline=student.timeline||[];student.timeline.unshift({id:uid(),date:todayISO(),type:'whatsapp',title,detail,by:State.user?.name||'Purple'});Storage.save(State.db)}
async function sendWhatsAppFile(file){const active=whatsappActiveConversation();if(!file||!active)return;const number=String(active.phone||'').replace(/\D/g,'');if(!number)return toast('Esta conversa não possui telefone válido para envio.');const reader=new FileReader();reader.onload=async()=>{try{const media=String(reader.result||'').split(',')[1]||reader.result;const mediatype=file.type.startsWith('image/')?'image':file.type.startsWith('audio/')?'audio':file.type.startsWith('video/')?'video':'document';State.whatsappMessages=State.whatsappMessages||[];State.whatsappMessages.push({conversationId:active.id,text:`Arquivo enviado: ${file.name}`,at:new Date().toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'}),createdAt:new Date().toISOString(),user:State.user?.name||'Purple'});appendWhatsAppTimeline(active,'Arquivo enviado pelo WhatsApp',file.name);renderPage();await evolutionRequest('sendMedia',{number,media,mediatype,mimetype:file.type||'application/octet-stream',fileName:file.name,caption:''});toast('Arquivo enviado pelo WhatsApp.')}catch(error){console.error('[Purple Gestão] Envio de arquivo WhatsApp',error);toast('Arquivo registrado na conversa, mas o envio real falhou. Verifique a Evolution API.')}};reader.readAsDataURL(file)}
async function sendWhatsAppMessage(){const field=$('#whatsappComposer'),text=field?.value.trim(),active=whatsappActiveConversation();if(!text)return toast('Escreva uma mensagem antes de enviar.');const number=String(active?.phone||'').replace(/\D/g,'');State.whatsappMessages=State.whatsappMessages||[];State.whatsappMessages.push({conversationId:active.id,text,at:new Date().toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'}),createdAt:new Date().toISOString(),user:State.user?.name||'Purple'});appendWhatsAppTimeline(active,'Mensagem enviada pelo WhatsApp',text);field.value='';renderPage();if(!number)return toast('Mensagem registrada. Esta conversa não possui telefone válido para envio real.');try{await evolutionRequest('sendText',{number,text});toast('Mensagem enviada pelo WhatsApp.')}catch(error){console.error('[Purple Gestão] Envio WhatsApp',error);toast('Mensagem registrada na conversa, mas o envio real falhou. Verifique a Evolution API.')}}
function openWhatsAppCrmCard(stage){modal(`<div class="modal-head"><div><span class="eyebrow">CRM WhatsApp</span><h3>${escapeHTML(stage)}</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><p class="muted">Etapa operacional do pipeline. O drag-and-drop real será ligado quando o serviço de conversas estiver persistindo dados no backend.</p><div class="section-actions"><button class="btn primary" onclick="App.closeModal()">Fechar</button></div>`,true)}
function openWhatsAppCampaignPreview(){modal(`<div class="modal-head"><div><span class="eyebrow">Campanhas</span><h3>Prévia de disparo controlado</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="grid cols-3">${metricCard('Público estimado',fmtNumber((State.db.students||[]).length),'◉',0,'Alunos filtrados')}${metricCard('Com WhatsApp',fmtNumber((State.db.students||[]).filter(s=>s.whatsapp||s.phone).length),'☏',0,'Contatos válidos')}${metricCard('Envio real','Pendente','!',0,'Exige API oficial')}</div><p class="muted" style="margin-top:12px">Nenhuma mensagem em massa foi enviada. Esta etapa apenas valida filtros e volume antes da integração oficial.</p><div class="section-actions"><button class="btn primary" onclick="App.closeModal()">Fechar prévia</button></div>`,true)}
function openWhatsAppAutomation(name){toast(`${name} preparado para automação futura. Nenhum disparo automático foi ativado.`)}
async function saveServiceFollowUp(){const active=whatsappActiveConversation(),note=$('#centralFollowUpNote')?.value.trim(),kind=$('#centralFollowUpType')?.value||'Contato realizado',next=$('#centralFollowUpDate')?.value||todayISO();if(!active)return toast('Selecione uma conversa.');if(!note)return toast('Informe o resumo do follow-up.');State.whatsappMessages=State.whatsappMessages||[];const message={conversationId:active.id,text:`Follow-up registrado: ${kind} • ${note}`,at:new Date().toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'}),createdAt:new Date().toISOString(),user:State.user?.name||'Purple'};State.whatsappMessages.push(message);const student=serviceCenterActiveStudent(active),before=student?cloneValue(student):null;if(student){student.followUpEntries=student.followUpEntries||[];student.followUpEntries.unshift({id:uid(),date:todayISO(),time:new Date().toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'}),employee:State.user?.name||'Purple',type:kind,nextDate:next,subject:note,done:true});student.timeline=student.timeline||[];student.timeline.unshift({id:uid(),date:todayISO(),type:'followup',title:`Follow-up: ${kind}`,detail:note,by:State.user?.name||'Purple'});}try{if(student)await saveStudentRecord(student);toast('Follow-up salvo na conversa e na timeline do aluno.');renderPage()}catch(error){State.whatsappMessages=State.whatsappMessages.filter(item=>item!==message);if(student)restoreRecord(student,before);toast(friendlyError(error,'salvamento do follow-up'))}}
function saveWhatsAppTemplate(){toast('Modelo salvo como rascunho local da estrutura. Persistência definitiva depende da tabela de templates.')}
function saveWhatsAppLabel(){toast('Etiqueta preparada. Persistência definitiva depende da integração de CRM.')}
function renderWhatsAppModuleMenu(){return `<aside class="whatsapp-module-menu">${whatsappTabs().map(([key,icon,label])=>`<button class="${State.whatsappTab===key?'active':''}" onclick="App.setWhatsAppTab('${key}')"><span>${appIcon(icon)}</span><b>${label}</b></button>`).join('')}</aside>`}
function renderWhatsAppConnection(){const info=whatsappState(),canManage=can('whatsapp.manage'),missing=(info.missing||[]).join(', ');return `<section class="panel whatsapp-connection-full"><div class="panel-head"><div><span class="eyebrow">Conexões</span><h3>WhatsApp Business da Purple</h3><small>${escapeHTML(info.unit)} • ${escapeHTML(info.provider)}</small></div><span class="status ${info.connected?'success':'warning'}">${escapeHTML(info.status)}</span></div>${missing?`<div class="alert warning"><div class="alert-icon">!</div><div><b>Evolution API não configurada</b><span>Configure na Vercel: ${escapeHTML(missing)}. A interface permanece disponível, mas envio/QR reais dependem dessas variáveis.</span></div></div>`:''}<div class="whatsapp-connection-grid"><div class="whatsapp-qr large" aria-label="QR Code">${info.qrcode?`<img src="${escapeHTML(info.qrcode)}" alt="QR Code do WhatsApp" />`:'<div></div>'}<span>${info.qrcode?'Escaneie para conectar':'QR Code'}</span><small>${info.qrcode?'Aponte o WhatsApp Business para este código.':'Clique em Conectar para solicitar um QR Code à Evolution API.'}</small></div><div class="contact-facts"><span><b>Status</b>${escapeHTML(info.status)}</span><span><b>Aparelho conectado</b>${escapeHTML(info.device)}</span><span><b>Número conectado</b>${escapeHTML(info.number)}</span><span><b>Foto do perfil</b>${escapeHTML(info.profile)}</span><span><b>Última sincronização</b>${escapeHTML(info.lastSync)}</span></div></div><div class="section-actions">${canManage?`<button class="btn primary small" onclick="App.whatsappConnectionAction('connect')">Conectar</button><button class="btn ghost small" onclick="App.whatsappConnectionAction('reconnect')">Reconectar</button><button class="btn soft small" onclick="App.whatsappConnectionAction('refresh')">Atualizar</button><button class="btn danger small" onclick="App.whatsappConnectionAction('disconnect')">Desconectar</button>`:'<span class="muted">Somente Direção pode gerenciar a conexão.</span>'}</div></section>`}
function renderWhatsAppConversationList(){const filters=[['all','Todas'],['unread','Não lidas'],['today','Hoje'],['yesterday','Ontem'],['week','Esta semana'],['favorite','Favoritas'],['ai','Com IA'],['noresponse','Sem resposta'],['closed','Finalizadas']],list=whatsappConversations(),active=whatsappActiveConversation();return `<aside class="whatsapp-list"><div class="field"><input type="search" value="${escapeHTML(State.whatsappSearch||'')}" placeholder="Pesquisar conversas, alunos, pais ou telefone" oninput="App.setWhatsAppSearch(this.value)" /></div><div class="whatsapp-filters">${filters.map(([key,label])=>`<button class="${State.whatsappFilter===key?'active':''}" onclick="App.setWhatsAppFilter('${key}')">${label}</button>`).join('')}</div><div class="whatsapp-conversations">${list.map(item=>`<button class="whatsapp-conversation ${active?.id===item.id?'active':''}" onclick="App.setWhatsAppConversation('${item.id}')"><span class="whatsapp-avatar">${escapeHTML(item.name.charAt(0))}</span><span><b>${escapeHTML(item.name)}</b><small>${escapeHTML(item.last)}</small></span>${item.unread?`<i>${item.unread}</i>`:''}</button>`).join('')||'<div class="empty"><h3>Nenhuma conversa neste filtro</h3></div>'}</div></aside>`}
function renderWhatsAppThread(){const active=whatsappActiveConversation();if(!active)return `<section class="whatsapp-chat empty"><h3>Nenhuma conversa selecionada</h3></section>`;const canReply=can('whatsapp.reply');return `<section class="whatsapp-chat"><header><div><span class="eyebrow">${escapeHTML(active.tag)} • ${escapeHTML(active.stage)}</span><h3>${escapeHTML(active.name)}</h3><small>${escapeHTML(active.phone)}</small></div><span class="badge">${escapeHTML(active.type)}</span></header><div class="whatsapp-messages">${active.messages.map(msg=>`<div class="whatsapp-message ${msg.from==='agent'?'agent':'contact'}"><p>${escapeHTML(msg.text)}</p><time>${escapeHTML(msg.at)}</time></div>`).join('')}</div><div class="whatsapp-templates"><button onclick="App.openWhatsAppTemplate('welcome')">Boas-vindas</button><button onclick="App.openWhatsAppTemplate('followup')">Follow-up</button><button onclick="App.openWhatsAppTemplate('billing')">Cobrança</button><button onclick="App.openWhatsAppTemplate('rematricula')">Rematrícula</button><button onclick="App.openWhatsAppTemplate('classConfirm')">Confirmação</button></div><div class="whatsapp-composer"><div class="section-actions"><button class="btn ghost small" onclick="App.openWhatsAppAttachment('Imagem')">Imagem</button><button class="btn ghost small" onclick="App.openWhatsAppAttachment('PDF')">PDF</button><button class="btn ghost small" onclick="App.openWhatsAppAttachment('Documento')">Documento</button><button class="btn ghost small" onclick="App.openWhatsAppAttachment('Áudio')">Áudio</button><button class="btn ghost small" onclick="App.openWhatsAppAttachment('Vídeo')">Vídeo</button><button class="btn ghost small" onclick="App.openWhatsAppAttachment('Emoji')">Emoji</button></div><textarea id="whatsappComposer" ${canReply?'':'disabled'} placeholder="${canReply?'Escreva uma mensagem...':'Seu perfil não possui permissão para responder.'}"></textarea><div class="section-actions"><button class="btn ghost small" onclick="App.openWhatsAppAiAction('reply')" ${canReply?'':'disabled'}>✨ Sugerir resposta</button><button class="btn soft small" onclick="App.openWhatsAppAiAction('summary')">Resumir</button><button class="btn soft small" onclick="App.openWhatsAppAiAction('risk')">Risco</button><button class="btn primary small" onclick="App.sendWhatsAppMessage()" ${canReply?'':'disabled'}>Enviar</button></div></div></section>`}
function renderWhatsAppContactPanel(){const active=whatsappActiveConversation();if(!active)return '';return `<aside class="whatsapp-contact"><div class="panel-head"><div><span class="eyebrow">Painel inteligente</span><h3>${escapeHTML(active.name)}</h3><small>${escapeHTML(active.phone)}</small></div></div><div class="contact-facts"><span><b>Aluno vinculado</b>${escapeHTML(active.linkedStudent||'—')}</span><span><b>Responsável</b>${escapeHTML(active.tag||'—')}</span><span><b>Turma</b>${escapeHTML(active.className||'—')}</span><span><b>Professor</b>${escapeHTML(active.teacher||'—')}</span><span><b>Financeiro</b>${escapeHTML(active.financial||'—')}</span><span><b>Frequência</b>${escapeHTML(active.frequency||'—')}</span><span><b>Último pagamento</b>${escapeHTML(active.lastPayment||'—')}</span><span><b>Ocorrências</b>${escapeHTML(active.occurrences||'—')}</span><span><b>Próxima aula</b>${escapeHTML(active.nextClass||'—')}</span><span><b>Último atendimento</b>${escapeHTML(active.lastService||'—')}</span></div><div class="whatsapp-tag-list">${(active.tags||[]).map(tag=>`<span>${escapeHTML(tag)}</span>`).join('')}</div><div class="form-card"><h3>Linha do tempo</h3><p class="muted">Mensagens futuras serão vinculadas automaticamente à Timeline do aluno, follow-up e auditoria.</p></div></aside>`}
function renderWhatsAppConversations(){return `<div class="whatsapp-layout">${renderWhatsAppConversationList()}${renderWhatsAppThread()}${renderWhatsAppContactPanel()}</div>`}
function renderWhatsAppCRM(){const stages=['Novo Lead','Primeiro Contato','Em Atendimento','Aguardando Resposta','Visita Agendada','Aula Experimental','Negociação','Documentação','Matrícula Confirmada','Aluno Ativo','Rematrícula','Perdido','Cancelado'];const conversations=whatsappConversationSeed();return `<section class="whatsapp-kanban">${stages.map(stage=>{const cards=conversations.filter(c=>c.stage===stage||(stage==='Novo Lead'&&c.type==='Lead')||(stage==='Aluno Ativo'&&c.type==='Aluno'&&!c.pending)).slice(0,4);return `<div class="kanban-column"><h3>${escapeHTML(stage)} <small>${fmtNumber(cards.length)}</small></h3>${cards.map(card=>`<button class="kanban-card" onclick="App.openWhatsAppCrmCard('${escapeHTML(stage)}')"><b>${escapeHTML(card.name)}</b><span>${escapeHTML(card.last)}</span></button>`).join('')||'<p class="muted">Sem contatos nesta etapa.</p>'}</div>`}).join('')}</section>`}
function renderWhatsAppTemplates(){const cats=['Comercial','Financeiro','Pedagógico','Secretaria','Rematrícula','Cobrança','Reposição','Boas-vindas','Aniversário','Documentos','Professor'];return `<section class="panel"><div class="panel-head"><div><span class="eyebrow">Mensagens rápidas</span><h3>Biblioteca com variáveis</h3><small>Use {{nome}}, {{turma}}, {{professor}}, {{valor}} e {{vencimento}}</small></div><button class="btn primary small" onclick="App.saveWhatsAppTemplate()">Salvar modelo</button></div><div class="grid cols-3">${cats.map(cat=>`<div class="form-card"><h3>${escapeHTML(cat)}</h3><p class="muted">${escapeHTML(whatsappTemplateText(cat==='Financeiro'?'billing':cat==='Rematrícula'?'rematricula':cat==='Boas-vindas'?'welcome':'followup'))}</p></div>`).join('')}</div></section>`}
function renderWhatsAppCampaigns(){return `<section class="panel"><div class="panel-head"><div><span class="eyebrow">Campanhas</span><h3>Disparos controlados</h3><small>Selecione público antes de qualquer envio.</small></div><button class="btn primary small" onclick="App.openWhatsAppCampaignPreview()">Visualizar quantidade</button></div><div class="form-grid cols-3"><div class="field"><label>Turma</label><select><option>Todas</option>${(State.db.classes||[]).map(c=>`<option>${escapeHTML(c.name)}</option>`).join('')}</select></div><div class="field"><label>Professor</label><select><option>Todos</option>${(State.db.teachers||[]).map(t=>`<option>${escapeHTML(t.name)}</option>`).join('')}</select></div><div class="field"><label>Situação</label><select><option>Todos</option><option>Ativo</option><option>Rematrícula</option><option>Inadimplente</option><option>Prospect</option></select></div><div class="field"><label>Curso</label><input placeholder="Ex.: Inglês, Espanhol"/></div><div class="field"><label>Data de envio</label><input type="date" value="${todayISO()}"/></div><div class="field"><label>Status</label><select><option>Rascunho</option><option>Aguardando aprovação</option></select></div></div></section>`}
function renderWhatsAppAutomations(){const items=['Boas-vindas','Confirmação de matrícula','Lembrete de aula','Cobrança','Aniversário','Reposição','Reunião','Rematrícula','Pesquisa de satisfação'];return `<section class="grid cols-3">${items.map(name=>`<div class="panel"><div class="panel-head"><div><span class="eyebrow">Automação</span><h3>${escapeHTML(name)}</h3><small>Preparada para integração futura</small></div></div><button class="btn ghost small" onclick="App.openWhatsAppAutomation('${escapeHTML(name)}')">Configurar</button></div>`).join('')}</section>`}
function renderWhatsAppLabels(){const labels=['Lead quente','Cobrança','Rematrícula','Reposição','Pedagógico','Documentos','Aguardando resposta','Risco de evasão'];return `<section class="panel"><div class="panel-head"><div><span class="eyebrow">Etiquetas</span><h3>Organização dos atendimentos</h3></div><button class="btn primary small" onclick="App.saveWhatsAppLabel()">Nova etiqueta</button></div><div class="whatsapp-tag-list large">${labels.map(label=>`<span>${escapeHTML(label)}</span>`).join('')}</div></section>`}
function renderWhatsAppReports(){const total=whatsappConversationSeed().length,unread=whatsappConversationSeed().filter(x=>x.unread).length,pending=whatsappConversationSeed().filter(x=>x.pending).length,leads=whatsappConversationSeed().filter(x=>x.type==='Lead').length;return `<section class="grid cols-4">${metricCard('Conversas',fmtNumber(total),'☏',0,'Base atual')}${metricCard('Não lidas',fmtNumber(unread),'!',0,'Exigem resposta')}${metricCard('Pendentes',fmtNumber(pending),'◷',0,'Sem finalização')}${metricCard('Leads',fmtNumber(leads),'↗',0,'Origem comercial')}</section><section class="panel" style="margin-top:14px"><div class="panel-head"><div><h3>Indicadores de atendimento</h3><small>Tempo médio, conversões e origem de matrícula serão calculados pela API real.</small></div></div><div class="kpi-strip"><span><b>Tempo médio:</b> Aguardando sincronização</span><span><b>Atendimentos por colaborador:</b> Estrutura pronta</span><span><b>Matrículas originadas:</b> Estrutura pronta</span></div></section>`}
function renderWhatsAppSettings(){return `<section class="panel"><div class="panel-head"><div><span class="eyebrow">Configurações</span><h3>WhatsApp e canais</h3><small>Área administrativa. A secretária trabalha na Central; conexão fica aqui.</small></div></div><div class="contact-facts"><span><b>Modelo</b>Um número por unidade ou departamento.</span><span><b>Sessão</b>Persistência via Evolution API.</span><span><b>Segurança</b>Responder somente com permissão whatsapp.reply.</span><span><b>Auditoria</b>Registrar usuário, data, hora e mensagem enviada.</span></div><div class="section-actions" style="justify-content:flex-start;margin-top:12px"><button class="btn primary small" onclick="App.openWhatsAppDrawer('connections')">Gerenciar conexão</button></div></section>`}
function renderWhatsAppMain(){if(State.whatsappTab==='connections')return renderWhatsAppConnection();if(State.whatsappTab==='crm')return renderWhatsAppCRM();if(State.whatsappTab==='campaigns')return renderWhatsAppCampaigns();if(State.whatsappTab==='templates')return renderWhatsAppTemplates();if(State.whatsappTab==='automations')return renderWhatsAppAutomations();if(State.whatsappTab==='labels')return renderWhatsAppLabels();if(State.whatsappTab==='reports')return renderWhatsAppReports();if(State.whatsappTab==='settings')return renderWhatsAppSettings();return renderWhatsAppConversations()}
function legacyRenderWhatsApp(){if(!canOpenWhatsApp())return `<div class="page"><div class="empty"><div class="emoji">🔒</div><h3>Acesso restrito</h3></div></div>`;return `<div class="page whatsapp-page"><section class="hero whatsapp-hero"><div class="hero-content"><div><span class="eyebrow light">Central de comunicação</span><h2>WhatsApp como CRM de atendimento da Purple.</h2><p>Conversas, pipeline, campanhas, mensagens rápidas, automações, relatórios e contexto do aluno em um módulo nativo. Sem iframe.</p></div><div class="hero-badge">Preparado para API oficial</div></div></section><div class="whatsapp-module-shell">${renderWhatsAppModuleMenu()}<main class="whatsapp-module-main">${renderWhatsAppMain()}</main></div></div>`}

function serviceCenterDrawers(){return {connections:'Conexão do WhatsApp',details:'Dados do aluno',financial:'Financeiro',frequency:'Frequência',occurrences:'Ocorrências',documents:'Documentos',followup:'Follow-up',templates:'Mensagens rápidas'}}
function serviceCenterStages(){return ['Nova','Em atendimento','Aguardando resposta','Resolvida','Arquivada']}
function openWhatsAppDrawer(type){State.whatsappDrawer=type||'';renderPage()}
function closeWhatsAppDrawer(){State.whatsappDrawer='';renderPage()}
function setWhatsAppTab(tab){const map={connections:'connections',conversations:'',crm:'crm',campaigns:'campaigns',templates:'templates',automations:'automations',labels:'crm',reports:'reports',settings:'settings'};State.whatsappDrawer=map[tab]||'';renderPage()}
function setWhatsAppCrmStatus(id,stage){if(!id||!stage)return;State.whatsappStages=State.whatsappStages||{};State.whatsappStages[id]=stage;appendWhatsAppTimeline(whatsappConversationSeed().find(item=>item.id===id),`Status do CRM alterado para ${stage}`,'Central de Atendimento');toast(`Status do atendimento alterado para ${stage}.`);renderPage()}
function serviceCenterActiveStudent(active){if(!active?.id?.startsWith('student-'))return null;const studentId=active.id.replace(/^student-/,'');return (State.db.students||[]).find(s=>s.id===studentId)||null}
function serviceCenterFilters(){return [['all','Todas'],['unread','Não lidas'],['today','Hoje'],['week','Semana'],['noresponse','Sem resposta'],['students','Alunos'],['lead','Leads']]}
function renderServiceConversationList(){const list=whatsappConversations(),active=whatsappActiveConversation();return `<aside class="service-conversations"><div class="service-panel-title"><div><span class="eyebrow">Entrada</span><h2>Conversas</h2></div><span class="service-status-dot ${State.whatsappConnection?.connected?'online':''}" title="${escapeHTML(State.whatsappConnection?.status||'')}"></span></div><div class="field service-search"><input type="search" value="${escapeHTML(State.whatsappSearch||'')}" placeholder="Buscar por nome ou telefone" oninput="App.setWhatsAppSearch(this.value)"/></div><div class="whatsapp-filters compact">${serviceCenterFilters().map(([key,label])=>`<button class="${State.whatsappFilter===key?'active':''}" onclick="App.setWhatsAppFilter('${key}')">${label}</button>`).join('')}</div><div class="service-conversation-list">${list.map(item=>`<button class="service-conversation ${active?.id===item.id?'active':''}" onclick="App.setWhatsAppConversation('${item.id}')"><span class="whatsapp-avatar">${escapeHTML(item.name.charAt(0))}</span><span><b>${escapeHTML(item.name)}</b><small>${escapeHTML(item.last)}</small><em>${escapeHTML(item.phone)}</em></span>${item.unread?`<i>${item.unread}</i>`:''}</button>`).join('')||'<div class="empty"><h3>Nenhuma conversa</h3><p>Ajuste a busca ou os filtros.</p></div>'}</div></aside>`}
function renderServiceChat(active){if(!active)return `<section class="service-chat empty"><h3>Selecione uma conversa</h3></section>`;const canReply=can('whatsapp.reply'),currentStage=State.whatsappStages?.[active.id]||active.stage,stages=serviceCenterStages();return `<section class="service-chat"><header class="service-chat-head"><div><h2>${escapeHTML(active.name)}</h2><small><span class="service-online">● WhatsApp</span> ${escapeHTML(active.phone||'—')} • ${escapeHTML(active.className||'—')}</small></div><div class="service-chat-controls"><label>Atendimento<select onchange="App.setWhatsAppCrmStatus('${active.id}',this.value)"><option value="${escapeHTML(currentStage)}">${escapeHTML(currentStage||'Em atendimento')}</option>${stages.filter(stage=>stage!==currentStage).map(stage=>`<option value="${escapeHTML(stage)}">${escapeHTML(stage)}</option>`).join('')}</select></label></div></header><div class="whatsapp-messages service-messages">${active.messages.map(msg=>`<div class="whatsapp-message ${msg.from==='agent'?'agent':'contact'}"><p>${escapeHTML(msg.text)}</p><time>${escapeHTML(msg.at)}</time></div>`).join('')}</div><div class="service-composer"><input id="whatsappFileInput" type="file" hidden onchange="App.sendWhatsAppFile(this.files&&this.files[0])" /><textarea id="whatsappComposer" ${canReply?'':'disabled'} placeholder="${canReply?'Digite sua resposta...':'Seu perfil não possui permissão para responder.'}"></textarea><div class="service-composer-actions"><button title="Anexo" onclick="App.openWhatsAppAttachment('Anexo')" ${canReply?'':'disabled'}>📎 Anexo</button><button title="Imagem" onclick="App.openWhatsAppAttachment('Imagem')" ${canReply?'':'disabled'}>📷 Imagem</button><button title="PDF" onclick="App.openWhatsAppAttachment('PDF')" ${canReply?'':'disabled'}>📄 PDF</button><button title="Áudio" onclick="App.openWhatsAppAttachment('Áudio')" ${canReply?'':'disabled'}>🎤 Áudio</button><button onclick="App.openWhatsAppDrawer('templates')" ${canReply?'':'disabled'}>Modelo</button><button onclick="App.openWhatsAppDrawer('followup')">Follow-up</button><button onclick="App.openWhatsAppDrawer('financial')">Financeiro</button><button class="primary" onclick="App.sendWhatsAppMessage()" ${canReply?'':'disabled'}>Enviar</button></div></div></section>`}
function renderServiceSmartPanel(active){if(!active)return '';const rows=[['Dados','details',active.linkedStudent],['Financeiro','financial',active.financial],['Frequência','frequency',active.frequency],['Ocorrências','occurrences',active.occurrences],['Documentos','documents','Arquivos do aluno'],['Follow-up','followup','Registrar contato']];return `<aside class="service-smart-panel"><div class="service-person-head"><span class="eyebrow">Aluno / contato</span><h3>${escapeHTML(active.name)}</h3><small>${escapeHTML(active.phone)}</small></div><div class="service-person-list">${rows.map(([label,type,value])=>`<button onclick="App.openWhatsAppDrawer('${type}')"><b>${escapeHTML(label)}</b><span>${escapeHTML(value||'—')}</span></button>`).join('')}</div></aside>`}
function renderServiceDrawerContent(type,active){
  const student=serviceCenterActiveStudent(active),label=serviceCenterDrawers()[type]||'Detalhes';
  if(type==='connections')return renderWhatsAppConnection();
  if(type==='details')return `<div class="service-drawer-section"><h3>Dados do aluno</h3><div class="contact-facts"><span><b>Aluno</b>${escapeHTML(active?.linkedStudent||active?.name||'—')}</span><span><b>Telefone</b>${escapeHTML(active?.phone||'—')}</span><span><b>Responsável</b>${escapeHTML(active?.tag||'—')}</span><span><b>Turma</b>${escapeHTML(active?.className||'—')}</span><span><b>Professor</b>${escapeHTML(active?.teacher||'—')}</span><span><b>Próxima aula</b>${escapeHTML(active?.nextClass||'—')}</span></div></div>`;
  if(type==='financial')return `<div class="service-drawer-section"><h3>Financeiro do contato</h3><div class="grid cols-3">${metricCard('Situação',active?.financial||'—','R$',0,'Cadastro do aluno')}${metricCard('Último pagamento',active?.lastPayment||'—','✓',0,'Resumo operacional')}${metricCard('Ação','Cobrança','☎',0,'Próximo contato')}</div><p class="muted">Para recebimento completo, use a aba Financeiro do aluno. Aqui a secretária enxerga o contexto sem sair do atendimento.</p></div>`;
  if(type==='enrollment')return `<div class="service-drawer-section"><h3>Matrícula</h3><div class="contact-facts"><span><b>Aluno</b>${escapeHTML(active?.linkedStudent||'Ainda não vinculado')}</span><span><b>Turma</b>${escapeHTML(active?.className||'—')}</span><span><b>Professor</b>${escapeHTML(active?.teacher||'—')}</span><span><b>Status CRM</b>${escapeHTML(active?.stage||'—')}</span></div><button class="btn primary small" onclick="App.go('students')">Abrir prontuário completo</button></div>`;
  if(type==='frequency')return `<div class="service-drawer-section"><h3>Frequência</h3><div class="service-big-number">${escapeHTML(active?.frequency||'—')}</div><p class="muted">Resumo para atendimento rápido. Histórico detalhado permanece no prontuário do aluno.</p></div>`;
  if(type==='occurrences')return `<div class="service-drawer-section"><h3>Ocorrências</h3><p class="muted">${escapeHTML(active?.occurrences||student?.occurrences||'Sem ocorrências registradas.')}</p><button class="btn ghost small" onclick="App.openWhatsAppDrawer('followup')">Transformar em follow-up</button></div>`;
  if(type==='documents')return `<div class="service-drawer-section"><h3>Documentos</h3><div class="service-doc-list"><span>Contrato</span><span>Declaração</span><span>Comprovantes</span><span>Material didático</span></div><p class="muted">Uploads reais serão vinculados ao cadastro/documentos do aluno.</p></div>`;
  if(type==='followup')return `<div class="service-drawer-section"><h3>Follow-up</h3><div class="form-grid cols-2"><div class="field"><label>Tipo</label><select id="centralFollowUpType"><option>Contato realizado</option><option>Cobrança</option><option>Pedagógico</option><option>Rematrícula</option></select></div><div class="field"><label>Próximo contato</label><input id="centralFollowUpDate" type="date" value="${todayISO()}"/></div></div><div class="field"><label>Resumo</label><textarea id="centralFollowUpNote" placeholder="Registre o que foi combinado no atendimento."></textarea></div><button class="btn primary small" onclick="App.saveServiceFollowUp()">Salvar follow-up</button></div>`;
  if(type==='templates')return renderWhatsAppTemplates();
  return `<div class="service-drawer-section"><h3>${escapeHTML(label)}</h3><p class="muted">Painel preparado para uso dentro da Central de Atendimento.</p></div>`
}
function renderServiceDrawer(active){const type=State.whatsappDrawer;if(!type)return '';const label=serviceCenterDrawers()[type]||'Painel';return `<aside class="service-drawer"><div class="modal-head"><div><span class="eyebrow">Central de Atendimento</span><h3>${escapeHTML(label)}</h3></div><button class="modal-close" onclick="App.closeWhatsAppDrawer()">×</button></div>${renderServiceDrawerContent(type,active)}</aside>`}
function renderWhatsApp(){if(!canOpenWhatsApp())return `<div class="page"><div class="empty"><div class="emoji">🔒</div><h3>Acesso restrito</h3></div></div>`;const active=whatsappActiveConversation(),info=whatsappState();return `<div class="page service-center-page"><div class="service-center-top"><div><span class="eyebrow">Central de Atendimento</span><h1>WhatsApp da Purple</h1></div><div class="service-top-tabs"><button class="active" onclick="App.closeWhatsAppDrawer()">Conversas</button><button class="${State.whatsappDrawer==='connections'?'active':''}" onclick="App.openWhatsAppDrawer('connections')">${info.connected?'Conectado':'Conectar WhatsApp'}</button></div></div><div class="service-workspace ${State.whatsappDrawer?'drawer-open':''}">${renderServiceConversationList()}${renderServiceChat(active)}${renderServiceSmartPanel(active)}${renderServiceDrawer(active)}</div></div>`}

function editTask(id=null){const t=id?(State.db.tasks||[]).find(x=>x.id===id):null;modal(`<div class="modal-head"><div><span class="eyebrow">Meu Dia</span><h3>${t?'Editar':'Nova'} tarefa</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="field"><label>Título</label><input id="taskTitle" value="${escapeHTML(t?.title||'')}"/></div><div class="field"><label>Descrição</label><textarea id="taskDescription">${escapeHTML(t?.description||'')}</textarea></div><div class="form-grid cols-2"><div class="field"><label>Prioridade</label><select id="taskPriority"><option value="alta" ${t?.priority==='alta'?'selected':''}>Alta</option><option value="media" ${!t||t?.priority==='media'?'selected':''}>Média</option><option value="baixa" ${t?.priority==='baixa'?'selected':''}>Baixa</option></select></div><div class="field"><label>Prazo</label><input id="taskDue" type="date" value="${t?.due_date||todayISO()}"/></div></div><div class="section-actions"><button class="btn ghost" onclick="App.closeModal()">Cancelar</button><button class="btn primary" onclick="App.saveTask('${id||''}')">Salvar tarefa</button></div>`,true)}
async function saveTask(id){const title=upperFormValue($('#taskTitle').value);if(!title)return toast('Informe o título da tarefa.');const existing=id?State.db.tasks.find(x=>x.id===id):null,payload={user_id:existing?.user_id||State.user.id,title,description:upperFormValue($('#taskDescription').value),priority:$('#taskPriority').value,due_date:$('#taskDue').value||null,sector:existing?.sector||State.user.sector,source_type:existing?.source_type||'manual',source_id:existing?.source_id||null};const result=id?await Supabase.from('tasks').update(payload).eq('id',id).select().single():await Supabase.from('tasks').insert(payload).select().single();if(result.error)return toast(friendlyError(result.error,'salvamento da tarefa'));if(id)Object.assign(existing,result.data);else State.db.tasks.unshift(result.data);closeModal();renderPage();premiumToast('Tarefa salva. Mais um passo organizado.')}
async function createPurpleIaTask(index){const item=purpleIaRecommendations()[index];if(!item)return toast('Recomendação não encontrada.');const payload={user_id:State.user.id,title:item.title,description:[item.problem,item.actions[0]||'',item.impact].filter(Boolean).join(' '),priority:item.priority,due_date:item.dueDate||todayISO(),sector:item.sector==='integrado'?State.user.sector:item.sector,source_type:'manual',source_id:null};const {data,error}=await Supabase.from('tasks').insert(payload).select().single();if(error)return toast(friendlyError(error,'criação da tarefa sugerida'));State.db.tasks.unshift(data);await logAudit('Criou tarefa a partir do Purple IA',`${item.title} • ${SECTOR_LABELS[item.sector]||'Geral'}`);renderPage();premiumToast('Tarefa criada a partir da recomendação do Purple IA.')}
async function toggleTask(id,completed){const {data,error}=await Supabase.from('tasks').update({completed,completed_at:completed?new Date().toISOString():null,archived_at:completed?new Date().toISOString():null,completed_by:completed?State.user.name:null,completed_by_id:completed?State.user.id:null}).eq('id',id).select().single();if(error)return toast(friendlyError(error));Object.assign(State.db.tasks.find(x=>x.id===id),data);renderPage();if(completed)premiumToast('Excelente! Tarefa concluída e arquivada.')}
async function deleteTask(id){if(!confirm('Excluir esta tarefa?'))return;const {error}=await Supabase.from('tasks').delete().eq('id',id);if(error)return toast(friendlyError(error));State.db.tasks=State.db.tasks.filter(x=>x.id!==id);renderPage()}
function answerPulse(feeling){const allowed=['excelente','bem','normal','dificil','muito_dificil'];if(!can('pulse.answer'))return toast('Você não possui permissão para responder ao Pulse.');if(!allowed.includes(feeling))return toast('Resposta do Pulse inválida.');if(['dificil','muito_dificil'].includes(feeling))return modal(`<div class="modal-head"><div><span class="eyebrow">Pulse</span><h3>Quer contar um pouco mais?</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><p class="muted">O comentário é opcional e será visível somente para você e para a Direção.</p><div class="field"><label>Comentário opcional</label><textarea id="pulseComment"></textarea></div><div class="section-actions"><button class="btn primary" onclick="App.savePulse('${feeling}')">Registrar</button></div>`,true);savePulse(feeling)}
async function savePulse(feeling){
  const allowed=['excelente','bem','normal','dificil','muito_dificil'];
  if(!can('pulse.answer'))return toast('Você não possui permissão para responder ao Pulse.');
  if(!allowed.includes(feeling))return toast('Resposta do Pulse inválida.');
  try{
    const payload={user_id:State.user.id,sector:State.user.sector,feeling,comment:$('#pulseComment')?.value.trim()||'',entry_date:todayISO()},{data,error}=await Supabase.from('pulse_entries').insert(payload).select().single();
    if(error){if(error.code==='23505')return toast('Você já respondeu ao Pulse hoje.');throw error}
    State.db.pulse.unshift(data);closeModal();renderPage();premiumToast('Obrigado por compartilhar como você está.');
  }catch(error){toast(friendlyError(error,'registro do Pulse'))}
}
async function syncAutomaticTasks(){if(State.user.role==='viewer')return;const existing=new Set((State.db.tasks||[]).filter(t=>t.user_id===State.user.id&&t.source_type!=='manual').map(t=>`${t.source_type}:${t.source_id}`)),items=[];State.db.reports.filter(r=>sectorAllowed(r.sector)).forEach(r=>{if(r.status==='adjust'&&State.user.role!=='direction')items.push({source_type:'report_adjust',source_id:r.id,title:`Ajustar relatório — ${SECTOR_LABELS[r.sector]}`,due_date:r.presentation,priority:'alta',sector:r.sector});if(['sent','review'].includes(r.status)&&State.user.role==='direction')items.push({source_type:'report_approval',source_id:r.id,title:`Analisar relatório — ${SECTOR_LABELS[r.sector]}`,due_date:r.presentation,priority:'alta',sector:r.sector})});State.db.actions.filter(actionVisible).filter(a=>!['done','cancelled'].includes(a.status)).forEach(a=>items.push({source_type:'action',source_id:a.id,title:a.title,due_date:a.deadline,priority:a.priority||'media',sector:a.sector}));State.db.meetings.filter(meetingVisible).filter(m=>m.status!=='done').forEach(m=>items.push({source_type:'meeting',source_id:m.id,title:`Café com Raphael — ${m.participant}`,due_date:m.date,priority:'media',sector:m.sector}));purpleIaRecommendations().slice(0,2).forEach(item=>items.push({source_type:'purple_ia',source_id:item.id,title:`Purple IA: ${item.title}`,due_date:item.dueDate||todayISO(),priority:item.priority,sector:item.sector==='integrado'?State.user.sector:item.sector}));for(const item of items.filter(x=>!existing.has(`${x.source_type}:${x.source_id}`))){const {data,error}=await Supabase.from('tasks').insert({...item,user_id:State.user.id,description:'Tarefa gerada automaticamente pelo Purple Gestão.'}).select().single();if(!error)State.db.tasks.unshift(data)}}
async function unlockAchievements(){if(State.user.role==='viewer')return;const own=State.db.reports.filter(r=>r.ownerId===State.user.id||r.owner===State.user.name),existing=new Set((State.db.achievements||[]).filter(a=>a.user_id===State.user.id).map(a=>a.code)),candidates=[];if(own.some(r=>r.status!=='draft'))candidates.push(['first_report','Primeiro relatório enviado']);if(own.some(r=>r.status==='approved'))candidates.push(['first_approved','Primeiro relatório aprovado']);const ontime=own.filter(r=>r.status==='approved'&&!r.adjustmentNote).length;if(ontime>=5)candidates.push(['five_ontime','Cinco relatórios sem atraso']);if(ontime>=10)candidates.push(['ten_ontime','Dez relatórios sem atraso']);const visibleActions=State.db.actions.filter(actionVisible),visibleMeetings=State.db.meetings.filter(meetingVisible);if(visibleActions.length&&!visibleActions.some(a=>!['done','cancelled'].includes(a.status)&&daysUntil(a.deadline)<0))candidates.push(['thirty_clear','30 dias sem pendências vencidas']);if(visibleMeetings.length&&visibleMeetings.every(m=>m.status==='done'))candidates.push(['meetings_complete','100% das reuniões realizadas']);if(visibleActions.length&&visibleActions.every(a=>a.status==='done'&&(!a.updatedAt||a.updatedAt.slice(0,10)<=a.deadline)))candidates.push(['actions_ontime','100% dos planos concluídos no prazo']);for(const [code,title] of candidates.filter(x=>!existing.has(x[0]))){const {data,error}=await Supabase.from('achievements').insert({user_id:State.user.id,code,title}).select().single();if(!error){State.db.achievements.unshift(data);setTimeout(()=>premiumToast(`Conquista desbloqueada: ${title}`),500)}}}
function premiumToast(message){toast(message);const t=$('#toast');t.classList.add('premium');setTimeout(()=>t.classList.remove('premium'),2600)}

function renderMural(){const list=(State.db.announcements||[]).filter(a=>!a.valid_until||a.valid_until>=todayISO()),mayCreate=can('mural.create'),mayEdit=can('mural.edit'),mayDelete=can('mural.delete');return `<div class="page"><div class="section-title"><div><h2>Mural Purple</h2><p>Comunicados importantes para manter todos na mesma direção.</p></div>${mayCreate?'<button class="btn primary" onclick="App.editAnnouncement()">Novo comunicado</button>':''}</div><div class="mural-grid">${list.map(a=>`<article class="announcement ${a.pinned?'pinned':''}"><div class="announcement-head"><span class="eyebrow">${a.pinned?'Fixado • ':''}${a.priority}</span><span>${fmtDate(a.published_at)}</span></div><h3>${escapeHTML(a.title)}</h3><p>${escapeHTML(a.message)}</p><footer>${a.sector==='all'?'Toda a Purple':SECTOR_LABELS[a.sector]}${mayEdit||mayDelete?`<div>${mayEdit?`<button class="btn ghost small" onclick="App.editAnnouncement('${a.id}')">Editar</button>`:''}${mayDelete?`<button class="btn danger small" onclick="App.deleteAnnouncement('${a.id}')">Remover</button>`:''}</div>`:''}</footer></article>`).join('')||'<div class="empty"><h3>Nenhum comunicado ativo</h3></div>'}</div></div>`}
function editAnnouncement(id=null){const a=id?(State.db.announcements||[]).find(x=>x.id===id):null;modal(`<div class="modal-head"><div><span class="eyebrow">Mural Purple</span><h3>${a?'Editar':'Novo'} comunicado</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="field"><label>Título</label><input id="announcementTitle" value="${escapeHTML(a?.title||'')}"/></div><div class="field"><label>Mensagem</label><textarea id="announcementMessage" class="large">${escapeHTML(a?.message||'')}</textarea></div><div class="form-grid cols-4"><div class="field"><label>Validade</label><input id="announcementUntil" type="date" value="${a?.valid_until||''}"/></div><div class="field"><label>Prioridade</label><select id="announcementPriority"><option value="alta" ${a?.priority==='alta'?'selected':''}>Alta</option><option value="normal" ${!a||a?.priority==='normal'?'selected':''}>Normal</option><option value="baixa" ${a?.priority==='baixa'?'selected':''}>Baixa</option></select></div><div class="field"><label>Público</label><select id="announcementAudience"><option value="all" ${!a||a?.audience==='all'?'selected':''}>Todos</option><option value="leaders" ${a?.audience==='leaders'?'selected':''}>Líderes</option><option value="direction" ${a?.audience==='direction'?'selected':''}>Direção</option></select></div><div class="field"><label>Setor</label><select id="announcementSector"><option value="all">Todos</option>${['retencao','pedagogico','financeiro'].map(s=>`<option value="${s}" ${a?.sector===s?'selected':''}>${SECTOR_LABELS[s]}</option>`).join('')}</select></div></div><label class="check-chip"><input id="announcementPinned" type="checkbox" ${a?.pinned?'checked':''}/> Fixar comunicado</label><div class="section-actions"><button class="btn primary" onclick="App.saveAnnouncement('${id||''}')">Salvar comunicado</button></div>`,true)}
async function saveAnnouncement(id){const permission=id?'mural.edit':'mural.create';if(!can(permission))return toast('Operação não autorizada.');const title=$('#announcementTitle').value.trim(),message=$('#announcementMessage').value.trim();if(!title||!message)return toast('Informe título e mensagem.');const payload={title,message,valid_until:$('#announcementUntil').value||null,priority:$('#announcementPriority').value,sector:$('#announcementSector').value,audience:$('#announcementAudience').value,pinned:$('#announcementPinned').checked};if(!id)Object.assign(payload,{created_by:State.user.id,published_at:todayISO()});const result=id?await Supabase.from('announcements').update(payload).eq('id',id).select().single():await Supabase.from('announcements').insert(payload).select().single();if(result.error)return toast(friendlyError(result.error,'salvamento do comunicado'));if(id)Object.assign(State.db.announcements.find(x=>x.id===id),result.data);else State.db.announcements.unshift(result.data);await logAudit(id?'Editou comunicado':'Publicou comunicado',`${result.data.title} • ${result.data.sector==='all'?'Toda a Purple':SECTOR_LABELS[result.data.sector]}`);closeModal();renderPage();premiumToast('Comunicado publicado no Mural Purple.')}
async function deleteAnnouncement(id){if(!can('mural.delete'))return toast('Exclusão não autorizada.');const announcement=State.db.announcements.find(x=>x.id===id);if(!announcement)return toast('Comunicado não encontrado.');if(!confirm('Remover este comunicado?'))return;const {error}=await Supabase.from('announcements').delete().eq('id',id);if(error)return toast(friendlyError(error,'exclusão do comunicado'));State.db.announcements=State.db.announcements.filter(x=>x.id!==id);await logAudit('Removeu comunicado',`${announcement.title} • ${announcement.sector==='all'?'Toda a Purple':SECTOR_LABELS[announcement.sector]}`);renderPage()}

function adminTab(tab){State.inventoryTab=tab;renderPage()}
function setAdminButtonLoading(button,loading){if(!button)return;button.disabled=loading;button.classList.toggle('loading',loading)}
async function finishAdministrationCommit(successMessage,refreshFailureMessage){
  closeModal();
  try{await refreshAdministration();renderPage();toast(successMessage)}
  catch(error){console.error('Purple Gestão — atualização após gravação:',error);toast(refreshFailureMessage)}
}
function adminTabs(){const tabs=[['overview','Visão Geral',can('inventory.view')||can('assets.view')],['books','Estoque de Livros',can('inventory.view')],['assets','Patrimônio',can('assets.view')],['movements','Movimentações',can('inventory.view')||can('assets.view')]],exportButton=State.inventoryTab==='assets'&&can('assets.export')?'<button class="btn ghost admin-export" onclick="App.exportAssetsCSV()">Exportar patrimônio</button>':'';return `<nav class="admin-tabs">${tabs.filter(x=>x[2]).map(x=>`<button class="${State.inventoryTab===x[0]?'active':''}" onclick="App.adminTab('${x[0]}')">${x[1]}</button>`).join('')}</nav>${exportButton}`}
function bookItems(){return (State.db.inventoryItems||[]).filter(x=>x.item_type==='book')}
function activeBooks(){return bookItems().filter(x=>x.active)}
