function inventoryIntegrityMigrationMissing(error,feature=''){
  const details=[error?.code,error?.message,error?.details,error?.hint].filter(Boolean).join(' ').toLowerCase(),expected=String(feature||'').toLowerCase();
  if(error?.code==='42703'&&details.includes('related_movement_id'))return true;
  if(['PGRST202','42883'].includes(error?.code)&&(!expected||details.includes(expected)))return true;
  return ['save_inventory_book','record_book_return','related_movement_id'].some(name=>details.includes(name))&&/(schema cache|could not find|does not exist|undefined column|function)/.test(details)
}
