async function loadPendingBookReturnIssues(){
  const rows=[],pageSize=1000,columns='id,item_id,item_name,movement_type,quantity_change,student_name,class_name,movement_date,created_at,related_movement_id';
  for(let from=0;;from+=pageSize){
    const {data,error}=await Supabase.from('book_movements').select(columns).in('movement_type',['issue','return']).order('created_at',{ascending:false}).order('id',{ascending:false}).range(from,from+pageSize-1);
    if(error)throw error;
    const batch=data||[];rows.push(...batch);
    if(batch.length<pageSize)break
  }
  const returnedByIssue=new Map(),legacyReturnKeys=new Set(),studentKey=value=>String(value||'').trim().toLocaleLowerCase('pt-BR'),movementKey=movement=>`${movement.item_id}::${studentKey(movement.student_name)}`;
  rows.filter(row=>row.movement_type==='return').forEach(row=>{if(row.related_movement_id)returnedByIssue.set(row.related_movement_id,(returnedByIssue.get(row.related_movement_id)||0)+Math.max(0,Number(row.quantity_change)||0));else legacyReturnKeys.add(movementKey(row))});
  let blocked=0;
  const activeIds=new Set(activeBooks().map(book=>book.id)),issues=rows.filter(row=>row.movement_type==='issue'&&activeIds.has(row.item_id)).map(row=>({...row,remaining:Math.max(0,Math.abs(Number(row.quantity_change)||0)-(returnedByIssue.get(row.id)||0))})).filter(row=>{if(row.remaining<=0)return false;if(legacyReturnKeys.has(movementKey(row))){blocked++;return false}return true});
  return {issues,blocked}
}
function updateBookReturnFields(){
  const issue=pendingBookReturnIssues.find(row=>row.id===$('#bookReturnIssue')?.value);
  if(!issue)return;
  const book=$('#bookReturnBook'),student=$('#bookReturnStudent'),balance=$('#bookReturnBalance'),quantity=$('#bookMovementQuantity');
  if(book)book.value=issue.item_name||bookItems().find(item=>item.id===issue.item_id)?.name||'';
  if(student)student.value=[issue.student_name,issue.class_name].filter(Boolean).join(' — ');
  if(balance)balance.value=`${issue.remaining} de ${Math.abs(Number(issue.quantity_change)||0)} exemplar(es)`;
  if(quantity){quantity.max=String(issue.remaining);const current=Number(quantity.value);if(!Number.isInteger(current)||current<1||current>issue.remaining)quantity.value='1'}
}
