function exportAssetsCSV(){if(!can('assets.export'))return toast('Exportação não autorizada.');const keys=['asset_code','name','category','brand','model','serial_number','quantity','location','current_responsible','acquisition_date','acquisition_value','condition','status'];download(`patrimonio-${todayISO()}.csv`,[keys.join(';'),...assetItems().map(x=>keys.map(k=>csvCell(x[k])).join(';'))].join('\n'),'text/csv;charset=utf-8')}
function inventoryOptions(items,key,label){return [...new Set(items.map(x=>x[key]).filter(Boolean))].sort().map(v=>`<option value="${escapeHTML(v)}">${escapeHTML(v)}</option>`).join('')}
function renderInventory(){if(!can('inventory.view'))return `<div class="page"><div class="empty"><div class="emoji">🔒</div><h3>Acesso restrito</h3></div></div>`;const items=(State.db.inventoryItems||[]).filter(x=>x.active);const total=items.reduce((sum,x)=>sum+Number(x.current_quantity||0),0),low=items.filter(x=>inventoryStatus(x).key==='low').length,out=items.filter(x=>inventoryStatus(x).key==='out').length;return `<div class="page inventory-page"><div class="section-title"><div><span class="eyebrow">Administrativo</span><h2>Estoque</h2><p>Controle de livros e materiais físicos da Purple.</p></div><div class="section-actions">${can('inventory.entry')?'<button class="btn soft" onclick="App.openInventoryMovement(\'entry\')">Entrada de estoque</button>':''}${can('inventory.issue')?'<button class="btn soft" onclick="App.openInventoryMovement(\'issue\')">Baixa de estoque</button>':''}${can('inventory.create')?'<button class="btn primary" onclick="App.editInventoryItem()">Novo livro</button>':''}</div></div>${!State.db.inventoryAvailable?'<div class="alert yellow inventory-migration"><div class="alert-icon">!</div><div><b>Módulo aguardando migração do banco</b><span>A interface está pronta. Aplique a migração de Estoque para habilitar cadastros e movimentações.</span></div></div>':''}<section class="grid cols-4 inventory-kpis">${metricCard('Total de livros',fmtNumber(items.length),'▣',0,'Títulos ativos')}${metricCard('Quantidade em estoque',fmtNumber(total),'▤',0,'Unidades disponíveis')}${metricCard('Estoque baixo',fmtNumber(low),'!',0,'Abaixo ou igual ao mínimo')}${metricCard('Esgotados',fmtNumber(out),'○',0,'Sem unidades disponíveis')}</section><section class="panel inventory-panel"><div class="inventory-toolbar"><input id="inventorySearch" class="search" placeholder="Pesquisar livro, código ou curso" oninput="App.applyInventoryFilters()"/><select id="inventoryCourse" class="select" onchange="App.applyInventoryFilters()"><option value="all">Todos os cursos</option>${inventoryOptions(items,'course')}</select><select id="inventoryCategory" class="select" onchange="App.applyInventoryFilters()"><option value="all">Todas as categorias</option>${inventoryOptions(items,'category')}</select><select id="inventoryLevel" class="select" onchange="App.applyInventoryFilters()"><option value="all">Todos os níveis</option>${inventoryOptions(items,'level')}</select><select id="inventoryAvailability" class="select" onchange="App.applyInventoryFilters()"><option value="all">Toda disponibilidade</option><option value="available">Disponível</option><option value="low">Estoque Baixo</option><option value="out">Esgotado</option></select></div><div id="inventoryTable"></div></section><section class="panel inventory-history"><div class="panel-head"><div><span class="eyebrow">Histórico</span><h3>Últimas movimentações</h3></div></div>${renderInventoryHistory()}</section></div>`}
function applyInventoryFilters(){const target=$('#inventoryTable');if(!target)return;const search=($('#inventorySearch')?.value||'').toLowerCase(),course=$('#inventoryCourse')?.value||'all',category=$('#inventoryCategory')?.value||'all',level=$('#inventoryLevel')?.value||'all',availability=$('#inventoryAvailability')?.value||'all';const items=(State.db.inventoryItems||[]).filter(x=>x.active).filter(x=>(!search||`${x.name} ${x.internal_code||''} ${x.course||''}`.toLowerCase().includes(search))&&(course==='all'||x.course===course)&&(category==='all'||x.category===category)&&(level==='all'||x.level===level)&&(availability==='all'||inventoryStatus(x).key===availability));target.innerHTML=`<div class="table-wrap"><table class="inventory-table"><thead><tr><th>Nome</th><th>Curso</th><th>Nível</th><th>Quantidade disponível</th><th>Status</th><th>Ações</th></tr></thead><tbody>${items.map(item=>{const status=inventoryStatus(item);return `<tr><td><b>${escapeHTML(item.name)}</b>${item.internal_code?`<small>${escapeHTML(item.internal_code)}</small>`:''}</td><td>${escapeHTML(item.course||'—')}</td><td>${escapeHTML(item.level||'—')}</td><td><b>${fmtNumber(item.current_quantity)}</b><small>Mínimo: ${fmtNumber(item.minimum_quantity)}</small></td><td><span class="stock-status ${status.key}">${status.label}</span></td><td><div class="table-actions">${can('inventory.edit')?`<button class="btn ghost small" onclick="App.editInventoryItem('${item.id}')">Editar</button>`:''}${can('inventory.adjust')?`<button class="btn soft small" onclick="App.openInventoryMovement('adjustment','${item.id}')">Ajustar</button>`:''}${can('inventory.delete')?`<button class="btn danger small" onclick="App.deleteInventoryItem('${item.id}')">Excluir</button>`:''}</div></td></tr>`}).join('')||'<tr><td colspan="6"><div class="empty"><p>Nenhum item encontrado.</p></div></td></tr>'}</tbody></table></div>`}
function renderInventoryHistory(){const names=Object.fromEntries((State.db.inventoryItems||[]).map(x=>[x.id,x.name]));const labels={entry:'Entrada',issue:'Baixa',adjustment:'Ajuste manual'};return `<div class="table-wrap"><table><thead><tr><th>Data</th><th>Usuário</th><th>Operação</th><th>Quantidade</th><th>Livro</th></tr></thead><tbody>${(State.db.inventoryMovements||[]).slice(0,12).map(m=>`<tr><td>${fmtDateTime(m.created_at)}</td><td>${escapeHTML(m.responsible_name||'Usuário')}</td><td>${labels[m.movement_type]||m.movement_type}${m.student_name?`<small>Aluno: ${escapeHTML(m.student_name)}</small>`:''}</td><td class="movement-qty ${Number(m.quantity_change)>=0?'positive':'negative'}">${Number(m.quantity_change)>0?'+':''}${fmtNumber(m.quantity_change)}</td><td>${escapeHTML(names[m.item_id]||m.item_name||'Item')}</td></tr>`).join('')||'<tr><td colspan="5"><div class="empty"><p>Nenhuma movimentação registrada.</p></div></td></tr>'}</tbody></table></div>`}
function editInventoryItem(id=''){if(!can(id?'inventory.edit':'inventory.create'))return toast('Operação não autorizada.');if(!State.db.inventoryAvailable)return toast('Aplique a migração do Estoque antes de cadastrar itens.');const item=id?State.db.inventoryItems.find(x=>x.id===id):null;modal(`<div class="modal-head"><div><span class="eyebrow">Estoque</span><h3>${item?'Editar livro':'Novo livro'}</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="form-grid cols-2"><div class="field"><label>Código interno (opcional)</label><input id="inventoryCode" value="${escapeHTML(item?.internal_code||'')}"/></div><div class="field"><label>Nome do livro</label><input id="inventoryName" value="${escapeHTML(item?.name||'')}" required/></div><div class="field"><label>Categoria</label><input id="inventoryCategoryEdit" value="${escapeHTML(item?.category||'Livro didático')}"/></div><div class="field"><label>Curso</label><input id="inventoryCourseEdit" value="${escapeHTML(item?.course||'')}"/></div><div class="field"><label>Nível</label><input id="inventoryLevelEdit" value="${escapeHTML(item?.level||'')}"/></div><div class="field"><label>Quantidade mínima</label><input id="inventoryMinimum" type="number" min="0" value="${Number(item?.minimum_quantity||0)}"/></div>${item?'':`<div class="field"><label>Quantidade inicial</label><input id="inventoryInitial" type="number" min="0" value="0"/></div>`}<div class="field"><label>Localização (opcional)</label><input id="inventoryLocation" value="${escapeHTML(item?.location||'')}"/></div></div><div class="field"><label>Observações</label><textarea id="inventoryNotes">${escapeHTML(item?.notes||'')}</textarea></div><div class="section-actions"><button class="btn ghost" onclick="App.closeModal()">Cancelar</button><button class="btn primary" onclick="App.saveInventoryItem('${id}')">Salvar livro</button></div>`,true)}
function saveInventoryItem(id='',button=null){return saveBook(id,button)}
function deleteInventoryItem(id,button=null){return inactivateBook(id,button)}
function openInventoryMovement(type,itemId=''){const permission={entry:'inventory.entry',issue:'inventory.issue',adjustment:'inventory.adjust'}[type];if(!can(permission))return toast('Operação não autorizada.');if(!State.db.inventoryAvailable)return toast('Aplique a migração do Estoque antes de registrar movimentações.');const items=(State.db.inventoryItems||[]).filter(x=>x.active),selected=items.find(x=>x.id===itemId);modal(`<div class="modal-head"><div><span class="eyebrow">Movimentação de estoque</span><h3>${type==='entry'?'Entrada de Estoque':type==='issue'?'Baixa de Livro':'Ajuste de Quantidade'}</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="field"><label>Livro</label><select id="movementItem" ${itemId?'disabled':''}>${items.map(x=>`<option value="${x.id}" ${x.id===itemId?'selected':''}>${escapeHTML(x.name)} — ${fmtNumber(x.current_quantity)} disponíveis</option>`).join('')}</select></div>${type==='issue'?'<div class="field"><label>Aluno</label><input id="movementStudent" placeholder="Nome do aluno"/></div>':''}<div class="field"><label>${type==='adjustment'?'Nova quantidade':'Quantidade'}</label><input id="movementQuantity" type="number" min="${type==='adjustment'?0:1}" value="${type==='adjustment'?Number(selected?.current_quantity||0):1}"/></div><div class="field"><label>Observações</label><textarea id="movementNotes"></textarea></div><div class="section-actions"><button class="btn ghost" onclick="App.closeModal()">Cancelar</button><button class="btn primary" onclick="App.saveInventoryMovement('${type}')">Confirmar</button></div>`,true)}
function saveInventoryMovement(type,button=null){return saveBookMovement(type,button)}
function refreshInventory(){return Promise.reject(new Error('Fluxo legado de estoque removido.'))}

function renderAudit(){if(State.user.role!=='direction')return `<div class="page"><div class="empty"><div class="emoji">🔒</div><h3>Acesso restrito</h3></div></div>`;const events=State.db.audit.slice().sort((a,b)=>b.at.localeCompare(a.at)).map(e=>`<div class="audit-event"><time>${fmtDateTime(e.at)}</time><div><b>${escapeHTML(e.action)}</b><div class="muted" style="margin-top:3px">${escapeHTML(e.detail||'')}</div></div><div class="actor">${escapeHTML(e.actor)}</div></div>`).join('');return `<div class="page"><div class="section-title"><div><h2>Auditoria</h2><p>Registro das principais alterações realizadas no sistema.</p></div><button class="btn ghost" onclick="App.exportAuditCSV()">Exportar CSV</button></div><section class="panel">${events||'<div class="empty"><p>Nenhum evento registrado.</p></div>'}</section></div>`}
function exportAuditCSV(){const rows=[['Data','Ator','Ação','Detalhe'],...State.db.audit.map(e=>[fmtDateTime(e.at),e.actor,e.action,e.detail||''])];download(`purple-auditoria-${new Date().toISOString().slice(0,10)}.csv`,'\ufeff'+rows.map(r=>r.map(csvCell).join(';')).join('\n'),'text/csv;charset=utf-8')}

function renderSettings(){const s=State.db.settings,u=State.user;return `<div class="page account-page"><div class="section-title"><div><h2>Configurações</h2><p>Gerencie sua conta e as preferências do Purple Gestão.</p></div></div><div class="settings-tabs"><button onclick="App.settingsTab('account')">Minha Conta</button><button onclick="App.settingsTab('security')">Segurança</button><button onclick="App.settingsTab('preferences')">Preferências</button>${u.role==='direction'?'<button onclick="App.settingsTab(\'system\')">Sistema</button>':''}</div><div id="settingsContent">${renderSettingsTab('account',s,u)}</div></div>`}
function renderSettingsTab(tab,s=State.db.settings,u=State.user){if(tab==='security')return `<section class="form-card account-card"><h3>Segurança</h3><p class="helper">Use uma senha exclusiva com pelo menos 8 caracteres.</p><div class="field"><label>Senha atual</label><input id="currentPassword" type="password" autocomplete="current-password"/></div><div class="form-grid cols-2"><div class="field"><label>Nova senha</label><input id="newPassword" type="password" minlength="8" autocomplete="new-password"/></div><div class="field"><label>Confirmar nova senha</label><input id="confirmPassword" type="password" minlength="8" autocomplete="new-password"/></div></div><button id="changePasswordButton" class="btn primary" onclick="App.changePassword()">Alterar senha</button></section>`;if(tab==='preferences')return `<section class="form-card account-card"><h3>Preferências</h3><div class="setting-row"><div><b>Notificações</b><p>Configuração global de alertas operacionais e lembretes.</p></div><button class="switch ${s.notifications?'on':''}" onclick="App.toggleSetting('notifications')" ${can('settings.edit')?'':'disabled'}></button></div></section>`;if(tab==='system'&&u.role==='direction'){const status=window.PurpleSystemStatus?.()||{};return `<section class="form-card account-card"><h3>Status do Sistema</h3><p class="helper">Leitura técnica rápida da instalação atual, cache, Supabase e sessão.</p>${[['Status do Supabase',status.supabaseReady?'Conectado':'Verificando'],['Versão do sistema',status.appVersion||s.version||'1.0'],['Data da implantação',s.deploymentDate||'18/07/2026'],['Versão do banco',s.databaseVersion||'20260719'],['Versão do cache',status.serviceWorkerVersion||s.cacheVersion||'v85'],['Service Worker',status.serviceWorkerSupported?(status.controllerActive?'Ativo':'Suportado, aguardando controle'):'Não suportado'],['Estado da autenticação',status.authState||'—'],['Última sincronização',fmtDateTime(s.lastSync)],['Atualizado em',fmtDateTime(status.timestamp)]].map(x=>`<div class="setting-row"><b>${x[0]}</b><span>${escapeHTML(x[1]||'—')}</span></div>`).join('')}<div class="section-actions" style="justify-content:flex-start;margin-top:14px"><button class="btn ghost" onclick="App.showDiagnostics()">Abrir diagnóstico técnico</button></div></section>`}return `<section class="form-card account-card"><h3>Meu Perfil</h3><div class="profile-summary"><div class="user-avatar profile-avatar">${escapeHTML(u.name.charAt(0).toUpperCase())}</div><div><b>${escapeHTML(u.name)}</b><span>${escapeHTML(u.email)}</span></div></div><div class="form-grid cols-2"><div class="field"><label>Nome</label><input id="profileName" value="${escapeHTML(u.name)}"/></div><div class="field"><label>Telefone</label><input id="profilePhone" value="${escapeHTML(u.phone)}"/></div><div class="field"><label>Cargo</label><input id="profileJobTitle" value="${escapeHTML(u.jobTitle)}"/></div><div class="field"><label>Foto</label><input id="profileAvatarUrl" value="${escapeHTML(u.avatarUrl||'')}" placeholder="Foto administrada pela Direção" disabled/></div><div class="field"><label>E-mail</label><input value="${escapeHTML(u.email)}" disabled/></div><div class="field"><label>Perfil</label><input value="${ROLE_LABELS[u.role]}" disabled/></div><div class="field"><label>Último acesso</label><input value="${fmtDateTime(u.lastLoginAt)}" disabled/></div><div class="field"><label>Data de criação</label><input value="${fmtDateTime(u.createdAt)}" disabled/></div></div><div class="field"><label>Assinatura eletrônica</label><textarea id="profileSignature" placeholder="Assinatura utilizada em aprovações e registros internos">${escapeHTML(u.electronicSignature)}</textarea></div><button id="saveProfileButton" class="btn primary" onclick="App.saveMyProfile()">Salvar perfil</button></section>`}
function settingsTab(tab){$('#settingsContent').innerHTML=renderSettingsTab(tab)}
async function saveMyProfile(){
  const button=$('#saveProfileButton'),payload={p_name:$('#profileName').value.trim(),p_phone:$('#profilePhone').value.trim(),p_job_title:$('#profileJobTitle').value.trim(),p_electronic_signature:$('#profileSignature').value.trim()};
  if(!payload.p_name)return toast('Informe seu nome.');
  button.disabled=true;
  try{
    const {data,error}=await Supabase.rpc('update_my_profile',payload);
    if(error)throw error;
    const profilePatch={name:data.name,phone:data.phone||'',jobTitle:data.job_title||'',electronicSignature:data.electronic_signature||''};
    Object.assign(State.user,profilePatch);
    const listedUser=State.db.users.find(user=>user.id===State.user.id);
    if(listedUser)Object.assign(listedUser,profilePatch);
    $('#userName').textContent=State.user.name;
    $('#userAvatar').textContent=State.user.name.charAt(0).toUpperCase();
    logAudit('Editou o próprio perfil','Dados pessoais atualizados');
    toast('Perfil atualizado com sucesso.');
    State.page='settings';
    renderPage();
  }catch(e){toast(friendlyError(e,'atualização de perfil'))}
  finally{button.disabled=false}
}
async function changePassword(){const current=$('#currentPassword').value,next=$('#newPassword').value,confirmPassword=$('#confirmPassword').value,button=$('#changePasswordButton');if(!current)return toast('Informe a senha atual.');if(next.length<8)return toast('A nova senha deve ter pelo menos 8 caracteres.');if(next!==confirmPassword)return toast('A confirmação da senha não confere.');button.disabled=true;try{const {error:verifyError}=await Supabase.auth.signInWithPassword({email:State.user.email,password:current});if(verifyError)throw new Error('Senha atual inválida.');const {error}=await Supabase.auth.updateUser({password:next});if(error)throw error;logAudit('Alterou a senha','Senha atualizada pelo próprio usuário');toast('Senha alterada com sucesso.');$('#currentPassword').value=$('#newPassword').value=$('#confirmPassword').value=''}catch(e){console.error('Purple Gestão — alteração de senha:',e);toast(e.message==='Senha atual inválida.'?e.message:'Não foi possível alterar a senha. Tente novamente.')}finally{button.disabled=false}}
async function saveSettings(){const before=cloneValue(State.db.settings);Object.assign(State.db.settings,{retentionRisk:Number($('#settingRetentionRisk').value),rematriculationTarget:Number($('#settingRematriculation').value),delinquencyAlert:Number($('#settingDelinquency').value),criticalGroups:Number($('#settingCriticalGroups').value),weeklyDeadline:$('#settingWeekly').value,biweeklyDeadline:$('#settingBiweekly').value,monthlyDeadline:$('#settingMonthly').value});try{await Storage.save(State.db);logAudit('Atualizou configurações','Metas, alertas e prazos padrão');toast('Configurações salvas.');renderPage()}catch(error){State.db.settings=before;toast(friendlyError(error,'salvamento das configurações'))}}
async function toggleSetting(key){if(State.user.role!=='direction')return toast('Somente a direção pode alterar esta configuração.');const before=State.db.settings[key];State.db.settings[key]=!before;try{await Storage.save(State.db);logAudit('Alterou configuração',`${key}: ${State.db.settings[key]}`);renderPage()}catch(error){State.db.settings[key]=before;toast(friendlyError(error,'alteração da configuração'))}}
function defaultPermissions(role,sector){const all=Object.values(PERMISSION_GROUPS).flat().map(x=>x[0]);if(role==='direction')return Object.fromEntries(all.map(k=>[k,true]));const base=['panel.view','reports.view','indicators.view','tasks.view','mural.view','meetings.view','settings.view'];if(role==='viewer')base.push('whatsapp.view','inventory.view','assets.view');if(role==='leader')base.push('reports.create','reports.edit','reports.export','tasks.create','tasks.edit','tasks.delete','pulse.view','pulse.answer','cases.view','actions.view','actions.create','actions.edit','whatsapp.view','whatsapp.reply','inventory.view','inventory.issue','inventory.return');if(role==='leader'&&sector==='financeiro')base.push('financial.receipts.view','financial.payments.view','financial.receivables.view','financial.payables.view','financial.bank_accounts.view','financial.balances.view','financial.transactions.create','financial.transactions.edit','financial.transactions.delete','financial.export','inventory.create','inventory.edit','inventory.entry','inventory.adjust','inventory.inactivate','inventory.export','assets.view','assets.export');return Object.fromEntries(all.map(k=>[k,base.includes(k)]))}
function permissionChecklist(permissions){return Object.entries(PERMISSION_GROUPS).map(([group,items])=>`<section class="permission-group"><h4>${group}</h4><div class="permission-checks">${items.map(([key,label])=>`<label class="check-chip"><input type="checkbox" data-permission="${key}" onchange="App.updatePermissionSummary()" ${permissions[key]?'checked':''}/> ${label}</label>`).join('')}</div></section>`).join('')}
function validPermissionObject(value){return !!value&&!Array.isArray(value)&&typeof value==='object'&&Object.entries(value).every(([key,enabled])=>PERMISSION_KEY_SET.has(key)&&typeof enabled==='boolean')}
function isEffectiveAdministrator(user){return user?.role==='direction'&&user.active===true&&user.sector==='all'&&user.accessScope==='all_sectors'&&user.permissions?.['users.edit']===true}
function enforceUserAccessFields(){
  const role=$('#userEditRole')?.value,sector=$('#userEditSector'),scope=$('#userEditScope');
  if(!role||!sector||!scope)return;
  if(role==='direction'){sector.value='all';scope.value='all_sectors';sector.disabled=true;scope.disabled=true;return}
  sector.disabled=false;scope.value='own_sector';scope.disabled=true;
  if(role==='leader'&&sector.value==='all')sector.value='retencao';
}
function renderUsers(){if(!can('users.view'))return `<div class="page"><div class="empty"><div class="emoji">🔒</div><h3>Acesso restrito</h3></div></div>`;const editable=can('users.edit')&&State.user.role==='direction',rows=State.db.users.map(u=>`<tr><td>${escapeHTML(u.name)}</td><td>${escapeHTML(u.email)}</td><td>${ROLE_LABELS[u.role]}</td><td>${u.sector==='all'?'Todos':SECTOR_LABELS[u.sector]}</td><td>${u.accessScope==='all_sectors'?'Todos os setores':'Próprio setor'}</td><td><span class="status ${u.active?'approved':'archived'}">${u.active?'Ativo':'Inativo'}</span></td><td>${editable?`<button class="btn ghost small" onclick="App.editUser('${u.id}')">Editar</button>`:'<span class="muted">Somente leitura</span>'}</td></tr>`).join('');return `<div class="page"><div class="section-title"><div><h2>Usuários e permissões</h2><p>Perfis padrão com ajustes individuais e negação por padrão.</p></div></div><div class="table-wrap"><table><thead><tr><th>Nome</th><th>E-mail</th><th>Perfil</th><th>Setor</th><th>Escopo</th><th>Status</th><th>Ações</th></tr></thead><tbody>${rows}</tbody></table></div></div>`}
function editUser(id){if(State.user.role!=='direction'||!can('users.edit'))return toast('Operação não autorizada.');const u=State.db.users.find(x=>x.id===id);if(!u)return toast('Usuário não encontrado.');const permissions={...(u.permissions||{})};modal(`<div class="modal-head"><div><span class="eyebrow">Gerenciar usuário</span><h3>${escapeHTML(u.name)}</h3></div><button class="modal-close" onclick="App.closeModal()">×</button></div><div class="form-grid cols-2"><div class="field"><label>Nome completo</label><input id="userEditName" value="${escapeHTML(u.name)}"/></div><div class="field"><label>E-mail</label><input id="userEditEmail" type="email" value="${escapeHTML(u.email)}"/></div><div class="field"><label>Cargo</label><input id="userEditJobTitle" value="${escapeHTML(u.jobTitle||'')}"/></div><div class="field"><label>Avatar</label><input id="userEditAvatarUrl" value="${escapeHTML(u.avatarUrl||'')}" placeholder="URL da imagem"/></div></div><div class="form-grid cols-4"><div class="field"><label>Perfil padrão</label><select id="userEditRole" onchange="App.restoreUserPermissions()"><option value="direction" ${u.role==='direction'?'selected':''}>Direção</option><option value="leader" ${u.role==='leader'?'selected':''}>Líder</option><option value="viewer" ${u.role==='viewer'?'selected':''}>Consulta</option></select></div><div class="field"><label>Setor</label><select id="userEditSector" onchange="App.restoreUserPermissions()"><option value="all" ${u.sector==='all'?'selected':''}>Todos</option>${['retencao','pedagogico','financeiro'].map(s=>`<option value="${s}" ${u.sector===s?'selected':''}>${SECTOR_LABELS[s]}</option>`).join('')}</select></div><div class="field"><label>Escopo</label><select id="userEditScope"><option value="own_sector" ${u.accessScope!=='all_sectors'?'selected':''}>Próprio setor</option><option value="all_sectors" ${u.accessScope==='all_sectors'?'selected':''}>Todos os setores</option></select></div><div class="field"><label>Status</label><select id="userEditActive"><option value="true" ${u.active?'selected':''}>Ativo</option><option value="false" ${!u.active?'selected':''}>Inativo</option></select></div></div><div id="permissionChecklist">${permissionChecklist(permissions)}</div><div class="form-card"><h4>Permissões efetivas</h4><p id="permissionSummary" class="helper">${Object.entries(permissions).filter(x=>x[1]).map(x=>x[0]).join(' • ')}</p></div><button type="button" class="btn soft" onclick="App.toggleUserPasswordReset()">Redefinir senha</button><div id="userPasswordReset" class="form-card hidden" style="margin-top:12px"><div class="form-grid cols-2"><div class="field"><label>Nova senha</label><input id="userEditPassword" type="password" minlength="8" autocomplete="new-password"/></div><div class="field"><label>Confirmar nova senha</label><input id="userEditPasswordConfirm" type="password" minlength="8" autocomplete="new-password"/></div></div></div><div class="section-actions"><button class="btn ghost" onclick="App.closeModal()">Cancelar</button><button id="saveUserAdminButton" class="btn primary" onclick="App.saveUserPermissions('${u.id}')">Salvar</button></div>`,true);enforceUserAccessFields()}
function toggleUserPasswordReset(){$('#userPasswordReset').classList.toggle('hidden');if(!$('#userPasswordReset').classList.contains('hidden'))$('#userEditPassword').focus()}
function updatePermissionSummary(){const summary=$('#permissionSummary');if(summary)summary.textContent=$$('[data-permission]:checked').map(x=>x.dataset.permission).join(' • ')||'Nenhuma permissão concedida.'}
function restoreUserPermissions(){enforceUserAccessFields();const role=$('#userEditRole').value,sector=$('#userEditSector').value;$('#permissionChecklist').innerHTML=permissionChecklist(defaultPermissions(role,sector));updatePermissionSummary()}
async function saveUserPermissions(id){
  if(State.user.role!=='direction'||!can('users.edit'))return toast('Operação não autorizada.');
  const user=State.db.users.find(x=>x.id===id);if(!user)return toast('Usuário não encontrado.');
  enforceUserAccessFields();
  const name=$('#userEditName').value.trim(),email=$('#userEditEmail').value.trim().toLowerCase(),role=$('#userEditRole').value,sector=$('#userEditSector').value,access_scope=$('#userEditScope').value,active=$('#userEditActive').value==='true',job_title=$('#userEditJobTitle').value.trim(),avatar_url=$('#userEditAvatarUrl').value.trim(),password=$('#userEditPassword')?.value||'',passwordConfirm=$('#userEditPasswordConfirm')?.value||'',permissions=Object.fromEntries(Object.entries(user.permissions||{}).filter(([key,enabled])=>PERMISSION_KEY_SET.has(key)&&typeof enabled==='boolean')),button=$('#saveUserAdminButton');
  $$('[data-permission]').forEach(x=>permissions[x.dataset.permission]=x.checked);
  if(!name||!email)return toast('Informe nome e e-mail.');
  if(!validPermissionObject(permissions))return toast('As permissões informadas são inválidas.');
  if(role==='direction'&&(sector!=='all'||access_scope!=='all_sectors'))return toast('A Direção deve possuir acesso global.');
  if(role==='leader'&&(sector==='all'||access_scope!=='own_sector'))return toast('O líder deve permanecer restrito ao próprio setor.');
  if(role==='viewer'&&access_scope!=='own_sector')return toast('O perfil Consulta deve permanecer restrito ao escopo configurado.');
  if(password&&password.length<8)return toast('A nova senha deve ter pelo menos 8 caracteres.');
  if(password!==passwordConfirm)return toast('A confirmação da senha não confere.');
  if(password&&!confirm(`Redefinir a senha de ${user.name}?`))return;
  const effectiveAdmins=State.db.users.filter(isEffectiveAdministrator),finalUser={...user,role,sector,accessScope:access_scope,permissions,active};
  if(isEffectiveAdministrator(user)&&!isEffectiveAdministrator(finalUser)&&effectiveAdmins.length===1)return toast('O último administrador efetivo da Direção deve permanecer ativo, global e com permissão para gerenciar usuários.');
  const body={user_id:id},assign=(key,value,current)=>{if(JSON.stringify(value)!==JSON.stringify(current))body[key]=value};
  assign('name',name,user.name);assign('email',email,user.email);assign('role',role,user.role);assign('sector',sector,user.sector);assign('access_scope',access_scope,user.accessScope);assign('permissions',permissions,user.permissions||{});assign('active',active,user.active);assign('job_title',job_title,user.jobTitle||'');assign('avatar_url',avatar_url,user.avatarUrl||'');
  if(password)body.password=password;
  if(Object.keys(body).length===1)return toast('Nenhuma alteração para salvar.');
  button.disabled=true;button.classList.add('loading');
  try{
    const {data,error}=await Supabase.functions.invoke('admin-manage-user',{body});
    if(error){let message='Não foi possível atualizar o usuário.';try{message=(await error.context.json())?.error||message}catch{}throw new Error(message)}
    if(data?.error)throw new Error(data.error);
    const profile=data.profile||{},profilePatch={name:profile.name??name,email:profile.email??email,role:profile.role??role,sector:profile.sector??sector,accessScope:profile.access_scope??access_scope,permissions:profile.permissions??permissions,active:profile.active??active,jobTitle:profile.job_title??job_title,avatarUrl:profile.avatar_url??avatar_url};
    Object.assign(user,profilePatch);
    const selfUpdated=user.id===State.user.id;
    if(selfUpdated){Object.assign(State.user,profilePatch);State.sector=State.user.accessScope==='all_sectors'?'integrado':State.user.sector;$('#userName').textContent=State.user.name;$('#userAvatar').textContent=State.user.name.charAt(0).toUpperCase();$('#userAccess').textContent=State.user.role==='direction'?'Acesso geral':State.user.role==='viewer'?'Somente consulta':`Acesso: ${SECTOR_LABELS[State.user.sector]}`;renderSectorSwitcher();renderNav()}
    logAudit('Atualizou usuário',`${user.name} • ${ROLE_LABELS[user.role]}`);closeModal();toast(password?'Usuário e senha atualizados.':'Usuário atualizado com sucesso.');
    if(selfUpdated&&!State.user.active)return logout();
    if(selfUpdated&&!can('users.view'))return go('home');
    renderPage();
  }catch(e){console.error('Purple Gestão — atualização de usuário:',e);toast(e.message||'Não foi possível atualizar o usuário.')}
  finally{button.disabled=false;button.classList.remove('loading')}
}
