function secureSaveActionUpdate(id){const a=State.db.actions.find(x=>x.id===id);if(!can('actions.edit')||!a||!sectorAllowed(a.sector))return toast('Edição não autorizada.');return saveActionUpdate(id)}
function secureDeleteAction(id){const a=State.db.actions.find(x=>x.id===id);if(!can('actions.delete')||!a||!sectorAllowed(a.sector))return toast('Exclusão não autorizada.');return deleteAction(id)}
