function secureSaveMeeting(id){if(!can('meetings.edit'))return toast('Edição não autorizada.');return saveMeeting(id)}
function secureToggleMeetingStatus(id){if(!can('meetings.edit'))return toast('Edição não autorizada.');return toggleMeetingStatus(id)}
function secureEditAnnouncement(id){if(!can(id?'mural.edit':'mural.create'))return toast('Edição não autorizada.');return editAnnouncement(id)}
