function secureDeleteAnnouncement(id){if(!can('mural.delete'))return toast('Exclusão não autorizada.');return deleteAnnouncement(id)}
function secureSaveSettings(){if(!can('settings.edit'))return toast('Edição não autorizada.');return saveSettings()}
function secureToggleSetting(key){if(!can('settings.edit'))return toast('Edição não autorizada.');return toggleSetting(key)}
function blockDatabaseReplacement(){return toast('Operação bloqueada por segurança. Use uma migração administrativa auditada.')}

