(async function init(){
  try{
    State.db.settings.version=APP_VERSION;
    State.db.settings.cacheVersion=SW_VERSION;
    bindUppercaseTyping();
    bindNavigationFallback();
    initializeSupabaseClient();
    const restoredLocalSession=Boolean(window.PurpleAuth?.restorePersistedSession?.());
    if(hasSupabaseClient()){
      const {data:{session}}=await Supabase.auth.getSession();
      if(session){
        try{
          await loadSession();
        }catch(error){
          if(restoredLocalSession){
            console.warn('Purple Gestão — sessão remota falhou, mantendo sessão local:',error);
          }else{
            enterRecoveryMode('restauração da sessão',error);
            console.warn('Purple Gestão — sessão preservada após falha de restauração:',error);
          }
        }
      }
    }
    if(!State.user){
      const cached=readLocalSessionCache();
      if(cached?.user?.active!==false){
        State.user=cached.user;
        State.sector=cached.sector||cached.user.sector||'integrado';
        State.db=State.db||defaultDB();
        Bootstrap.loginState='session-cache-loaded';
        startApp();
        if(hasSupabaseClient())loadSession().catch(error=>console.warn('Purple Gestão — sincronização pós-cache de sessão:',error));
      }
    }
  }catch(error){enterRecoveryMode('bootstrap geral',error)}
  try{
      if('serviceWorker' in navigator&&location.protocol!=='file:')navigator.serviceWorker.register(`./service-worker.js?v=${SW_VERSION.split('v').pop()||'55'}`).catch(error=>recordBootstrapError('registro do service worker',error));
  }catch(error){recordBootstrapError('registro do service worker',error)}
  renderRecoveryNotice();
})();
